-- Poems batch 134
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('0f15ef89-8b8c-4216-b9c3-d131b9333480','宿長安閘','楊萬里','宋','宋诗','song-poetry','','[]','野次何銷追水程，昏時即住曉時行。',32,'全唐诗/poet.song.141000.json','["野次何銷追水程，昏時即住曉時行。", "驚眠幸自無更點，猶有船頭擊柝聲。"]'),
('cc2a1c72-61b0-4380-868f-6dc129da68d8','讀詩','楊萬里','宋','宋诗','song-poetry','','[]','船中活計只詩編，讀了唐詩讀半山。',32,'全唐诗/poet.song.141000.json','["船中活計只詩編，讀了唐詩讀半山。", "不是老夫朝不食，半山絕句當朝餐。"]'),
('3d739170-b3ba-4d71-8fb7-0f2231e16695','夜泊平望二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','夜來微雪曉還晴，平望維舟嫩月生。',32,'全唐诗/poet.song.141000.json','["夜來微雪曉還晴，平望維舟嫩月生。", "道是燭花總無恨，爲誰須暗爲誰明。"]'),
('2dd34d4b-1403-48f9-9697-8afb4d8a11fd','夜泊平望二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一色河邊賣酒家，於中酒客一家多。',32,'全唐诗/poet.song.141000.json','["一色河邊賣酒家，於中酒客一家多。", "青帘不飲能樣醉，弄殺霜風舞殺它。"]'),
('6fa8aafe-07ed-4065-b9ca-b805c268494b','平望夜景','楊萬里','宋','宋诗','song-poetry','','[]','二鼕鼕，三當當。',104,'全唐诗/poet.song.141000.json','["二鼕鼕，三當當。", "夜泊平望更點長，新月無光湖有光。", "昨宵一雪今宵霜，犬吠兩岸歸人忙。", "夜深人靜無一事，畫燭泣殘人欲睡。", "忽有漁船外水來，一棹波聲風雨至。", "半生墮在紅塵中，浮家東吳東復東。", "樓船夜宿瑠璃國，誰言別有水精宮。"]'),
('2d2433a0-6f33-410a-8953-128d323f5171','遠樹','楊萬里','宋','宋诗','song-poetry','','[]','行行遠樹慘無聊，脫盡清陰只有梢。',32,'全唐诗/poet.song.141000.json','["行行遠樹慘無聊，脫盡清陰只有梢。", "霜幹瘦來無可庇，更能庇得鷺鷥巢。"]'),
('ef3a5cff-e46e-452d-a2b2-b11b90202df3','望姑蘇','楊萬里','宋','宋诗','song-poetry','','[]','曠野平中天四垂，凍雲罅裏日平西。',64,'全唐诗/poet.song.141000.json','["曠野平中天四垂，凍雲罅裏日平西。", "水村人遠看來短，茅屋簷長反作低。", "最愛河堤能底巧，截他山脚不勝齊。", "喜聞借得姑蘇館，百尺高臺入杖藜。"]'),
('db2cd4e0-f1cc-41af-b0d5-c6abd7a309eb','風定過垂虹亭','楊萬里','宋','宋诗','song-poetry','','[]','松江未過不勝愁，過了垂虹百不憂。',32,'全唐诗/poet.song.141000.json','["松江未過不勝愁，過了垂虹百不憂。", "忽見石湖山上塔，定知塔背是蘇州。"]'),
('7bba60a9-262e-4174-8781-ae85ebd8fbba','鱸魚','楊萬里','宋','宋诗','song-poetry','','[]','兩年三度過垂虹，每過垂虹每雪中。',64,'全唐诗/poet.song.141000.json','["兩年三度過垂虹，每過垂虹每雪中。", "要與鱸魚償舊債，不應張翰獨秋風。", "買來一尾那嫌少，尚有杯羹慰老窮。", "祗是蓴絲無覓處，仰天大笑笑天公。"]'),
('fb4d83d6-2c57-47dc-ae91-0a97c8c5eea9','泊姑蘇城外大雪二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','夜燒銀燭卷金巵，猛落天花醉未知。',64,'全唐诗/poet.song.141000.json','["夜燒銀燭卷金巵，猛落天花醉未知。", "若怯一寒都不看，却教六出更投誰。", "開門片片灑人面，送眼山山呈玉肌。", "纔雪又晴晴又雪，吳中風物許清奇。"]'),
('2a45ac6e-c6b8-4aca-91c1-3330c873b6ac','泊姑蘇城外大雪二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','今日晴光滿碧空，也無霧雨也無風。',64,'全唐诗/poet.song.141000.json','["今日晴光滿碧空，也無霧雨也無風。", "寂然窗戶黄昏後，霍地瓊瑶一望中。", "千里湖山銀作地，半篙舴艋玉爲宮。", "丁寧浮蟻非常綠，計會祥麟分外紅。"]'),
('1ae78590-c14a-446b-8392-212dac95bcff','跋袁起巖所藏蘭亭帖','楊萬里','宋','宋诗','song-poetry','','[]','南朝千載有斯人，拈出蘭亭花草春。',32,'全唐诗/poet.song.141000.json','["南朝千載有斯人，拈出蘭亭花草春。", "俛仰之間已陳跡，至今此紙尚如新。"]'),
('63e4dd6b-1be3-4036-a78a-5f60d7117249','謁范參政并赴袁起巖郡會坐中熾炭周圍遂中火毒得疾垂死乃悟貴人多病皆養之太過耳','楊萬里','宋','宋诗','song-poetry','','[]','後炭前爐便是窯，饒君是鐵也教銷。',64,'全唐诗/poet.song.141000.json','["後炭前爐便是窯，饒君是鐵也教銷。", "不須泉下火山獄，新制人間法外條。", "今日晴明殊可喜，病夫意緒自無聊。", "看來只欠刀圭藥，脚踏層冰雪沒腰。"]'),
('7f2c4e9f-02ee-4e12-ac78-05bdf2d94e9f','辛亥元日送章德茂自建康移帥江陵二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','極知借寇未多時，道是徵黄有近期。',64,'全唐诗/poet.song.141000.json','["極知借寇未多時，道是徵黄有近期。", "不割半青江令宅，却飛大白習家池。", "湖山解語云來暮，淮水無情也去思。", "莫近鄉關動歸興，輕黄一點上雙眉。"]'),
('94a4b521-656d-494d-b0cb-773b4187b30a','辛亥元日送章德茂自建康移帥江陵二首  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖一別忽三年，白首相從豈偶然。',64,'全唐诗/poet.song.141000.json','["西湖一別忽三年，白首相從豈偶然。", "到得我來恰君去，政當臘後與春前。", "醉餘犯雪追征帽，送了憑欄望去船。", "待把衣冠掛神武，看渠勳業上凌煙。"]'),
('77b81b03-77bc-4cae-a2dd-d19d6c36f1cb','金陵官舍後圃散策二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','江梅未落杏先繁，萱草都齊柳半勻。',32,'全唐诗/poet.song.141000.json','["江梅未落杏先繁，萱草都齊柳半勻。", "却是淺寒花較耐，東風未要十分溫。"]'),
('d111749d-8ae2-4006-92ef-e6b13de3cb7b','金陵官舍後圃散策二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','旋種花窠二百株，不知種了有花無。',32,'全唐诗/poet.song.141000.json','["旋種花窠二百株，不知種了有花無。", "阿誰便向春工說，急擣紅藍染玉酥。"]'),
('b9e2d2b9-e566-4305-99e8-e4a6d01191c5','過秦淮','楊萬里','宋','宋诗','song-poetry','','[]','曉過新橋啟轎窗，要看春水弄春光。',32,'全唐诗/poet.song.141000.json','["曉過新橋啟轎窗，要看春水弄春光。", "東風作意驚詩眼，攪亂垂楊兩岸黄。"]'),
('4bfa4ac7-486c-4a06-800f-8a3a612393f7','後圃杏花','楊萬里','宋','宋诗','song-poetry','','[]','小樹手初種，當年花便稠。',48,'全唐诗/poet.song.141000.json','["小樹手初種，當年花便稠。", "揀枝那忍折，繞徑祗成愁。", "淡了猶紅在，留渠肯住不。", "無端萬銀竹，判却一春休。"]'),
('35050dea-4443-48c5-9a61-d9e2418879a2','戲綵堂前海棠','楊萬里','宋','宋诗','song-poetry','','[]','露揉雨漬柳方濃，日曬風曛杏政烘。',32,'全唐诗/poet.song.141000.json','["露揉雨漬柳方濃，日曬風曛杏政烘。", "祗有海棠非旋染，粟來大小便鮮紅。"]'),
('3db1e6b9-63ec-4a8c-a391-a6d205b017e6','櫻桃花','楊萬里','宋','宋诗','song-poetry','','[]','櫻桃花發滿晴柯，不賭嬌饒只賭多。',32,'全唐诗/poet.song.141000.json','["櫻桃花發滿晴柯，不賭嬌饒只賭多。", "落盡江梅餘半朶，依前風韻合還他。"]'),
('7c6acd64-6705-469b-b6ed-91d108027aac','春寒','楊萬里','宋','宋诗','song-poetry','','[]','陣陣風寒樹樹斜，不容老子出簷牙。',32,'全唐诗/poet.song.141000.json','["陣陣風寒樹樹斜，不容老子出簷牙。", "繡簾半捲門偏啟，深倚胡床遠看花。"]'),
('ae046025-f61b-4f58-9d7c-6e72c19f293a','春陰忽霽','楊萬里','宋','宋诗','song-poetry','','[]','雲膜辛勤護日華，一重縠子一重紗。',32,'全唐诗/poet.song.141000.json','["雲膜辛勤護日華，一重縠子一重紗。", "玉奩忽透菱花影，淡與油窗描杏花。"]'),
('09f4ac1e-89bb-4719-8712-7987c939e567','過笪橋','楊萬里','宋','宋诗','song-poetry','','[]','輕風欲動沒人知，早被垂楊報酒旗。',32,'全唐诗/poet.song.141000.json','["輕風欲動沒人知，早被垂楊報酒旗。", "行到笪橋中半處，鍾山飛入轎窗來。"]'),
('8f7dc87e-1669-4fa4-90a6-4c17b0b6e4d0','登鳳凰臺','楊萬里','宋','宋诗','song-poetry','','[]','千年百尺鳳凰臺，送盡潮回鳳不回。',64,'全唐诗/poet.song.141000.json','["千年百尺鳳凰臺，送盡潮回鳳不回。", "白鷺北頭江草合，烏衣西面杏花開。", "龍蟠虎踞山川在，古往今來鼓角哀。", "只有謫仙留句處，春風掌管拂蛛煤。"]'),
('a19645bf-5315-4cae-b738-8fd3839f0b9d','上巳寒食同日後圃行散','楊萬里','宋','宋诗','song-poetry','','[]','百五重三併一朝，風光不怕不嬌饒。',64,'全唐诗/poet.song.141000.json','["百五重三併一朝，風光不怕不嬌饒。", "鹿葱引道心猶卷，楊柳應門手對招。", "筇未喚隨非是强，扇聊作伴不須摇。", "先生道是無歌舞，花勸鶑酬酒自銷。"]'),
('f8927fb8-d295-45cd-9665-79da91c7ee50','代書呈張功父','楊萬里','宋','宋诗','song-poetry','','[]','不見子張子，令人夢亦思。',48,'全唐诗/poet.song.141000.json','["不見子張子，令人夢亦思。", "只應依舊瘦，近作幾多詩。", "聯句平生事，看花去歲時。", "海棠今好不，傳語併酴醾。"]'),
('c5b24bc9-1e00-41a7-93fd-6f9d2a02875b','移瑞香花斛','楊萬里','宋','宋诗','song-poetry','','[]','夜掇香窠沐露華，晝移翠斛馥窗紗。',32,'全唐诗/poet.song.141000.json','["夜掇香窠沐露華，晝移翠斛馥窗紗。", "將身挨起簾帷著，生怕簾帷挨著花。"]'),
('8d67b4ac-ae35-48c4-a694-06a7779d0218','三月三日上忠襄墳因之行散得十絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','暖轎行春底見春，遮欄春色不教親。',32,'全唐诗/poet.song.141000.json','["暖轎行春底見春，遮欄春色不教親。", "急呼青繖小涼轎，又被春光著莫人。"]'),
('ecf2139b-c33e-41df-b0cc-554036a90889','三月三日上忠襄墳因之行散得十絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','草藉輪蹄翠織成，花圍巷陌錦幃屏。',32,'全唐诗/poet.song.141000.json','["草藉輪蹄翠織成，花圍巷陌錦幃屏。", "早來指點遊人處，今在游人行處行。"]'),
('250a03dc-e2cb-4890-96ce-5d0dbf78ba92','三月三日上忠襄墳因之行散得十絕句  其三','楊萬里','宋','宋诗','song-poetry','','[]','淮山脚下大江橫，御柳梢頭絳闕明。',32,'全唐诗/poet.song.141000.json','["淮山脚下大江橫，御柳梢頭絳闕明。", "覽盡山川更城郭，雨花臺上太奇生。"]'),
('33479604-2411-472e-ae9b-62739a1ae4ba','三月三日上忠襄墳因之行散得十絕句  其四','楊萬里','宋','宋诗','song-poetry','','[]','天公也自喜良辰，上巳風光忽斬新。',32,'全唐诗/poet.song.141000.json','["天公也自喜良辰，上巳風光忽斬新。", "點檢一春好天色，更無兩日似今晨。"]'),
('4215caaf-b95b-45c1-aff5-f97917e29a0f','三月三日上忠襄墳因之行散得十絕句  其五','楊萬里','宋','宋诗','song-poetry','','[]','游人不是上墳回，便是清湍禊事來。',32,'全唐诗/poet.song.141000.json','["游人不是上墳回，便是清湍禊事來。", "最苦相逢無處避，天禧寺及雨花臺。"]'),
('2c0e07ce-fb56-4b78-b7e5-c01563b70ff1','三月三日上忠襄墳因之行散得十絕句  其六','楊萬里','宋','宋诗','song-poetry','','[]','女唱兒歌去踏青，阿婆笑語伴渠行。',32,'全唐诗/poet.song.141000.json','["女唱兒歌去踏青，阿婆笑語伴渠行。", "只虧郎罷優輕殺，櫑子雙擔挈酒缾。"]'),
('a3fab1ab-d6d5-4237-8704-5129ef8d4ac8','三月三日上忠襄墳因之行散得十絕句  其七','楊萬里','宋','宋诗','song-poetry','','[]','粉捏孩兒活逼真，象生果子更時新。',32,'全唐诗/poet.song.141000.json','["粉捏孩兒活逼真，象生果子更時新。", "輸贏一擲渾閑事，空手入城羞殺人。"]'),
('3f59fdc2-95ed-4294-8450-95fa49679bde','三月三日上忠襄墳因之行散得十絕句  其八','楊萬里','宋','宋诗','song-poetry','','[]','長干橋外即烏衣，今著屠沽賣菜兒。',32,'全唐诗/poet.song.141000.json','["長干橋外即烏衣，今著屠沽賣菜兒。", "晉殿吳宮猶碧草，玉亭謝館儘黄鸝。"]'),
('49867ece-64b9-42cc-8881-9e555d193ece','三月三日上忠襄墳因之行散得十絕句  其九','楊萬里','宋','宋诗','song-poetry','','[]','除却鍾山與石城，六朝遺跡問難真。',32,'全唐诗/poet.song.141000.json','["除却鍾山與石城，六朝遺跡問難真。", "里名只道新名好，不道新名誤後人。"]'),
('05a3e038-d47c-4de6-a94b-47e31653493a','三月三日上忠襄墳因之行散得十絕句  其一○','楊萬里','宋','宋诗','song-poetry','','[]','切忌尋春預作謀，教君行樂定成愁。',32,'全唐诗/poet.song.141000.json','["切忌尋春預作謀，教君行樂定成愁。", "老夫乘興翩然出，不遣風知雨覺休。"]'),
('c889cf66-38a5-4cb0-bbc1-37c45bbdcf87','折花','楊萬里','宋','宋诗','song-poetry','','[]','指似青童折海棠，繁枝仍要豔花房。',32,'全唐诗/poet.song.141000.json','["指似青童折海棠，繁枝仍要豔花房。", "癡眉騃眼生疎手，顫脫花房悶一場。"]'),
('949b66e0-5658-4651-8857-5a4a1128d9a5','行闕養種園千葉杏花二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','不信東皇也有私，如何偏寵杏花枝。',32,'全唐诗/poet.song.141000.json','["不信東皇也有私，如何偏寵杏花枝。", "於中更出紅千葉，且道此花奇不奇。"]'),
('e79e388e-5690-434b-8d9c-18dd1e7b42ab','行闕養種園千葉杏花二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','白白紅紅兩不真，重重疊疊是精神。',32,'全唐诗/poet.song.141000.json','["白白紅紅兩不真，重重疊疊是精神。", "誰言跂石眠雲客，也見長楊五柞春。"]'),
('bec645f9-d72d-4f24-a979-c45116ff1c96','清明日雨雪來早晴霽二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','清明一雨壞花時，梅杏櫻桃總脫枝。',32,'全唐诗/poet.song.141000.json','["清明一雨壞花時，梅杏櫻桃總脫枝。", "挽住落英供細舞，東風猶自妬游絲。"]'),
('7a6b1af7-1906-4dec-8dee-4a0bba11b92c','清明日雨雪來早晴霽二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','清明一雪怪生寒，逗曉新晴雪未殘。',32,'全唐诗/poet.song.141000.json','["清明一雪怪生寒，逗曉新晴雪未殘。", "要見海棠還傅粉，捲簾不徹急來看。"]'),
('d0807d1a-2b6e-47e4-9783-5dace6562fc2','海棠四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','小園不到負今晨，晚喚嬌紅伴老身。',64,'全唐诗/poet.song.141000.json','["小園不到負今晨，晚喚嬌紅伴老身。", "落日爭明那肯暮，豔粧一出更無春。", "樹間露坐看摇影，酒底花光併入唇。", "銀燭不燒渠不睡，梢頭恰恰掛冰輪。"]'),
('c1752a5b-f76f-45bb-ae6f-b750d6e5f58b','海棠四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','暖醉寒醒各自奇，千花誰是復誰非。',64,'全唐诗/poet.song.141000.json','["暖醉寒醒各自奇，千花誰是復誰非。", "燕支濃透春風面，翡翠新裁生色衣。", "破落東皇能許劣，莊嚴西子較些肥。", "癡兒猶恨無香在，紫蝶黄蜂政打圍。"]'),
('0125801a-e920-4699-9753-2bd45f855a51','海棠四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','競豔爭嬌最是他，教人嫌少不嫌多。',64,'全唐诗/poet.song.141000.json','["競豔爭嬌最是他，教人嫌少不嫌多。", "初酣曉日紅千滴，晚笑東風淡一渦。", "自是花中無國色，非關格外占春窠。", "開時慳爲渠儂醉，却恨飄零可若何。"]'),
('b05f235e-29ab-4a63-b8fb-38c0951d2156','海棠四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','吾詩多爲海棠哦，花意依前怨不多。',64,'全唐诗/poet.song.141000.json','["吾詩多爲海棠哦，花意依前怨不多。", "已拆未開渾是韻，乍濃還淡總由它。", "留連春色能銷底，請託東風定肯麽。", "豈是少陵無句子，少陵未見欲如何。"]'),
('b75e3986-b2e0-4eda-b804-283d943de7d4','花下夜飲','楊萬里','宋','宋诗','song-poetry','','[]','夜深移入小杯盤，回首花枝不忍看。',32,'全唐诗/poet.song.141000.json','["夜深移入小杯盤，回首花枝不忍看。", "豈與海棠情分薄，老夫自是怯春寒。"]'),
('2e6e0561-e37d-441e-85d6-ca574a29c792','柳絮','楊萬里','宋','宋诗','song-poetry','','[]','寒勒花遲却速殘，暖將絮過忽吹還。',64,'全唐诗/poet.song.141000.json','["寒勒花遲却速殘，暖將絮過忽吹還。", "雪翻霽日光風急，毬衮回廊曲榭閑。", "萬里雲天皆去處，羣飛蹤跡恣中間。", "道渠催得春闌著，春不緣渠獨不闌。"]'),
('e11c6732-618f-470f-9601-eabe2672ec8a','折杏子','楊萬里','宋','宋诗','song-poetry','','[]','天暖酒易醺，春暮花難覓。',84,'全唐诗/poet.song.141000.json','["天暖酒易醺，春暮花難覓。", "意行到南園，杏子半紅碧。", "輕風動高枝，可望不可摘。", "聳肩跂一足，偶爾攀翻得。", "攀條初亦喜，折條還復惜。", "小苦已自韻，未酸政堪喫。", "聊將插鬢歸，空樽有餘瀝。"]'),
('4d731484-d173-45be-8f13-7dff0a6e5167','紅錦带花','楊萬里','宋','宋诗','song-poetry','','[]','天女風梭織露機，碧絲地上茜欒枝。',64,'全唐诗/poet.song.141000.json','["天女風梭織露機，碧絲地上茜欒枝。", "何曾繫住春歸脚，只解縈長客恨眉。", "節節生花花點點，茸茸曬日日遲遲。", "後園初夏無題目，小樹微芳也得詩。"]'),
('1a17c240-6ba4-46bd-b4eb-641b8447bdec','送劉覺之歸蜀','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','大江東西湖南北，鵠袍學子森如竹。',232,'全唐诗/poet.song.141000.json','["大江東西湖南北，鵠袍學子森如竹。", "何人開口不伊川，阿誰初道此水源。", "清純先生劉夫子，冷笑俗儒鑽故紙。", "夢中親見大小程，爲渠刺船入洙泗。", "嗟我結髮從先生，日日看子趨鯉庭。", "先生命子却從我，小窗短檠共燈火。", "陋巷柴扉共寒餓，安知頭上天幾大。", "子今行李寄大寧，翩然束書游帝城。", "袖中一卷經濟策，天關九虎叫不應。", "朝來忽見毛生刺，看來看去驚且喜。", "風花聚散三十年，何許飛墮老眼前。", "相逢幾日又相別，珍重兩字不忍說。", "我有故山江之西，祗遣思歸不遣歸。", "贈行聊借退之詩，石頭城下一杯酒，便是此生長別離。"]'),
('c1cb2615-694e-46a1-bf8c-8f33ff6be1c9','跋余伯益所藏張欽夫書西銘短紙二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','一高一下一中央，怙恃兼儂豈別房。',32,'全唐诗/poet.song.141000.json','["一高一下一中央，怙恃兼儂豈別房。", "撞過煙樓休劣相，祗如郎罷也無良。"]'),
('5a7e83dd-9cbe-4860-8838-54e6cbb32d0c','跋余伯益所藏張欽夫書西銘短紙二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','橫渠方寸著乾坤，傳到南軒更莫論。',32,'全唐诗/poet.song.141000.json','["橫渠方寸著乾坤，傳到南軒更莫論。", "四海交朋霜葉落，半張翰墨雪濤翻。"]'),
('6f153d02-6b64-4917-8053-96986e6688c5','遊定林寺即荆公讀書處四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','鍾山已在萬山深，更過鍾山入定林。',32,'全唐诗/poet.song.141000.json','["鍾山已在萬山深，更過鍾山入定林。", "穿盡松杉行盡石，一庵猶隔白雲岑。"]'),
('98677f9d-7471-4e60-91a1-ef114b52a922','遊定林寺即荆公讀書處四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一箇青童一蹇馿，九年來往定林居。',32,'全唐诗/poet.song.141000.json','["一箇青童一蹇馿，九年來往定林居。", "經綸枉被周公誤，罷相歸來始讀書。"]'),
('c94ab866-9a44-4107-ad44-4667adc88f09','遊定林寺即荆公讀書處四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','半破僧庵半補籬，舊題無復壁間詩。',32,'全唐诗/poet.song.141000.json','["半破僧庵半補籬，舊題無復壁間詩。", "祗餘手植雙桐在，此外仍兼洗硯池。"]'),
('88d451e1-9c3e-48ac-9908-78aa0a2202f9','遊定林寺即荆公讀書處四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','踏月敲門訪病夫，問來還是雪堂蘇。',32,'全唐诗/poet.song.141000.json','["踏月敲門訪病夫，問來還是雪堂蘇。", "不知把燭高談許，曾舉烏臺詩帳無。"]'),
('fce895a2-76e3-4b8c-9566-990632d13d76','半山寺三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','霜松雪竹老重尋，南蕩東陂水自深。',32,'全唐诗/poet.song.141000.json','["霜松雪竹老重尋，南蕩東陂水自深。", "鳳去宅存誰與住，不如作寺免傷心。"]'),
('00859721-0d58-4aa0-a0cc-681ec1f3aa0f','半山寺三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','老無穉子爲應門，病有毗耶伴此身。',32,'全唐诗/poet.song.141000.json','["老無穉子爲應門，病有毗耶伴此身。", "相府梵宮均是幻，却須捨宅即離塵。"]'),
('1817b91d-d715-4555-ad66-cdd591b0e234','半山寺三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','日邊賜額寺名新，雞犬猶迎舊主人。',32,'全唐诗/poet.song.141000.json','["日邊賜額寺名新，雞犬猶迎舊主人。", "見說小兒齊拍手，半山寺主裹頭巾。"]'),
('a35962ad-05f3-4a50-b341-8e6d03b461f6','初夏即事','楊萬里','宋','宋诗','song-poetry','','[]','今日風光定自佳，不寒不熱恰清和。',64,'全唐诗/poet.song.141000.json','["今日風光定自佳，不寒不熱恰清和。", "百年人世行樂耳，一歲春歸奈老何。", "芍藥晚花終是小，戎葵新莟許來多。", "俸錢自笑渾無用，祗合文江買釣蓑。"]'),
('cc99ef32-c672-44aa-b500-d78976a6c731','賀建康帥余處恭迎寶公禱雨隨應','楊萬里','宋','宋诗','song-poetry','','[]','大士多時不入城，入城猶未炷爐熏。',64,'全唐诗/poet.song.141000.json','["大士多時不入城，入城猶未炷爐熏。", "忽吹淮水千峰雨，不費鍾山半朶雲。", "桑葉秧苗俱起舞，葵花萱草亦歡欣。", "尚書款送公歸去，留下豐年二十分。"]'),
('43625ddf-7cdd-4634-bf09-9020aa2a3bfe','跋虞丞相與趙撙節使帖還其猶子濟二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','虞丞相與趙將軍，同策江淮第一勳。',32,'全唐诗/poet.song.141000.json','["虞丞相與趙將軍，同策江淮第一勳。", "大羽進賢今寂寞，凌煙頌裏感風雲。"]'),
('46a8a820-1163-485b-a3e0-ef071aa647ea','跋虞丞相與趙撙節使帖還其猶子濟二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','側厘一幅落雲煙，意豁神傾歎兩賢。',32,'全唐诗/poet.song.141000.json','["側厘一幅落雲煙，意豁神傾歎兩賢。", "從古將門長出將，眼看小阮勒燕然。"]'),
('ac612e69-80b2-41f2-a505-38e91a0efa96','送李君亮大著出守眉州','楊萬里','宋','宋诗','song-poetry','','[]','老夫丐外自緣老，復聞建鄴江山好。',162,'全唐诗/poet.song.141000.json','["老夫丐外自緣老，復聞建鄴江山好。", "不應夫子亦翩然，一柁江花更江草。", "黄金宮闕三神山，蓬萊五雲霄漢間。", "仍將弱水三萬里，隔斷塵世無往還。", "西州名勝李太史，豈徒國士天下士。", "玉皇催入道山堂，知費臺家幾黄紙。", "似聞郎罷對薰風，忽思錦江荔枝紅。", "人生奉親行樂耳，金印斗大何關儂。", "峨眉山月却入手，影落庭闈一杯酒。", "蚤賦中和樂職宣布詩，會看夔龍集鳳池。"]'),
('566aa87a-5fe7-42ae-8108-db3436518f23','晝倦','楊萬里','宋','宋诗','song-poetry','','[]','睡眼䰒鬆倦日長，却拋詩卷步回廊。',32,'全唐诗/poet.song.141000.json','["睡眼䰒鬆倦日長，却拋詩卷步回廊。", "貍奴幸自雙雙戲，忽見人來走似獐。"]'),
('39f8c788-367a-42f5-aa52-29204e327b3a','陪留守余處恭總領錢進思提刑傅景仁游清凉寺即古石頭城三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','山自新亭走下來，化爲一虎首重回。',64,'全唐诗/poet.song.141000.json','["山自新亭走下來，化爲一虎首重回。", "平吞雪浪三江水，卧對雨花千丈臺。", "點檢故城遺址在，淒涼浩歎宿雲開。", "六朝蹤跡登臨徧，底事茲游獨壯哉。"]'),
('b7dc8a67-a841-495e-9eba-16b9b1361023','陪留守余處恭總領錢進思提刑傅景仁游清凉寺即古石頭城三首  其二','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','萬里長江天上來，石頭却欲打江回。',64,'全唐诗/poet.song.141000.json','["萬里長江天上來，石頭却欲打江回。", "青山外面周如削，紫府中間劃洞開。", "蘇峻戰場今草樹，仲謀廟貌古塵埃。", "多情白鷺洲前水，月落潮生聲自哀。"]'),
('a14dff54-6a6c-4edc-ba51-4f5215dfca07','陪留守余處恭總領錢進思提刑傅景仁游清凉寺即古石頭城三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','已守臺城更石城，不知併力或分營。',64,'全唐诗/poet.song.141000.json','["已守臺城更石城，不知併力或分營。", "六師只遣環天闕，一壘真成借寇兵。", "向者王蘇俱解此，冤哉隗協可憐生。", "若言虎踞渾堪倚，萬歲千秋無戰爭。"]'),
('75fddfdc-abdf-4598-a1be-37673035234b','和傅景仁游清凉寺','楊萬里','宋','宋诗','song-poetry','','[]','舊時月過女牆頭，風雨摧頹廢不脩。',64,'全唐诗/poet.song.141000.json','["舊時月過女牆頭，風雨摧頹廢不脩。", "地老天荒無處問，松聲灘響替人愁。", "祥刑使者來何暮，弔古詩篇清更幽。", "收拾江山入懷袖，却歸講席進鴻疇。"]'),
('ae79bd3b-5dda-4f93-b161-cece16b51972','夏日雜興','楊萬里','宋','宋诗','song-poetry','','[]','金陵六月曉猶寒，近北天時較少暄。',64,'全唐诗/poet.song.141000.json','["金陵六月曉猶寒，近北天時較少暄。", "打盡來禽那待熟，半開萱草已先翻。", "獨龍岡頂青千摺，十字河頭碧一痕。", "九郡報來都雨足，插秧收麥喜村村。"]'),
('e625961c-45ed-4416-a110-59e05c78c49d','新亭送客','楊萬里','宋','宋诗','song-poetry','','[]','六朝豈是乏勳賢，爲底京師不晏然。',64,'全唐诗/poet.song.141000.json','["六朝豈是乏勳賢，爲底京師不晏然。", "柏壁置人天一笑，楚囚對泣後千年。", "鍾山喚客長南望，江水留人懶北還。", "强管興亡談不盡，枉教吟殺夕陽蟬。"]'),
('f569ce3e-bdf0-4673-bb81-23b51d02c6b5','戲詠陳氏女剪綵花二絕句 拒霜','楊萬里','宋','宋诗','song-poetry','','[]','染露金風裏，宜霜玉水濱。',24,'全唐诗/poet.song.141000.json','["染露金風裏，宜霜玉水濱。", "莫嫌開最晚，元自不爭春。"]'),
('435d3cd4-2be1-419a-8f4a-3516ab9af2cb','戲詠陳氏女剪綵花二絕句 菊','楊萬里','宋','宋诗','song-poetry','','[]','味苦誰能愛，香寒只自珍。',24,'全唐诗/poet.song.141000.json','["味苦誰能愛，香寒只自珍。", "長將潭底水，普供世間人。"]'),
('a872aba3-3dc3-4d5e-a431-e2466b1dba41','謝余處恭送七夕酒果蜜食化生兒二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','踉蹡兒孫忽滿庭，折荷騎竹臂春鶑。',64,'全唐诗/poet.song.141000.json','["踉蹡兒孫忽滿庭，折荷騎竹臂春鶑。", "巧樓後夜邀牛女，留鑰今朝送化生。", "節物催人教老去，壺觴拜賜喜先傾。", "醉眠管得銀河鵲，天上歸來打六更。"]'),
('f87e3f47-e8a7-423c-b448-0a307c1add31','謝余處恭送七夕酒果蜜食化生兒二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','新釀秦淮鴨綠坳，旋熬粔籹蜜蜂巢。',64,'全唐诗/poet.song.141000.json','["新釀秦淮鴨綠坳，旋熬粔籹蜜蜂巢。", "來禽濃抹日半臉，水藕初凝雪一梢。", "豈有天孫千度嫁，枉同河鼓兩相嘲。", "渠儂有巧真堪乞，不倩蛛絲罥果肴。"]'),
('8b40b580-ec98-4c59-b507-1a5011e332c9','初秋行圃四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','今年六月不勝涼，七月炎蒸不可當。',32,'全唐诗/poet.song.141000.json','["今年六月不勝涼，七月炎蒸不可當。", "一陣秋風初過雨，箇般天氣好燒香。"]'),
('d3e9d8d2-ad64-46ca-9270-642d2aad7c61','初秋行圃四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','小小園亭亦自佳，晚雲過雨却成霞。',32,'全唐诗/poet.song.141000.json','["小小園亭亦自佳，晚雲過雨却成霞。", "爛開梔子渾如雪，已熟來禽尚带花。"]'),
('cc0b18cf-b434-40e4-9efc-62f36db003ec','初秋行圃四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','花梢飛下兩鳴鳩，欲住還行行復留。',32,'全唐诗/poet.song.141000.json','["花梢飛下兩鳴鳩，欲住還行行復留。", "拾得來禽吞不得，啄來啄去竟成休。"]'),
('2df2ac3d-f464-4110-b113-d0f3297db9aa','初秋行圃四首  其四','楊萬里','宋','宋诗','song-poetry','','["\u751f\u6d3b", "\u7530\u56ed", "\u590f", "\u52a8\u7269"]','落日無情最有情，徧催萬樹暮蟬鳴。',32,'全唐诗/poet.song.141000.json','["落日無情最有情，徧催萬樹暮蟬鳴。", "聽來咫尺無尋處，尋到旁邊却不聲。"]'),
('0dcb5e24-9d15-413b-81e6-f93bed73802e','跋澹庵先生辭工部侍郎答詔不允  其一','楊萬里','宋','宋诗','song-poetry','','[]','高卧崖州二十年，黑頭去國白頭還。',32,'全唐诗/poet.song.141000.json','["高卧崖州二十年，黑頭去國白頭還。", "身居紫禁鶑花裏，心在青原水石間。"]'),
('e74f5045-2d90-484c-9c8c-5189ac62b608','跋澹庵先生辭工部侍郎答詔不允  其二','楊萬里','宋','宋诗','song-poetry','','[]','願挽天河洗北夷，老臣底用紫荷爲。',32,'全唐诗/poet.song.141000.json','["願挽天河洗北夷，老臣底用紫荷爲。", "丹心一寸凌霜雪，祗有隆興聖主知。"]'),
('677e86c2-0975-43df-96fc-b3650386efe9','跋澹庵先生繳張欽夫賜章服答詔二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','平生師友兩相知，苦爲君王惜一衣。',32,'全唐诗/poet.song.141000.json','["平生師友兩相知，苦爲君王惜一衣。", "刺口爭來爭不得，青蠅猶傍太陽飛。"]'),
('391c011c-53a8-40e8-9b54-bf81add3ca2c','跋澹庵先生繳張欽夫賜章服答詔二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','紫綬當時賜兩人，一爲乳臭一名臣。',32,'全唐诗/poet.song.141000.json','["紫綬當時賜兩人，一爲乳臭一名臣。", "老韓不要令同傳，誰會先生此意真。"]'),
('9523fdb3-b2bb-4855-b021-4fb419eb8186','中元前賀余處恭尚書禱雨沛然霑足','楊萬里','宋','宋诗','song-poetry','','[]','數點飄蕭供晚清，二更傾瀉到天明。',64,'全唐诗/poet.song.141000.json','["數點飄蕭供晚清，二更傾瀉到天明。", "雷驅雲氣如旋磨，雨徧山村却入城。", "簟面頓無秋後暑，簷牙最愛夢中聲。", "尚書幸有爲霖手，偏灑江東作麽生。"]'),
('fa3202e7-f5cf-4e65-a30e-43915359a9b8','竹床','楊萬里','宋','宋诗','song-poetry','','[]','已製青奴一壁寒，更搘綠玉兩頭安。',64,'全唐诗/poet.song.141000.json','["已製青奴一壁寒，更搘綠玉兩頭安。", "誰言詩老眠雲榻，不是漁郎釣月竿。", "醉夢那知蕉葉雨，小舟親過蓼花灘。", "蹶然驚起天將曉，窗下書燈耿復殘。"]'),
('5801711b-3a3c-4b57-a0ff-9ac377c7bbcf','中元日午','楊萬里','宋','宋诗','song-poetry','','[]','雨餘赤日尚如炊，亭午青陰不肯移。',64,'全唐诗/poet.song.141000.json','["雨餘赤日尚如炊，亭午青陰不肯移。", "蜂過無花絕糧道，蟻行有水遏歸師。", "今朝道是中元節，天氣過於初伏時。", "小圃追涼還得熱，焚香清坐讀唐詩。"]'),
('d1a76492-b7ef-468f-8eb8-3b58ae4924d0','偶成','楊萬里','宋','宋诗','song-poetry','','[]','珍禽飲盆池，將扇撲窗戶。',24,'全唐诗/poet.song.141000.json','["珍禽飲盆池，將扇撲窗戶。", "一聲驚得飛，再聲驚不去。"]'),
('e354b79e-2c8d-41f0-98f0-a30f6d45cc99','秋日早起','楊萬里','宋','宋诗','song-poetry','','[]','我眠亦甚安，夢中初無驚。',168,'全唐诗/poet.song.141000.json','["我眠亦甚安，夢中初無驚。", "如何作夢語，反側意不平。", "起來不復寐，郡樓撾五更。", "窗紙尚昏昏，看到漸次明。", "卷簾啟後戶，披衣步中庭。", "汲井漱新泉，滿面吹寒冰。", "仰看天宇曠，微白復淡青。", "猶挂爛銀梳，未昇紫金鉦。", "砌蛩餘夜唧，樹鵲作曉鳴。", "群動俱擾擾，競若有所營。", "而人居其間，獨欲免夙興。", "出山三見秋，一年一征行。", "今茲秋又至，歸心捺還生。", "會當挂其冠，高卧聽松聲。"]'),
('13b773af-fd9e-465d-aba9-e529ec51a6a1','月臺夜坐二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','秋日非無熱，秋宵至竟清。',48,'全唐诗/poet.song.141000.json','["秋日非無熱，秋宵至竟清。", "老夫連數夕，露坐到三更。", "風急星明滅，雲行月送迎。", "追驩追不得，驩却偶然成。"]'),
('d8b28a55-cd67-4361-a4c2-d56f3b3692be','月臺夜坐二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','日落片時許，星纔數點明。',48,'全唐诗/poet.song.141000.json','["日落片時許，星纔數點明。", "須臾玉棋子，徧滿碧瑶枰。", "向晚垂垂雨，通宵得得晴。", "秋蛩伴儂語，苦底是誰聲。"]'),
('131a9736-71dd-4a41-bb7e-5e72214ca48b','初凉與次公子共讀書冊','楊萬里','宋','宋诗','song-poetry','','[]','暑嬾歸投簟，涼醒打當書。',48,'全唐诗/poet.song.141000.json','["暑嬾歸投簟，涼醒打當書。", "罷吟唇欲裂，起坐膝難舒。", "汲古微瀾動，悲秋小雨餘。", "五言未針線，百過且階除。"]'),
('47452581-9b1c-473a-a5ed-1ae5fdddf86b','後圃秋步','楊萬里','宋','宋诗','song-poetry','','[]','夏箑秋新妬，暄窗冷早侵。',48,'全唐诗/poet.song.141000.json','["夏箑秋新妬，暄窗冷早侵。", "病葵萱未悟，落果草偏深。", "老矣曾榮望，歸歟更嬾心。", "此冠彈與掛，若箇不山林。"]'),
('4482391b-fbdb-4621-9a8b-372271e886bc','戲用禪觀答曾無逸問山谷語','楊萬里','宋','宋诗','song-poetry','','[]','前說人間無漏仙，後說世上無眼禪。',32,'全唐诗/poet.song.141000.json','["前說人間無漏仙，後說世上無眼禪。", "衲子若全信佛語，生天定在靈運前。"]'),
('10e4bdaf-18a3-45e7-8e02-f4ccb48f3056','聽蟬八絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','披襟散髮晚風清，細細孤斟緩緩行。',32,'全唐诗/poet.song.141000.json','["披襟散髮晚風清，細細孤斟緩緩行。", "道是江東官事冗，綠楊陰裏聽蟬聲。"]'),
('3e36a153-f23f-4441-9d34-fca752ff9b41','聽蟬八絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','一隻初來報早秋，又添一隻說新愁。',32,'全唐诗/poet.song.141000.json','["一隻初來報早秋，又添一隻說新愁。", "兩蟬對語雙垂柳，知鬭先休鬭後休。"]'),
('0d18e9a5-c4db-434a-bc95-7d5b43b53151','聽蟬八絕句  其三','楊萬里','宋','宋诗','song-poetry','','[]','渠與斜陽有底讎，千冤萬恨訴清秋。',32,'全唐诗/poet.song.141000.json','["渠與斜陽有底讎，千冤萬恨訴清秋。", "更從誰子做頭抵，只放斜陽不落休。"]'),
('1460f1fa-b9a7-440e-93c2-5a442727740d','聽蟬八絕句  其四','楊萬里','宋','宋诗','song-poetry','','[]','一殻空空紙樣輕，風前却有許多聲。',32,'全唐诗/poet.song.141000.json','["一殻空空紙樣輕，風前却有許多聲。", "叫來叫去渾無事，叫到詩人白髮生。"]'),
('06f8ee2b-b760-4b1f-bf24-ae8c67af6ca1','聽蟬八絕句  其五','楊萬里','宋','宋诗','song-poetry','','[]','說露談風有典章，詠秋吟夏入宮商。',32,'全唐诗/poet.song.141000.json','["說露談風有典章，詠秋吟夏入宮商。", "蟬聲無一些煩惱，自是愁人枉斷腸。"]'),
('d570d833-d8ab-49fd-8614-b40272e810fa','聽蟬八絕句  其六','楊萬里','宋','宋诗','song-poetry','','[]','乍來忽去爲誰忙，短氣抽教强作長。',32,'全唐诗/poet.song.141000.json','["乍來忽去爲誰忙，短氣抽教强作長。", "道是渠儂聲不歇，一吟一續萬低昂。"]'),
('81cf4ba3-eeca-4511-bbad-3fed971e5e5a','聽蟬八絕句  其七','楊萬里','宋','宋诗','song-poetry','','[]','望帝啼春夜更多，不知蟬意却如何。',32,'全唐诗/poet.song.141000.json','["望帝啼春夜更多，不知蟬意却如何。", "還來入夜便無語，明日將詩理會它。"]'),
('e1f2cff1-9e14-4a72-be11-464893e85c15','聽蟬八絕句  其八','楊萬里','宋','宋诗','song-poetry','','[]','罪過渠儂商略秋，從朝至暮不曾休。',32,'全唐诗/poet.song.141000.json','["罪過渠儂商略秋，從朝至暮不曾休。", "莫嫌入夜還休去，自有寒蛩替說愁。"]'),
('9189c0bb-53ad-4484-a217-553713388a40','行部有日喜雨','楊萬里','宋','宋诗','song-poetry','','[]','一雨天良苦，連宵釀不成。',48,'全唐诗/poet.song.141000.json','["一雨天良苦，連宵釀不成。", "强摩昏睡眼，來看滴階聲。", "環細開來大，珠跳滅又生。", "稻花知我出，噴雪待相迎。"]'),
('f070cd2f-5b9f-438a-b0e3-dea6ab935c28','八月朔曉起趣辦行李','楊萬里','宋','宋诗','song-poetry','','[]','雨後晨先起，花間濕也行。',48,'全唐诗/poet.song.141000.json','["雨後晨先起，花間濕也行。", "破除婪尾暑，領略打頭清。", "蠹果無遲落，枯枝忽再榮。", "便須秣吾馬，及此半陰晴。"]'),
('fe0b58e7-1cf7-4b32-ad3e-fc61d4f09847','行部暫辭金陵同列有感','楊萬里','宋','宋诗','song-poetry','','[]','爽氣來江外，秋容上柳梢。',48,'全唐诗/poet.song.141000.json','["爽氣來江外，秋容上柳梢。", "生遭女嬃駡，老解子雲嘲。", "衰病聊飛屐，行藏鎮把包。", "君看社後燕，還憶社前巢。"]'),
('70206371-1d83-4de0-bbbb-ab258f80508f','木犀初發','楊萬里','宋','宋诗','song-poetry','','[]','可笑詩人山澤臞，平生枯淡不敷腴。',64,'全唐诗/poet.song.141000.json','["可笑詩人山澤臞，平生枯淡不敷腴。", "已搜杞菊到詒厥，絕與木犀親友于。", "挼入杯中金粟走，滿澆天上桂華孤。", "醉眠繞枕兩三朶，香冰肝脾酒更無。"]'),
('ce9c2853-8681-4956-bb34-cad20e68eb78','明發金陵晨炊義井','楊萬里','宋','宋诗','song-poetry','','[]','薄薄雲收日，霏霏雨散池。',48,'全唐诗/poet.song.141000.json','["薄薄雲收日，霏霏雨散池。", "平波光去遠，疎點暈來遲。", "所部餘千里，初程第一詩。", "先驅問行李，雙堠且晨炊。"]'),
('f72b7cbe-9b02-48cf-89ea-7e0d4cded404','道旁槿籬','楊萬里','宋','宋诗','song-poetry','','[]','夾路疎籬錦作堆，朝開暮落復朝開。',64,'全唐诗/poet.song.141000.json','["夾路疎籬錦作堆，朝開暮落復朝開。", "抽心粔籹輕拖糝，近蔕燕支釅抹腮。", "占破半年猶道少，何曾一日不芳來。", "花中却是渠長命，換舊添新底用催。"]'),
('de9698a5-25cc-4f99-94a7-d1c3c026f410','圩田二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','週遭圩岸繚金城，一眼圩田翠不分。',32,'全唐诗/poet.song.141000.json','["週遭圩岸繚金城，一眼圩田翠不分。", "行到秋苗初熟處，翠茸錦上織黄雲。"]'),
('7f15d1d2-6887-446b-b986-6d5e2208295e','圩田二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','古來圩岸護隄防，岸岸行行種綠楊。',32,'全唐诗/poet.song.141000.json','["古來圩岸護隄防，岸岸行行種綠楊。", "歲久樹根無寸土，綠楊走入水中央。"]'),
('cb1de6db-666f-4974-a624-1c9469be04d7','蚤起秣陵鎮二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','人趁村中市，雞鳴擔上籠。',48,'全唐诗/poet.song.141000.json','["人趁村中市，雞鳴擔上籠。", "忽看一天紫，未吐半輪紅。", "誰撼扶桑露，吹來楊柳風。", "詩肩忍涼冷，已出兩臞峰。"]'),
('ddfe3089-9385-448d-a4fd-f934a1e2d8de','蚤起秣陵鎮二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','山路祇言迥，農家俱夙興。',48,'全唐诗/poet.song.141000.json','["山路祇言迥，農家俱夙興。", "短長羣穉子，迴避一田塍。", "隨犬能知路，騎牛底用繩。", "茲行有勝事，何處不豐登。"]'),
('51c2214a-4071-459c-b5b7-064f1f29d90c','觀稼','楊萬里','宋','宋诗','song-poetry','','[]','井字行都整，花香遠已甜。',48,'全唐诗/poet.song.141000.json','["井字行都整，花香遠已甜。", "穗肥黄俯首，芒勁紫掀髯。", "風攪平雲陣，聲鬆缺月鐮。", "不愁禾把減，高廩却愁添。"]'),
('d8db08ff-9055-4e38-b240-7808f51090f7','路口回望方山','楊萬里','宋','宋诗','song-poetry','','[]','鍾阜回頭失，方山戀眼寒。',48,'全唐诗/poet.song.141000.json','["鍾阜回頭失，方山戀眼寒。", "似巾簷短帽，如覆玉琱盤。", "每恨青蒼遠，因行反覆看。", "歸時記面目，城裏指雲端。"]'),
('57552532-10d0-4a32-84d9-91b6f7b3da16','甯橋小渡','楊萬里','宋','宋诗','song-poetry','','[]','橋壞仍泥滑，舟橫隔水呼。',48,'全唐诗/poet.song.141000.json','["橋壞仍泥滑，舟橫隔水呼。", "岸頭危徑窄，轎子莫人扶。", "午漏相將裏，秋陽未肯無。", "明知近前店，暗覺展脩途。"]'),
('105a3b6d-54ac-4cc7-9fcc-decfe2f61261','橫山','楊萬里','宋','宋诗','song-poetry','','[]','已過方山了，橫山更絕奇。',48,'全唐诗/poet.song.141000.json','["已過方山了，橫山更絕奇。", "爭高一尖喜，妬逸衆青追。", "萬馬頭驚拶，千旗脚恣吹。", "娟峰恰三五，隔柳尚參差。"]'),
('e4b02d95-1e8d-427f-ad01-76c4cd7f53ef','入溧水界閲堠子','楊萬里','宋','宋诗','song-poetry','','[]','纔入溧水界，休教勤吏民。',48,'全唐诗/poet.song.141000.json','["纔入溧水界，休教勤吏民。", "是誰差堠子，久立待車塵。", "苔蘚今仍古，風霜秋復春。", "不知雙與隻，迎送幾行人。"]'),
('98b1497f-5242-4a8f-9791-6e219fb28026','午憩方虛坐睡','楊萬里','宋','宋诗','song-poetry','','[]','午暑殘偏力，長亭歇未行。',48,'全唐诗/poet.song.141000.json','["午暑殘偏力，長亭歇未行。", "睡鄉蠅俶擾，詩陣筆專征。", "今夕南吾枕，何時北我旌。", "不應菊花酒，兒女不同傾。"]'),
('d8bf60d5-b2c7-452a-85e6-f7fa7ec60bb0','樊系','楊萬里','宋','宋诗','song-poetry','','[]','冊文不做也由伊，做了何須死不辭。',32,'全唐诗/poet.song.141000.json','["冊文不做也由伊，做了何須死不辭。", "可惜一杯金屑酒，飲來祗較早些時。"]'),
('d09c0c7d-ef7c-4551-8e3e-4421405ca1db','方虛日斜再行宿烏山二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','日已衰容去，風仍劈面來。',48,'全唐诗/poet.song.141000.json','["日已衰容去，風仍劈面來。", "征徒歇得醒，老子不須催。", "綠蔭涼過傘，黄泥曬作埃。", "欣然片雲起，半霎又吹開。"]'),
('48031301-a7a9-44ff-ac0b-295a300dee37','方虛日斜再行宿烏山二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','多稼村村過，垂楊店店迎。',48,'全唐诗/poet.song.141000.json','["多稼村村過，垂楊店店迎。", "偶然逢客子，問得好山名。", "投宿欣猶早，斜陽落更明。", "僕人休進扇，得似晚風清。"]'),
('adffbd5e-dc67-4150-8d07-971e850a7dbf','發烏山入溧水縣中山驛','楊萬里','宋','宋诗','song-poetry','','[]','雨脚依山見，風頭觸樹回。',48,'全唐诗/poet.song.141000.json','["雨脚依山見，風頭觸樹回。", "泥深行不去，轎兀睡還來。", "栩栩情微適，喧喧眼竟開。", "夢殘那可續，續得轉悠哉。"]'),
('de9180eb-6319-4f98-bc2a-473c719e1459','圩丁詞十解  其一','楊萬里','宋','宋诗','song-poetry','','[]','圩田元是一平湖，憑仗兒郎築作圩。',32,'全唐诗/poet.song.141000.json','["圩田元是一平湖，憑仗兒郎築作圩。", "萬雉長城倩誰守，兩隄楊柳當防夫。"]'),
('1e8ce84d-7b15-49c4-8c78-f7ef15941229','圩丁詞十解  其二','楊萬里','宋','宋诗','song-poetry','','[]','何代何人作此圩，石頑土膩鐵難如。',32,'全唐诗/poet.song.141000.json','["何代何人作此圩，石頑土膩鐵難如。", "年年二月桃花水，如律流歸石臼湖。"]'),
('be138fde-1f38-422d-aa00-e1cd55d66514','圩丁詞十解  其三','楊萬里','宋','宋诗','song-poetry','','[]','上通建德下當塗，千里江湖繚一圩。',32,'全唐诗/poet.song.141000.json','["上通建德下當塗，千里江湖繚一圩。", "本是陽侯水精國，天公敕賜上農夫。"]'),
('6560a60d-f1b5-45df-a2c2-35e78e656f83','圩丁詞十解  其四','楊萬里','宋','宋诗','song-poetry','','[]','南望雙峰抹綠明，一峰起立一峰橫。',32,'全唐诗/poet.song.141000.json','["南望雙峰抹綠明，一峰起立一峰橫。", "不知圩裏田多少，直到峰根不見塍。"]'),
('47e3f251-c8a0-462b-a922-501b4cdb4c29','圩丁詞十解  其五','楊萬里','宋','宋诗','song-poetry','','[]','兩岸沿隄有水門，萬波隨吐復隨吞。',32,'全唐诗/poet.song.141000.json','["兩岸沿隄有水門，萬波隨吐復隨吞。", "君看紅蓼花邊脚，補去脩來無水痕。"]'),
('7062511b-5be4-4506-a635-474cd9af3b94','圩丁詞十解  其六','楊萬里','宋','宋诗','song-poetry','','[]','年年圩長集圩丁，不要招呼自要行。',32,'全唐诗/poet.song.141000.json','["年年圩長集圩丁，不要招呼自要行。", "萬杵一鳴千畚土，大呼高唱總齊聲。"]'),
('85b3fa74-72a3-4bf4-8d34-12eb19f35e05','圩丁詞十解  其七','楊萬里','宋','宋诗','song-poetry','','[]','兒郎辛苦莫呼天，一日修圩一歲眠。',32,'全唐诗/poet.song.141000.json','["兒郎辛苦莫呼天，一日修圩一歲眠。", "六七月頭無點雨，試登高處望圩田。"]'),
('6aaef776-60fb-45d3-bc21-a586aa564fdd','圩丁詞十解  其八','楊萬里','宋','宋诗','song-poetry','','[]','岸頭石板紫縱橫，不是修圩是築城。',32,'全唐诗/poet.song.141000.json','["岸頭石板紫縱橫，不是修圩是築城。", "傳語赫連莫蒸土，霸圖未必賽春耕。"]'),
('2e3d325f-f36b-493d-8f67-8621c0b3c6de','圩丁詞十解  其九','楊萬里','宋','宋诗','song-poetry','','[]','河水還高港水低，千枝萬派曲穿畦。',32,'全唐诗/poet.song.141000.json','["河水還高港水低，千枝萬派曲穿畦。", "斗門一閉君休笑，要看水從人指揮。"]'),
('a6c283f2-be74-482b-b00d-91f3dee96433','圩丁詞十解  其一○','楊萬里','宋','宋诗','song-poetry','','[]','圩上人牽水上航，從頭點檢萬農桑。',32,'全唐诗/poet.song.141000.json','["圩上人牽水上航，從頭點檢萬農桑。", "即非使者秋行部，乃是圩翁曉按莊。"]'),
('69a3363b-6b58-4bc4-928b-14bec100305a','宿孔鎮觀雨中蛛絲五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雨打蛛絲不打蛛，雨來蛛入畫簷隅。',32,'全唐诗/poet.song.141000.json','["雨打蛛絲不打蛛，雨來蛛入畫簷隅。", "網羅滿腹輸渠巧，也只蠅蚊命屬渠。"]'),
('68038faa-6b75-4e67-ae26-8a3142e273ea','宿孔鎮觀雨中蛛絲五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','雨罷蜘蛛却出簷，網絲小減再新添。',32,'全唐诗/poet.song.141000.json','["雨罷蜘蛛却出簷，網絲小減再新添。", "莫言辛苦無功業，便有飛蟲密處粘。"]'),
('e241fb01-c8ce-4c6b-bc94-101bf298c4ab','宿孔鎮觀雨中蛛絲五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','空中仰面却飛身，寂似毗耶不動尊。',32,'全唐诗/poet.song.141000.json','["空中仰面却飛身，寂似毗耶不動尊。", "忽有一蚊來觸網，手忙脚亂便星奔。"]'),
('58e05f52-980e-4659-95ca-37913ea6573f','宿孔鎮觀雨中蛛絲五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','走得團團織得窠，羣飛來往不逃它。',32,'全唐诗/poet.song.141000.json','["走得團團織得窠，羣飛來往不逃它。", "網羅外面逃多少，枉了辛勤設網羅。"]'),
('589bff73-35a5-46e1-8628-ddf619808274','宿孔鎮觀雨中蛛絲五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','網羅最密是蛛絲，却被秋蚊聖得知。',32,'全唐诗/poet.song.141000.json','["網羅最密是蛛絲，却被秋蚊聖得知。", "粘著便飛來不再，蛛絲也解有疎時。"]'),
('5695319d-9d4f-4fe3-804a-40f6890af644','蛩聲三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','山行我已厭征塵，夜語誰能伴老身。',32,'全唐诗/poet.song.141000.json','["山行我已厭征塵，夜語誰能伴老身。", "幸有暗蛩同店宿，被渠告訴却愁人。"]'),
('5d9ee911-5d38-4146-878b-0347ff62bc74','蛩聲三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','床根吟夜句冥搜，莎底啼寒泣怨秋。',32,'全唐诗/poet.song.141000.json','["床根吟夜句冥搜，莎底啼寒泣怨秋。", "人世如何無苦樂，一般蟋蟀兩般愁。"]'),
('b0319ae2-4b6d-44c2-8537-1bea5faf3fb8','蛩聲三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','莫憎苦調太酸辛，月思霜哀亦可人。',32,'全唐诗/poet.song.141000.json','["莫憎苦調太酸辛，月思霜哀亦可人。", "村路小家無此客，溧陽少府是前身。"]'),
('9fbcec0b-4b22-45f7-a9a6-b69faa917d90','發孔鎮晨炊漆橋道中紀行十首  其一','楊萬里','宋','宋诗','song-poetry','','[]','夢中一夜雨浪浪，曉過田間尚雨香。',32,'全唐诗/poet.song.141000.json','["夢中一夜雨浪浪，曉過田間尚雨香。", "塘水溉田能幾許，雨餘田水却歸塘。"]'),
('ddbdd272-57c7-4b8d-9d6a-74c75f97846e','發孔鎮晨炊漆橋道中紀行十首  其二','楊萬里','宋','宋诗','song-poetry','','[]','可堪衰病兩相纏，更苦懸車尚五年。',32,'全唐诗/poet.song.141000.json','["可堪衰病兩相纏，更苦懸車尚五年。", "羨殺雨中山上水，留它不住竟歸田。"]'),
('e44f5ba0-ddcd-4b43-a327-41800e33eef7','發孔鎮晨炊漆橋道中紀行十首  其三','楊萬里','宋','宋诗','song-poetry','','[]','雨入秋田恰及時，禾頭相枕卧相依。',32,'全唐诗/poet.song.141000.json','["雨入秋田恰及時，禾頭相枕卧相依。", "路南路北皆秋水，浄洗行人屨上泥。"]'),
('58fb7ab4-4933-452c-ba55-bd087f60d217','發孔鎮晨炊漆橋道中紀行十首  其四','楊萬里','宋','宋诗','song-poetry','','[]','不但秋原雨冒田，坐看平地路成川。',32,'全唐诗/poet.song.141000.json','["不但秋原雨冒田，坐看平地路成川。", "隔田山下青松外，不見人家只見煙。"]'),
('616583a5-8900-4166-bc9d-5736d6fbb813','發孔鎮晨炊漆橋道中紀行十首  其五','楊萬里','宋','宋诗','song-poetry','','[]','斫地燒畬旋旋開，豆花麻莢更菘栽。',32,'全唐诗/poet.song.141000.json','["斫地燒畬旋旋開，豆花麻莢更菘栽。", "荒山半寸無遺土，田父何曾一飽來。"]'),
('8b5a1af3-0125-47ab-b5a2-8899446681c7','發孔鎮晨炊漆橋道中紀行十首  其六','楊萬里','宋','宋诗','song-poetry','','[]','君看人跡蝶來輕，踏得林間路作坑。',32,'全唐诗/poet.song.141000.json','["君看人跡蝶來輕，踏得林間路作坑。", "古路今人行不得，一時移上上頭行。"]'),
('ddfc81a1-406e-4b26-8b3f-9ca650bb9efe','發孔鎮晨炊漆橋道中紀行十首  其七','楊萬里','宋','宋诗','song-poetry','','[]','行穿詰曲更崔嵬，野店柴門半未開。',32,'全唐诗/poet.song.141000.json','["行穿詰曲更崔嵬，野店柴門半未開。", "皂莢樹陰黄草屋，隔籬犬吠出頭來。"]'),
('196743c4-cbf6-4aa9-afb3-0e030df1833d','發孔鎮晨炊漆橋道中紀行十首  其八','楊萬里','宋','宋诗','song-poetry','','[]','雨入秋空細復輕，松梢積得太多生。',32,'全唐诗/poet.song.141000.json','["雨入秋空細復輕，松梢積得太多生。", "忽然落點拳來大，偏作行人滴傘聲。"]'),
('5bf02d43-b60b-439d-a61a-0696bf1a0e0f','發孔鎮晨炊漆橋道中紀行十首  其九','楊萬里','宋','宋诗','song-poetry','','[]','清曉新涼愜老懷，只愁傔從可憐哉。',32,'全唐诗/poet.song.141000.json','["清曉新涼愜老懷，只愁傔從可憐哉。", "泥行寸步無由到，雨去前山却復回。"]'),
('7fe5e488-ff16-44c9-86c6-229adcddcc74','發孔鎮晨炊漆橋道中紀行十首  其一○','楊萬里','宋','宋诗','song-poetry','','[]','水夾橫隄柳萬株，雨餘新沐更新梳。',32,'全唐诗/poet.song.141000.json','["水夾橫隄柳萬株，雨餘新沐更新梳。", "柔條如線長而細，不貫雙魚只貫珠。"]'),
('67b6f24f-72fb-4054-b1c7-f576ecf46851','過平公橋','楊萬里','宋','宋诗','song-poetry','','[]','高岸行成路，清渠淡不波。',48,'全唐诗/poet.song.141000.json','["高岸行成路，清渠淡不波。", "荇花深似菊，芡葉皺於荷。", "聞道新橋好，還成带雨過。", "如何平氏店，宿處不逢它。"]'),
('57be10d9-c4f2-4b7c-9013-dd7d87f377af','水漚二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','淡日輕雲雨點疎，大漚隨雨起清渠。',32,'全唐诗/poet.song.141000.json','["淡日輕雲雨點疎，大漚隨雨起清渠。", "跳來走去瓊盤裏，創見龍宮徑寸珠。"]'),
('080db6c2-240a-4676-a7c5-d07dfc0f5168','水漚二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','至寶何緣識得全，驪珠浮沒只俄然。',32,'全唐诗/poet.song.141000.json','["至寶何緣識得全，驪珠浮沒只俄然。", "金仙額上莊嚴底，只許凡人見半邊。"]'),
('eed62ee0-367a-4d8d-93fd-c3ffafc1c97a','攸山望石臼湖','楊萬里','宋','宋诗','song-poetry','','[]','雨中深閉轎窗紗，驚見孤光射眼花。',32,'全唐诗/poet.song.141000.json','["雨中深閉轎窗紗，驚見孤光射眼花。", "一顧平湖山盡處，碧銅鏡外走青蛇。"]'),
('eee67cc2-0ec6-4b26-b401-57d8dc2ac004','野店二絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','不勞官吏出將迎，山店如何遠有聲。',32,'全唐诗/poet.song.141000.json','["不勞官吏出將迎，山店如何遠有聲。", "人報官來爭出看，牛逢轎過忽然驚。"]'),
('e1f456e6-4b31-412d-864c-031d348a3b99','野店二絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','山店茅柴强一杯，梨酸藕苦眼慵開。',32,'全唐诗/poet.song.141000.json','["山店茅柴强一杯，梨酸藕苦眼慵開。", "深紅元子輕紅鮓，難得江西鄉味來。"]'),
('608d7311-96c0-47d4-a808-ee1d36abbcdb','菱沼','楊萬里','宋','宋诗','song-poetry','','[]','柄似蟾蜍股樣肥，葉如蝴蝶翼相差。',32,'全唐诗/poet.song.141000.json','["柄似蟾蜍股樣肥，葉如蝴蝶翼相差。", "蟾蜍翹立蝶飛起，便是菱花著子時。"]'),
('4c46f5eb-f41d-4a7d-8dd2-86ea478b2c1c','山村二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','一搭山村一搭奇，不堪風物索新詩。',64,'全唐诗/poet.song.141000.json','["一搭山村一搭奇，不堪風物索新詩。", "稻花雪白糝柳絮，柘子猩紅團荔枝。", "行者自愁居者樂，晴時即熱雨時泥。", "問知桐汭多程在，未說宣城與貴池。"]'),
('36cf85ec-8322-4b79-912b-69c9f7a30e63','山村二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','歇處何防更歇些，宿頭未到日頭斜。',64,'全唐诗/poet.song.141000.json','["歇處何防更歇些，宿頭未到日頭斜。", "風煙綠水青山國，籬落紫茄黄豆家。", "雨足一年生事了，我行三日去程賒。", "老夫不是如今錯，初識陶泓計已差。"]'),
('f71a5972-a867-4054-ac4a-177e8baa967c','發銀樹林','楊萬里','宋','宋诗','song-poetry','','[]','莫過溪橋銀樹林，溪深未抵路泥深。',64,'全唐诗/poet.song.141000.json','["莫過溪橋銀樹林，溪深未抵路泥深。", "清風一陣掠人面，晴色半開關客心。", "遠嶺惹雲秋裏雪，淡天刷墨曉來陰。", "幾多好句爭投我，柳奪花偷底處尋。"]'),
('ca2dac3c-499e-4831-9756-d344daaaa0b0','入建平界二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','溧水南頭接建平，丫頭兒子便勤耕。',64,'全唐诗/poet.song.141000.json','["溧水南頭接建平，丫頭兒子便勤耕。", "疎麻大豆已前輩，蕎麥晚菘初後生。", "席卷千山爲一囿，天憐春種賜秋成。", "不如老圃今真箇，樊子何曾透聖扃。"]'),
('ef0c440e-f9d6-41bf-aeea-3620de5069d4','入建平界二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一歲昇平在一收，今年田父又無愁。',64,'全唐诗/poet.song.141000.json','["一歲昇平在一收，今年田父又無愁。", "接天稻穗黄嬌日，照水蓼花紅滴秋。", "風有炎涼纔頃刻，雨無朝暮政滂流。", "浪言出却金陵界，入却廬陵界始休。"]'),
('62325ac0-5977-4faf-ac98-b0b511abfd99','早炊童家店','楊萬里','宋','宋诗','song-poetry','','[]','長亭深處小亭奇，雜蘤粗蕤亦有姿。',64,'全唐诗/poet.song.141000.json','["長亭深處小亭奇，雜蘤粗蕤亦有姿。", "羊角豆纏松葉架，雞冠花隔竹槍籬。", "不辭雨卧風餐裏，可惜橙黄橘綠時。", "行到前頭楊柳逕，平分紅白兩蓮池。"]'),
('991d729f-ed97-409b-846f-2a5b289d30b5','過謝家灣','楊萬里','宋','宋诗','song-poetry','','[]','行盡牛蹊兔逕中，忽逢平野四連空。',64,'全唐诗/poet.song.141000.json','["行盡牛蹊兔逕中，忽逢平野四連空。", "意隨白鷺一雙去，眼過青山千萬重。", "近嶺已看看遠嶺，連峰不愛愛孤峰。", "一丘一壑知何意，疎盡官人著牧童。"]'),
('2538ea6a-7c04-41dd-9771-d404f07d7a8b','轎中看山','楊萬里','宋','宋诗','song-poetry','','[]','買山安得錢，有錢價不賤。',240,'全唐诗/poet.song.141000.json','["買山安得錢，有錢價不賤。", "住山如冠玉，人見我不見。", "世言游山好，一峰足雙繭。", "峰外復有峰，歷盡獨能徧。", "不如近看山，近看不如遠。", "請山略退步，容我與對面。", "我行山欣隨，我住山樂伴。", "有酒喚山飲，有蔌分山饌。", "隔水絕高寒，縈雲偏蒨絢。", "雨滋青彌深，日炫紫還淺。", "端居忽飛動，遐逝即回轉。", "孤秀呈復逃，層尖隠還顯。", "掇入轎中來，置在几上玩。", "劣行三兩驛，已閲百千變。", "非我去旁搜，皆渠來自獻。", "寄言有山人，勿賣亦勿典。", "金多汝安用，價重山亦怨。", "估若爲我低，傷廉又非願。", "山已在胸中，豈復有餘羨。", "羨心固無餘，更借山一看。"]'),
('e936dd45-1c24-4887-b75d-2a5d80819f5f','嘲蜻蜓','楊萬里','宋','宋诗','song-poetry','','[]','餌花春蝶即花仙，飲露秋蟬怕露寒。',32,'全唐诗/poet.song.141000.json','["餌花春蝶即花仙，飲露秋蟬怕露寒。", "只道蜻蜓解餐水，元來照水不曾餐。"]'),
('d9324d48-ee3f-417a-b771-58dd42a84925','發中橋二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','濕轎乘涼入，斜燈借路明。',48,'全唐诗/poet.song.141000.json','["濕轎乘涼入，斜燈借路明。", "柳欹元不倒，橋闊自多驚。", "宿霤停殘滴，朝曦放快晴。", "溪流太無頼，不作一聲聲。"]'),
('029b5979-6e77-4712-b990-57d0861b82cd','發中橋二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','新雨豐今歲，初晴屏積陰。',48,'全唐诗/poet.song.141000.json','["新雨豐今歲，初晴屏積陰。", "猛收千疋練，微露一稜金。", "天熨粉青嫩，山描愁黛深。", "誰言殘剩暑，卓午不相尋。"]'),
('07ed7265-499a-4e1e-a7a7-0ba3143fe125','早炊高店','楊萬里','宋','宋诗','song-poetry','','[]','過雨溪山十倍明，乍晴風日一番清。',64,'全唐诗/poet.song.141000.json','["過雨溪山十倍明，乍晴風日一番清。", "白鷗池沼菰蒲影，紅棗村虛雞犬聲。", "肉食坐曹良媿死，囊衣行部亦勞生。", "不堪有七今成九，傖父年來老更傖。"]'),
('991ff38b-426e-403e-b9c8-d092093967ad','午熱憩忠義渡','楊萬里','宋','宋诗','song-poetry','','[]','秋陽嗔我緊追程，急泊臨流一短亭。',64,'全唐诗/poet.song.141000.json','["秋陽嗔我緊追程，急泊臨流一短亭。", "摘索風巾些子倦，蒼茫水枕霎時醒。", "單牌雙堠頭都白，萬壑千巖眼强青。", "不及溪邊老亭父，一生卧護竹窗櫺。"]'),
('16017dc6-85a0-4a9b-87aa-670c8d6bac37','宿雞林坊二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','路覺往而復，意迷東與西。',48,'全唐诗/poet.song.141000.json','["路覺往而復，意迷東與西。", "元來八九渡，只是一條溪。", "亭午雖微暑，茲辰較少泥。", "諸峰雲上出，不但與雲齊。"]'),
('261bbf94-bb48-4735-9f18-eadc295c5680','宿雞林坊二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','草有清無俗，田生不用耘。',48,'全唐诗/poet.song.141000.json','["草有清無俗，田生不用耘。", "菰花琱品字，荇葉缺錢文。", "出水浮難沒，遥風浄更芬。", "物情豈難狀，作麽未前聞。"]'),
('a1192232-569e-4dc1-901b-738c9f7e2e92','初九夜月二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','珍重姮娥住廣寒，不餐火食不餐煙。',32,'全唐诗/poet.song.141000.json','["珍重姮娥住廣寒，不餐火食不餐煙。", "秋空拾得一團餠，隨手如何失半邊。"]'),
('9f64c52e-f04f-4962-bbe4-2e7d9c682d89','初九夜月二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','也知月姊是天姝，天上人間絕世無。',32,'全唐诗/poet.song.141000.json','["也知月姊是天姝，天上人間絕世無。", "霧刷雲撩何不可，却須插一水精梳。"]'),
('04c629b6-8567-42ac-ba2e-094bc1763316','村店竹床','楊萬里','宋','宋诗','song-poetry','','[]','村店事事無，秋熱夜夜至。',24,'全唐诗/poet.song.141000.json','["村店事事無，秋熱夜夜至。", "一雙好竹床，無人將去睡。"]'),
('cb1872a0-f51c-4716-a5f5-23424ad86621','問月二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','月色幸自好，元無半點雲。',24,'全唐诗/poet.song.141000.json','["月色幸自好，元無半點雲。", "移床來一看，雲月兩昏昏。"]'),
('11759129-026a-421f-88c0-b47631f882f2','問月二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','月入雲中去，呼他不出來。',24,'全唐诗/poet.song.141000.json','["月入雲中去，呼他不出來。", "明宵教老子，何面更相陪。"]'),
('8f5e0424-895c-41ea-8489-266a66ab1811','將睡四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','老夫豈不眠，只是眠未得。',24,'全唐诗/poet.song.141000.json','["老夫豈不眠，只是眠未得。", "若到睡思來，華胥是誰國。"]'),
('4e47b462-d4dd-4f06-8b55-5e406ac07623','將睡四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一更打二點，夜夜此時睡。',24,'全唐诗/poet.song.141000.json','["一更打二點，夜夜此時睡。", "今夜當此時，不睡緣底事。"]'),
('da80f491-8c9d-4656-aa59-9d9a85a9af94','將睡四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','已被詩爲祟，更添茶作魔。',24,'全唐诗/poet.song.141000.json','["已被詩爲祟，更添茶作魔。", "端能去二者，一武到無何。"]'),
('b5c74c24-1dd0-4cb0-865c-8afc6bb6e15d','將睡四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','睡去非不願，熱來無奈何。',24,'全唐诗/poet.song.141000.json','["睡去非不願，熱來無奈何。", "蒙渠致西爽，爲汝守南柯。"]'),
('c5799fc3-0fb4-478b-b6f7-362d613ca075','曉行望雲山','楊萬里','宋','宋诗','song-poetry','','[]','霽天欲曉未明間，滿目奇峰總可觀。',32,'全唐诗/poet.song.141000.json','["霽天欲曉未明間，滿目奇峰總可觀。", "却有一峰忽然長，方知不動是真山。"]'),
('c3c7a1ae-2c90-4f4a-8ba5-3de42bf7ffbe','歸雲三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','可殺歸雲也愛山，夜來都宿好山間。',32,'全唐诗/poet.song.141000.json','["可殺歸雲也愛山，夜來都宿好山間。", "偶看一絮翩然起，引得崩騰相趁還。"]'),
('a6a13c08-9057-4995-998e-c45b9249a9f0','歸雲三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','三足鴉兒出海東，飛光一朶染天紅。',32,'全唐诗/poet.song.141000.json','["三足鴉兒出海東，飛光一朶染天紅。", "只銷半點歸雲動，立地濛濛暗太空。"]'),
('ed646d11-734f-4946-85d7-6991d24e267a','歸雲三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','坐看山頭託宿雲，一雲纔動萬雲奔。',32,'全唐诗/poet.song.141000.json','["坐看山頭託宿雲，一雲纔動萬雲奔。", "霍然散作千村霧，遠處昏來近處昏。"]'),
('d84c5819-0e6e-4a1f-b8ae-139c627f6d8b','日出','楊萬里','宋','宋诗','song-poetry','','[]','散雲作霧恰昏昏，收霧依前復作雲。',32,'全唐诗/poet.song.141000.json','["散雲作霧恰昏昏，收霧依前復作雲。", "一面紅金大圓鏡，盡銷雲霧照乾坤。"]'),
('cccb0e6c-80f5-42bc-939e-1adb6ac2d70b','道旁店','楊萬里','宋','宋诗','song-poetry','','[]','路旁野店兩三家，清曉無湯況有茶。',32,'全唐诗/poet.song.141000.json','["路旁野店兩三家，清曉無湯況有茶。", "道是渠儂不好事，青瓷瓶插紫薇花。"]'),
('694cc567-a817-4c38-94d8-814bff731d1f','蛛網','楊萬里','宋','宋诗','song-poetry','','[]','深山無水又無人，曬網攤罾奪日明。',32,'全唐诗/poet.song.141000.json','["深山無水又無人，曬網攤罾奪日明。", "却是蜘蛛遭積雨，經綸家計趁新晴。"]'),
('2c7001df-fccd-489a-b02b-c0dc86022939','加餐','楊萬里','宋','宋诗','song-poetry','','[]','脫髮星星徧，加餐日日新。',48,'全唐诗/poet.song.141000.json','["脫髮星星徧，加餐日日新。", "二升卧龍玉，一斗謫仙春。", "雲子恐稱屈，麴生能笑人。", "吾方有公事，公等不須嗔。"]'),
('7f224bcf-4478-447d-941d-9524d91dcde3','道旁竹','楊萬里','宋','宋诗','song-poetry','','[]','竹竿穿竹籬，却與籬爲柱。',24,'全唐诗/poet.song.141000.json','["竹竿穿竹籬，却與籬爲柱。", "大小且相依，榮枯何足顧。"]'),
('f35edcc9-5091-495a-86b2-665ad586b827','曉行山煙','楊萬里','宋','宋诗','song-poetry','','[]','曉煙橫抹碧山隅，只在松梢疋練如。',32,'全唐诗/poet.song.141000.json','["曉煙橫抹碧山隅，只在松梢疋練如。", "作意行前尋一看，遠濃近淡忽都無。"]'),
('47aa654e-ad10-42be-8c7f-43c9b707b002','雨漱紫泥','楊萬里','宋','宋诗','song-poetry','','[]','道旁雨漱紫浮泥，高底成山下底溪。',64,'全唐诗/poet.song.141000.json','["道旁雨漱紫浮泥，高底成山下底溪。", "谷轉峰回雲出岫，沙翻石走草緣堤。", "波生蟋蟀漂新宅，水落蚍蜉識舊蹊。", "大地山河亦如此，看來只是許高低。"]'),
('8e60fcee-6b2f-49d9-97e9-ced5f193f13f','炬火發誓節渡勇家店二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','飄爐飛空落曉星，隨風入草化秋螢。',32,'全唐诗/poet.song.141000.json','["飄爐飛空落曉星，隨風入草化秋螢。", "莎蟲誤認天明了，却變寒聲作暖聲。"]'),
('bce5dc71-b768-410f-821b-1dbed02e936c','炬火發誓節渡勇家店二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','昨午秋陽尚壯哉，今晨莫待日光催。',32,'全唐诗/poet.song.141000.json','["昨午秋陽尚壯哉，今晨莫待日光催。", "麻蒸一照三十里，底用金蓮花炬來。"]'),
('50af7727-df45-42f8-8a19-5a3071c7a0e8','曉過花橋入宣州界四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','路入宣城山便奇，蒼虯活走綠鸞飛。',32,'全唐诗/poet.song.141000.json','["路入宣城山便奇，蒼虯活走綠鸞飛。", "詩人眼毒已先見，却旋褰雲作翠幃。"]'),
('98d2b488-b028-4482-b46c-0632964b87f2','曉過花橋入宣州界四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','敬亭宛水故依然，疊嶂雙溪阿那邊。',32,'全唐诗/poet.song.141000.json','["敬亭宛水故依然，疊嶂雙溪阿那邊。", "謝守不生梅老死，倩誰海內掌風煙。"]'),
('6a3665e3-32a2-4b76-9fa1-9ba97b4d9340','曉過花橋入宣州界四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','近山淺綠遠深青，兩樣風姿一樣清。',32,'全唐诗/poet.song.141000.json','["近山淺綠遠深青，兩樣風姿一樣清。", "似怨朝陽卷雲霧，被儂看著太分明。"]'),
('392e5833-b638-4086-a419-3cadf3b34ed2','曉過花橋入宣州界四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','不是青山是畫圖，南山瘦削北敷腴。',32,'全唐诗/poet.song.141000.json','["不是青山是畫圖，南山瘦削北敷腴。", "兩山名姓君知麽，一字玄暉一聖俞。"]'),
('3167205d-3417-4f99-af33-6ae91149b740','野店多賣花木瓜','楊萬里','宋','宋诗','song-poetry','','[]','天下宣城花木瓜，日華露液繡成花。',32,'全唐诗/poet.song.141000.json','["天下宣城花木瓜，日華露液繡成花。", "何須堠子强呈界，自有瓊琚先報衙。"]'),
('d933c281-1bf2-429f-80ae-c05e6ddbb297','花果','楊萬里','宋','宋诗','song-poetry','','[]','野花山果絕芳馨，借問行人不識名。',32,'全唐诗/poet.song.141000.json','["野花山果絕芳馨，借問行人不識名。", "蜂蝶行糧猿鶴飯，一生口分兩無爭。"]'),
('5d34cf58-df98-4608-9807-a1c7fe318640','午熱','楊萬里','宋','宋诗','song-poetry','','[]','也無半點爽風吹，坐轎分明是甑炊。',32,'全唐诗/poet.song.141000.json','["也無半點爽風吹，坐轎分明是甑炊。", "宿處問來猶五里，火輪煽得正炎時。"]'),
('90357544-23dd-4155-b34f-5aefbc76c8c8','月中炬火發仙山驛小睡射亭五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','道是宵征即曉光，若言明發未朝陽。',32,'全唐诗/poet.song.141000.json','["道是宵征即曉光，若言明發未朝陽。", "月華露氣山兼水，享盡人間第一涼。"]'),
('9539e796-dc1b-4b1d-b012-7abdb0632043','月中炬火發仙山驛小睡射亭五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','踏月何銷秉炬行，也防月落未天明。',32,'全唐诗/poet.song.141000.json','["踏月何銷秉炬行，也防月落未天明。", "果然留下長庚去，更賺行人作曉星。"]'),
('7df4c06d-2afc-43c1-ae11-2fe71a78d2e3','月中炬火發仙山驛小睡射亭五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','月輪已落尚殘光，一似西山沒夕陽。',32,'全唐诗/poet.song.142000.json','["月輪已落尚殘光，一似西山沒夕陽。", "次第長庚都落去，日華猶未出扶桑。"]'),
('69839e8f-77f3-41ef-95c6-12e1ae5afc8a','月中炬火發仙山驛小睡射亭五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','長庚初讓月先行，不料姮娥也世情。',32,'全唐诗/poet.song.142000.json','["長庚初讓月先行，不料姮娥也世情。", "趣駕冰輪渡銀浦，亂拋玉李擲長庚。"]'),
('5aadb1d3-58e2-4e09-9e91-c8c493f7062a','月中炬火發仙山驛小睡射亭五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','轎中兀得軟如癡，逢店投床片子時。',32,'全唐诗/poet.song.142000.json','["轎中兀得軟如癡，逢店投床片子時。", "睡覺不知天曉未，半窗花影木犀枝。"]'),
('8c6ec6cc-95eb-4cd7-8143-59638063ec6a','甘瓠','楊萬里','宋','宋诗','song-poetry','','[]','笑殺桑根甘瓠苗，亂它桑葉上它條。',32,'全唐诗/poet.song.142000.json','["笑殺桑根甘瓠苗，亂它桑葉上它條。", "向人更逞廋藏巧，怪道桑梢挂一瓢。"]'),
('18794b0b-23d7-413e-85db-31a50e6a0c90','五更入宣城詣天慶觀朝謁','楊萬里','宋','宋诗','song-poetry','','[]','曉霧雙溪水，秋風百舫橋。',48,'全唐诗/poet.song.142000.json','["曉霧雙溪水，秋風百舫橋。", "行穿子城過，却望女牆遥。", "落月能相伴，疎鐘似見招。", "小亭憩山半，換馬上岧嶢。"]'),
('04429195-f979-4b07-8cd4-d6f39bb1dc0b','中秋前一夕雨中登雙溪疊嶂已而月出二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','州在三峰最上頭，上頭高處更高樓。',64,'全唐诗/poet.song.142000.json','["州在三峰最上頭，上頭高處更高樓。", "都將萬壑千巖景，堆作雙溪疊嶂秋。", "晚雨纔收山盡出，暮天似水月如流。", "敬亭堪喜還堪恨，領得風光攬得愁。"]'),
('bd5b2a63-2f12-4e73-a0fc-9049ad29dd6b','中秋前一夕雨中登雙溪疊嶂已而月出二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','雙溪疊嶂舊知名，投老初登眼不醒。',64,'全唐诗/poet.song.142000.json','["雙溪疊嶂舊知名，投老初登眼不醒。", "一雨飛來四天黑，亂雲遮斷萬峰青。", "急呼月色開秋色，奪得昭亭與敬亭。", "自笑詩翁猶狡獪，不饒山鬼弄精靈。"]'),
('aedf5cc2-1617-4252-8f62-bf3c3acec223','新凉','楊萬里','宋','宋诗','song-poetry','','[]','毛空兩日散霏微，勒住陰雲且四垂。',32,'全唐诗/poet.song.142000.json','["毛空兩日散霏微，勒住陰雲且四垂。", "一路新涼君會否，晴無日色雨無泥。"]'),
('09a3c1cd-0212-46d4-8540-efec541d885c','中秋無月宿青弋江曉行新寒','楊萬里','宋','宋诗','song-poetry','','[]','新寒催我索衣裘，涼雨淒雲總是愁。',32,'全唐诗/poet.song.142000.json','["新寒催我索衣裘，涼雨淒雲總是愁。", "耐冷素娥今老去，夜來桂殿罷中秋。"]'),
('50bb2b68-7b9f-4c50-a248-b5361c3b52af','秋花','楊萬里','宋','宋诗','song-poetry','','[]','顦顇牽牛病雨些，凋零木槿怯風斜。',32,'全唐诗/poet.song.142000.json','["顦顇牽牛病雨些，凋零木槿怯風斜。", "道邊籬落聊遮眼，白白紅紅匾豆花。"]'),
('3c03d6c6-a303-4ef3-b8ff-f277b5122136','過青陽縣望九華山雲中不真來早大霧竟不見其全三首  其一','楊萬里','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','山長百里玉孱顔，百里何緣盡好山。',32,'全唐诗/poet.song.142000.json','["山長百里玉孱顔，百里何緣盡好山。", "只是縣前青一簇，九芙蓉出五雲間。"]'),
('a33eda11-e68d-47d4-b956-6b0b96b409fd','過青陽縣望九華山雲中不真來早大霧竟不見其全三首  其二','楊萬里','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','肩輿過了九華西，恨殺秋雲故故低。',32,'全唐诗/poet.song.142000.json','["肩輿過了九華西，恨殺秋雲故故低。", "遮盡奇峰時放出，逐峰放出不教齊。"]'),
('3fc6b1ba-d163-46b7-903c-7ed632a42ff9','過青陽縣望九華山雲中不真來早大霧竟不見其全三首  其三','楊萬里','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','懊惱西來不見山，五更指準月中看。',32,'全唐诗/poet.song.142000.json','["懊惱西來不見山，五更指準月中看。", "却將香霧寬裁幕，性燥和天總一漫。"]'),
('00d90d91-d4da-4ab6-97cd-15f02212cccf','四更發青陽縣西五里柯家店','楊萬里','宋','宋诗','song-poetry','','[]','轎中萬兀路千縈，死盡村雞無一鳴。',64,'全唐诗/poet.song.142000.json','["轎中萬兀路千縈，死盡村雞無一鳴。", "落月正明知未曉，暗泉甚遠只聞聲。", "自緣客子行來早，豈是秋天不肯明。", "午熱未來先下店，却將晝睡補宵征。"]'),
('addf8ff1-1a4c-48eb-a0c8-6864bc365721','宿池州齊山寺即杜牧之九日登高處','楊萬里','宋','宋诗','song-poetry','','[]','我來秋浦政逢秋，夢裏曾來似舊游。',64,'全唐诗/poet.song.142000.json','["我來秋浦政逢秋，夢裏曾來似舊游。", "風月不供詩酒債，江山長管古今愁。", "謫仙狂飲顛吟寺，小杜倡情冶思樓。", "問著州民渾不識，齊山依舊俯寒流。"]'),
('1286af9e-50b8-4094-93fb-2a087443ee2f','從提舉黄元章登齊山寺後上清巖翠微亭望郡城左清溪右大江蓋絕境云','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','西山落日浴長江，併貫清溪作一光。',64,'全唐诗/poet.song.142000.json','["西山落日浴長江，併貫清溪作一光。", "千嶂圍來天四合，孤城涌出水中央。", "樓臺玉塔雲間見，楊柳金隄鏡裏長。", "客子要窮秋浦眼，翠微亭上上清旁。"]'),
('ec0666a1-c975-4823-ab80-d5e7375116c1','秋浦登舟阻風泊池口','楊萬里','宋','宋诗','song-poetry','','[]','午眠化蝶化未成，夢中澒洞發大聲。',176,'全唐诗/poet.song.142000.json','["午眠化蝶化未成，夢中澒洞發大聲。", "軍鼙雷鼓百千面，援桴齊下作一鳴。", "起來推窗無一物，海潮打入齊山窟。", "數洲翻覆相盪摩，四山動摇皆突兀。", "錢塘潮來聲驚天，金陵潮來聲寂然。", "此去金陵一千里，那得潮聲來到此。", "長年三老笑復嘲，云是波聲不是潮。", "清溪波頭高過屋，大江波頭潑日轂。", "清溪去江一步地，大江可望不可至。", "北風向晚動地來，跳出銀峰萬萬堆。", "儂船莫管行不得，且看銀峰永今夕。"]'),
('51a48f6f-03fa-4b9d-b13f-962456f21edf','池口移舟入江再泊十里頭潘家灣阻風不止','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','北風五日吹江練，江底吹翻作江面。',144,'全唐诗/poet.song.142000.json','["北風五日吹江練，江底吹翻作江面。", "大波一跳入天半，粉碎銀山成雪片。", "五日五夜無停時，長江倒流都上西。", "計程一日二千里，今踰灩澦到峨眉。", "更吹兩日江必竭，却將海水來相接。", "老夫蚤知當陸行，錯料一帆超十程。", "如今判却十程住，何策更與陽侯爭。", "水到峨眉無去處，下梢不到忘歸路。", "我到金陵水自東，只恐從此無南風。"]'),
('73be7397-754c-4312-93ce-5855aa3a8a81','舟中買雙鱖魚','楊萬里','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','金陵城中無纖鱗，一魚往往重六鈞。',160,'全唐诗/poet.song.142000.json','["金陵城中無纖鱗，一魚往往重六鈞。", "脊梁專車尾梢雲，肉如大武千秋筋。", "小港阻風泊烏舫，舫前漁艇晨收網。", "一雙白錦跳銀刀，玉質黑章大如掌。", "洞庭棖子青欲黄，香膚作線醯作漿。", "供儂朝喫復晚喫，秃尾槎頭俱避席。", "可憐秋浦好秋山，儂眼未飽即北還。", "江神挈月作團扇，一夜揮風卷波面。", "留儂看山仍看江，更薦鮮魚庖玉霜。", "江神好意那可忘，江神惡劇那可當。"]'),
('6fa9e118-f8e2-4fcb-98c4-ab14acb6c2e7','舟中排悶','楊萬里','宋','宋诗','song-poetry','','[]','江流一直還一曲，淮山一起還一伏。',128,'全唐诗/poet.song.142000.json','["江流一直還一曲，淮山一起還一伏。", "江流不肯放人行，淮山只管留人宿。", "老夫一出緣秋涼，半塗秋熱難禁當。", "却借樓船順流下，逆風五日殊未央。", "老夫平生行此世，不自爲政聽天地。", "只今未肯放歸程，安知天意非奇事。", "平生愛誦謫仙詩，百誦不熟良獨癡。", "舟中一日誦一首，誦得徧時應得歸。"]'),
('85f29f84-2102-4fb7-a378-1b1bcfd56c02','舟過大通鎮','楊萬里','宋','宋诗','song-poetry','','[]','淮上雲垂岸，江中浪拍天。',48,'全唐诗/poet.song.142000.json','["淮上雲垂岸，江中浪拍天。", "順風那敢望，下水更勞牽。", "蘆荻偏留纜，漁罾最礙船。", "何曾怨川后，魚蟹不論錢。"]'),
('4fa708ce-e30a-4855-b2c2-ca1844d6aed3','從丁家洲避風行小港出荻港大江三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','蓼岸藤灣隔盡人，大江小汊繞成輪。',64,'全唐诗/poet.song.142000.json','["蓼岸藤灣隔盡人，大江小汊繞成輪。", "圍蔬放荻不爭地，種柳堅隄非買春。", "匏瓠放教俱上屋，漁樵相倚自成鄰。", "夜來更下西風雪，蕎麥梢頭萬玉塵。"]'),
('c92514f5-9e4c-4d54-acc7-f3ab261af1d4','從丁家洲避風行小港出荻港大江三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','荻籬蕭灑織來新，茅屋橫斜畫不真。',64,'全唐诗/poet.song.142000.json','["荻籬蕭灑織來新，茅屋橫斜畫不真。", "乾地種禾那用水，濕蘆經火自成薪。", "島居莫笑三百里，菜把活它千萬人。", "白浪打天風動地，何曾驚著一微塵。"]'),
('63318af3-5ec6-4e15-9c05-159cefe8a8c1','從丁家洲避風行小港出荻港大江三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','蘆揮麈尾話清秋，柳弄腰支舞綠洲。',64,'全唐诗/poet.song.142000.json','["蘆揮麈尾話清秋，柳弄腰支舞綠洲。", "引得江風顛入骨，戲拋波浪過於樓。", "十程擬作一程快，一日翻成十日留。", "未到大江愁未到，大江到了更添愁。"]'),
('9a85effd-d2c2-4d6e-bb03-d8673edf75df','江天暮景有歎二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','只爭一水是江淮，日暮風高雲不開。',32,'全唐诗/poet.song.142000.json','["只爭一水是江淮，日暮風高雲不開。", "白鷺倦飛波政闊，都從淮上過江來。"]'),
('a19b0ad5-18d5-4ce2-ad7c-38212177aa19','江天暮景有歎二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一鷺南飛道偶然，忽然百百復千千。',32,'全唐诗/poet.song.142000.json','["一鷺南飛道偶然，忽然百百復千千。", "江淮總屬天家管，不肯營巢向北邊。"]'),
('db156cdb-1385-47cd-9e9f-bcfe0d9227ee','江行七日阻風至繁昌舍舟出陸二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','日日江行怖殺儂，逆風惡浪打船篷。',32,'全唐诗/poet.song.142000.json','["日日江行怖殺儂，逆風惡浪打船篷。", "只今判却肩輿去，遮莫掀天浪與風。"]'),
('3552cfb7-19e7-43f7-9556-f482a2404adf','江行七日阻風至繁昌舍舟出陸二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','山行辛苦水行愁，只是詩人薄命休。',32,'全唐诗/poet.song.142000.json','["山行辛苦水行愁，只是詩人薄命休。", "管取如今遵陸了，雲開風順水東流。"]'),
('c5746d28-2c82-4268-b339-efa011327ab5','過宜福橋','楊萬里','宋','宋诗','song-poetry','','[]','水鄉澤國最輸農，無旱無乾只有豐。',64,'全唐诗/poet.song.142000.json','["水鄉澤國最輸農，無旱無乾只有豐。", "碧豆密爭桑蔭底，綠荷雜出稻花中。", "是田是沼渾難辨，何地何村不一同。", "若遣明年無種子，却愁閑殺雨和風。"]'),
('ae8094e7-eaf5-4c2f-a1f1-c53778e58549','過若山坊進退格','楊萬里','宋','宋诗','song-poetry','','[]','綠漲空中幄，黄鋪地上雲。',48,'全唐诗/poet.song.142000.json','["綠漲空中幄，黄鋪地上雲。", "風條鈎過轎，雨穟沒行人。", "夾路桑千樹，平田稻十分。", "泥行殊不惡，物色逐村新。"]'),
('82975f11-4c9b-4777-ad5a-208265ee40a1','宿峨橋化城寺二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','一溪秋水一橫橋，近路人家却作遥。',32,'全唐诗/poet.song.142000.json','["一溪秋水一橫橋，近路人家却作遥。", "柳遶溪橋荷遶屋，何須更著酒旗招。"]'),
('3608a0f6-1303-461b-8fe6-e20ef8986a11','宿峨橋化城寺二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','忽從平地上高城，乃是圩塘隄上行。',32,'全唐诗/poet.song.142000.json','["忽從平地上高城，乃是圩塘隄上行。", "厚賽柳神銷底物，長腰雲子闊腰菱。"]'),
('5b1d1ab3-6479-41f2-9e26-8df76f81db68','過石硊渡','楊萬里','宋','宋诗','song-poetry','','[]','峨橋小渡十里長，石硊小渡五里强。',112,'全唐诗/poet.song.142000.json','["峨橋小渡十里長，石硊小渡五里强。", "斜風細雨寒蘆裏，下有深潭黑無底。", "渡船劣似紙半張，五里却成一千里。", "中流風作浪如山，前進不得後退難。", "隔溪市井只咫尺，安得飛墮於其間。", "大江風濤堪著力，小渡風濤更無格。", "咫尺性命輕於毛，只恐一毛猶不直。"]'),
('2dd249a9-7b01-4c8f-b259-a307811fcc4d','天絲行','楊萬里','宋','宋诗','song-poetry','','[]','天孫嬾困拋雲機，却倩月姊看殘絲。',144,'全唐诗/poet.song.142000.json','["天孫嬾困拋雲機，却倩月姊看殘絲。", "玉兔偷將乞風伯，和機失却天未知。", "風伯得絲那解織，未嘗躬桑那解惜。", "掀髯一笑戲一吹，散入寒空收不得。", "曉來翠嶺瑩無痕，片雲忽裂落嶺根。", "須臾吹作萬縷銀，乃是天絲不是雲。", "遠山成練不曾捲，近林成紗未經翦。", "坐看斜飛拂面來，分明是絲尋不見。", "元來著面化成水，是水是絲問誰子。"]'),
('8de3cdc1-ee04-47b0-a02f-ce812800ba0f','怪菌歌','楊萬里','宋','宋诗','song-poetry','','[]','雨前無物撩眼界，雨裏道邊出奇怪。',128,'全唐诗/poet.song.142000.json','["雨前無物撩眼界，雨裏道邊出奇怪。", "數莖枯菌破土膏，即時便與人般高。", "撒開圓頂丈來大，一菌可藏人一箇。", "黑如點漆黄如金，第一不怕驟雨淋。", "得雨聲如打荷葉，脚如紫玉排粉節。", "行人一箇掇一枚，無雨即闔有雨開。", "與風最巧能向背，忘却頭上天倚蓋。", "此菌破來還可補，只不堪餐不堪煮。"]'),
('5c690991-f502-42c0-961b-32d2c8940f48','曉晴發蕪湖縣吳波亭二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','八日川塗九雨風，船中出得入泥中。',32,'全唐诗/poet.song.142000.json','["八日川塗九雨風，船中出得入泥中。", "老夫强項誰能那，雨止風休伎自窮。"]'),
('068bc804-e7e9-4de1-a5fd-16e5c25cc0b0','曉晴發蕪湖縣吳波亭二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','雨來初做養禾天，雨久還成害稼年。',32,'全唐诗/poet.song.142000.json','["雨來初做養禾天，雨久還成害稼年。", "今日一晴無準在，金鴉飛出卯牌前。"]'),
('934585c0-0119-4a87-a34b-553a1aa65cf4','晨炊翫鞭亭二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','老賊平欺晉鼎輕，一輪五色夢中驚。',32,'全唐诗/poet.song.142000.json','["老賊平欺晉鼎輕，一輪五色夢中驚。", "寶鞭脫急非無策，何似休將日遶營。"]'),
('5871508e-475d-47c7-bb33-31538f2def2a','晨炊翫鞭亭二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','問著無聲是阿兄，坐看家賊只吞聲。',32,'全唐诗/poet.song.142000.json','["問著無聲是阿兄，坐看家賊只吞聲。", "戮屍大放經綸手，長柄判將錫茂弘。"]'),
('eb414f59-3b6f-4302-86b3-688106302cce','過獺橋湖','楊萬里','宋','宋诗','song-poetry','','[]','圩路抨絃白，圩溝夾柳青。',48,'全唐诗/poet.song.142000.json','["圩路抨絃白，圩溝夾柳青。", "藻明潜撥剌，日暖凍蜻蜓。", "只箇新茅店，分明是水亭。", "行來惟恐盡，覽處不容停。"]'),
('24352ac3-58b9-49a0-bbeb-6e92e60d3488','望謝家青山太白墓二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','阿朓青山自一村，州民歲歲與招魂。',32,'全唐诗/poet.song.142000.json','["阿朓青山自一村，州民歲歲與招魂。", "六朝陵墓今安在，只有詩仙月下墳。"]'),
('b1e153f1-8475-472b-8a6b-614b93543404','望謝家青山太白墓二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','玄暉舊宅略無存，太白來游愛是間。',32,'全唐诗/poet.song.142000.json','["玄暉舊宅略無存，太白來游愛是間。", "占作醉眠床一隻，謝家山是李家山。"]'),
('a689d20e-d2a9-41dd-a791-bb2b9baeb25f','登牛渚蛾眉亭二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','謫仙携妓戲人寰，也被千花妬玉顔。',64,'全唐诗/poet.song.142000.json','["謫仙携妓戲人寰，也被千花妬玉顔。", "半點閑情千古恨，一波秋水兩春山。", "錦袍宮燭雲霄上，白苧烏紗江海間。", "欲寄雙魚招醉魄，月輪捉了蚤言還。"]'),
('e40a5a06-acf4-4524-a974-52da041134e1','登牛渚蛾眉亭二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','山拆江通萬里流，菱花雙照繭眉頭。',64,'全唐诗/poet.song.142000.json','["山拆江通萬里流，菱花雙照繭眉頭。", "掃除却月橫雲樣，別有顰風蹙雨愁。", "明月入波那可捉，長庚伴月本同游。", "君看夜夜青天上，渠與姮家分管秋。"]'),
('61655cc9-6a88-4ad9-bd2e-08e15af42a2f','宿牧牛亭秦太師墳庵','楊萬里','宋','宋诗','song-poetry','','[]','函關只有一穰侯，瀛館寧無再帝丘。',64,'全唐诗/poet.song.142000.json','["函關只有一穰侯，瀛館寧無再帝丘。", "天極八重心未死，台星三點坼方休。", "只看壁後新亭策，恐作栘中屬國羞。", "今日牛羊上丘壠，不知丞相更嗔不。"]'),
('9109da6b-b159-45f5-883b-d176e90ade4f','雁來紅','楊萬里','宋','宋诗','song-poetry','','[]','開了元無雁，看來不是花。',48,'全唐诗/poet.song.142000.json','["開了元無雁，看來不是花。", "若爲黄更紫，乃借葉爲葩。", "藜莧真何擇，雞冠却較差。", "未應犀菊輩，赤脚也容它。"]'),
('f6b1a84d-9e54-4c9e-b0aa-70f1775551fe','早炊新林望見鍾山','楊萬里','宋','宋诗','song-poetry','','[]','辭俸鍾山一月前，如何知我北歸軒。',32,'全唐诗/poet.song.142000.json','["辭俸鍾山一月前，如何知我北歸軒。", "不通姓字殷勤甚，忽到新林野店邊。"]'),
('02ce3012-d215-46b8-ad85-e9e596f35012','兒姪新亭相迎','楊萬里','宋','宋诗','song-poetry','','[]','送客新亭恰放燈，兒曹迎我復新亭。',32,'全唐诗/poet.song.142000.json','["送客新亭恰放燈，兒曹迎我復新亭。", "百年事業何爲者，送往迎來過一生。"]'),
('3b0ec012-1129-41b0-8b37-2fef53dac612','送孫從之司業持節湖南二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','全家先遯却誰知，匹馬西歸也大奇。',64,'全唐诗/poet.song.142000.json','["全家先遯却誰知，匹馬西歸也大奇。", "出晝莫嫌三宿戀，壞麻不待七年遲。", "風生折檻人無古，水遶圜橋士有師。", "六一澹菴喬木在，今秋新長雪霜枝。"]'),
('a01de8bf-0c59-4df2-a21a-b1249cbdbd48','送孫從之司業持節湖南二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','白頭燈火共書林，自少論交老慰心。',64,'全唐诗/poet.song.142000.json','["白頭燈火共書林，自少論交老慰心。", "官職壞人餳裏鴆，忠賢到骨鍛中金。", "朝陽鳴鳳祗今見，夜雨對床何日尋。", "回雁峰前雁回後，紫薇紅藥待渠吟。"]'),
('9ae585d2-fae7-423d-abc9-7abc63fcc0b4','跋天台王仲言乞米詩','楊萬里','宋','宋诗','song-poetry','','[]','改言縮項更長腰，黄獨青精也絕苗。',32,'全唐诗/poet.song.142000.json','["改言縮項更長腰，黄獨青精也絕苗。", "尚有囊中餐玉法，藍田山裏過明朝。"]'),
('6fa0653b-0639-4a94-bc99-b644418b8134','十月朝補種杏花','楊萬里','宋','宋诗','song-poetry','','[]','百株種杏自今春，度夏榮枯不解勻。',32,'全唐诗/poet.song.142000.json','["百株種杏自今春，度夏榮枯不解勻。", "要看補栽新樹子，荼糜紅刺絓頭巾。"]'),
('a83df18d-4074-4295-8e6b-4e0c784019b5','下元日詣會慶節所道場呈余處恭尚書','楊萬里','宋','宋诗','song-poetry','','[]','琳宮朝謁早追趨，漏盡銅壺殺點初。',64,'全唐诗/poet.song.142000.json','["琳宮朝謁早追趨，漏盡銅壺殺點初。", "半縷碧雲橫界月，一規銀鏡裂成梳。", "自拈沉水祈天壽，散作非煙滿玉虛。", "已被新寒欺病骨，柳陰偏隔日光疎。"]'),
('9a21743a-0b84-4a46-93ea-7d84ee4adf36','和余處恭贈方士閻都幹','楊萬里','宋','宋诗','song-poetry','','[]','河出崑崙江出岷，風吹不斷浪花春。',64,'全唐诗/poet.song.142000.json','["河出崑崙江出岷，風吹不斷浪花春。", "但看此水源無竭，底用玄談谷有神。", "老健便爲仙放杖，斧斤祗在襪生塵。", "東家自有仁山訣，方士何曾悟一真。"]'),
('aa2e8c08-e4f8-4475-80e4-a37e6d36d5da','題榠查紅葉','楊萬里','宋','宋诗','song-poetry','','[]','榠查將葉學丹楓，戲與攀條撼晚風。',32,'全唐诗/poet.song.142000.json','["榠查將葉學丹楓，戲與攀條撼晚風。", "一片飛來最奇絕，碧羅袖尾滴猩紅。"]'),
('874d432c-be4a-426f-bbf3-1137da99144c','拾柏子','楊萬里','宋','宋诗','song-poetry','','[]','皺殻傾來紫麥新，中藏瓊米不勝珍。',32,'全唐诗/poet.song.142000.json','["皺殻傾來紫麥新，中藏瓊米不勝珍。", "胡桃松實何曾喫，却嚼秋風柏子仁。"]'),
('1a03ac3e-4167-4e54-bb5a-66f224fd1e31','新酒歌','楊萬里','宋','宋诗','song-poetry','','[]','酸酒齏湯猶可嘗，甜酒蜜汁不可當。',184,'全唐诗/poet.song.142000.json','["酸酒齏湯猶可嘗，甜酒蜜汁不可當。", "老夫出奇釀二缸，生民以來無杜康。", "桂子香，清無底。", "此米不是雲安米，此水祗是建鄴水。", "甕頭一日遶數巡，自候酒熟不倩人。", "松槽葛囊纔上榨，老夫脫帽先嘗新。", "初愁酒带官壺味，一杯徑到天地外。", "忽然玉山倒甕邊，只覺劍鋩割腸裏。", "度撰酒法不是儂，此法來自太虛中。", "酒經一卷偶拾得，一洗萬古甜酒空。", "酒徒若要嘗儂酒，先挽天河濯渠手。", "却來舉杯一中之，換君仙骨君不知。"]'),
('940530e7-86f8-4f00-935f-8219a619ef63','睡覺','楊萬里','宋','宋诗','song-poetry','','[]','小醉如無酒，寒宵似度年。',48,'全唐诗/poet.song.142000.json','["小醉如無酒，寒宵似度年。", "覺來因記夢，醒去不成眠。", "萬事從心下，三更到眼前。", "清愁政無那，一雁叫霜天。"]'),
('61f96e15-9ef4-466b-b9da-3d87937b50e7','菜圃','楊萬里','宋','宋诗','song-poetry','','[]','此圃何其窄，於儂已自華。',48,'全唐诗/poet.song.142000.json','["此圃何其窄，於儂已自華。", "看人澆白菜，分水及黄花。", "霜熟天殊暖，風微旆亦斜。", "笑摩桃竹杖，何日拄還家。"]'),
('23d4bdca-5a45-416e-a646-e5b3cf77a26b','觀化','楊萬里','宋','宋诗','song-poetry','','[]','道是東風巧，西風未減東。',48,'全唐诗/poet.song.142000.json','["道是東風巧，西風未減東。", "菊黄霜換紫，樹碧露揉紅。", "須把乖張眼，偷窺造化工。", "只愁失天巧，不悔得詩窮。"]'),
('393d558e-9c93-425a-8860-b085ea9148c8','冬暖','楊萬里','宋','宋诗','song-poetry','','[]','小春活脫是春時，霜熟風酣日上遲。',64,'全唐诗/poet.song.142000.json','["小春活脫是春時，霜熟風酣日上遲。", "晚蝶頻移獵殘蕊，驚禽衝過倒垂枝。", "暫閑何似長閑好，無事非關了事癡。", "三徑一筇人不見，假山以外菊花知。"]'),
('c93a70d5-451d-4e7d-9f1f-5f7a0fad4536','至後睡覺','楊萬里','宋','宋诗','song-poetry','','[]','匆匆又過一陽生，睡恰濃時夢忽驚。',64,'全唐诗/poet.song.142000.json','["匆匆又過一陽生，睡恰濃時夢忽驚。", "簾幕深沉人四寂，階除點滴雨三更。", "燈摇芒角開成暈，風吸窗櫺過後聲。", "不是寒雞寒似我，如何不肯喚天明。"]'),
('2a4c24d8-fa39-4dac-b4cc-7b150fe1173b','寄題王亞夫檢正不啻足齋','楊萬里','宋','宋诗','song-poetry','','[]','既得隴，復望蜀，未求寶劍先求玉。',208,'全唐诗/poet.song.142000.json','["既得隴，復望蜀，未求寶劍先求玉。", "秦相後車一千轂，唐相胡椒八百斛。", "黄金肘印駕黄鵠，身前佞佛身後福。", "九潦瀉入無底谷，匹似人心猶易足。", "九州四海王同年，三江五湖春水船。", "便應犯斗入月邊，餘事猶堪濟巨川。", "天風吹來墮人寰，水精宮裏作詩仙。", "寄牋排雲叫穹昊，願賜江湖散人號。", "玉皇留渠作豐年，早晚喚歸香案前。", "詩仙掉頭不肯住，田園將蕪夢歸去。", "括蒼山勝道場山，向來結茅非霧間。", "齋房恰則斗來大，中藏世界三千箇。", "門前蠻觸戰方酣，鼻息如雷政高卧。"]'),
('749ab78b-8ede-4a42-ae92-99dbf58efd7f','題王亞夫檢正峴湖堂','楊萬里','宋','宋诗','song-poetry','','[]','西峴山光照舊廬，北湖水色漾新居。',64,'全唐诗/poet.song.142000.json','["西峴山光照舊廬，北湖水色漾新居。", "翠鬟夜欲凌波去，玉鏡晨當掃黛初。", "萬壑千巖雙不借，輕風細浪一夫須。", "來書便當催詩雨，雪後燈前卷復舒。"]'),
('b505d004-3412-4396-96c8-3aeb2e6625ca','壬子正月四日後圃行散四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','淡日微舒又急收，兜羅綿隔紫燈毬。',32,'全唐诗/poet.song.142000.json','["淡日微舒又急收，兜羅綿隔紫燈毬。", "更將數點無聲雨，不濕人衣却濕頭。"]'),
('87743976-8870-470f-aa43-fd278237716b','壬子正月四日後圃行散四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','勃姑偶下小梅枝，要看渠儂褐錦衣。',32,'全唐诗/poet.song.142000.json','["勃姑偶下小梅枝，要看渠儂褐錦衣。", "柱後藏身教不見，却因不見轉驚飛。"]'),
('d489e707-b900-4b48-a518-33d3e3992d3f','壬子正月四日後圃行散四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','雙鵲營巢浪苦辛，揀條銜折不辭頻。',32,'全唐诗/poet.song.142000.json','["雙鵲營巢浪苦辛，揀條銜折不辭頻。", "舊條老硬新條韌，却向籬根拾落薪。"]'),
('5e4f2fe8-3c6b-41f1-a3c5-65ddbdb24cbb','壬子正月四日後圃行散四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','傳語春光恰好穠，太穠恐怕惱衰翁。',32,'全唐诗/poet.song.142000.json','["傳語春光恰好穠，太穠恐怕惱衰翁。", "日華五色無尋處，只在蛛絲來去中。"]'),
('5e348d6f-9f2a-48e8-9ad0-3e1c18c1fda4','雪後霜晴元宵月色特奇','楊萬里','宋','宋诗','song-poetry','','[]','玻璃盆瀉瑠璃水，素娥晚粧欲梳洗。',192,'全唐诗/poet.song.142000.json','["玻璃盆瀉瑠璃水，素娥晚粧欲梳洗。", "報道虛皇築雪宮，一架半間三萬里。", "却嫌廣寒未苦寬，要借新宮作上元。", "先煩玉妃整羽衛，次遣青女褰雲關。", "渠儂舊有七寶藏，封在瓊樓樓頂上。", "中藏腦子萬斛强，輕明片片梅花樣。", "急呼滕六取將來，更和端葉挼作埃。", "狂拋亂撒不停手，滿空碎下真珠胎。", "乾坤立變水精闕，雲衢透冷天街滑。", "姮家催索水霜袍，肌粟衣銖添不徹。", "銀輪凍作一團冰，望舒墮指推不行。", "兔啼蟾泣滴成露，海東飛上金鴉精。"]'),
('1ae6b613-b8a7-4c9b-a873-72fa25c791bd','清曉出郭迓客七里莊二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','却爲迎賓得探春，白門官柳早尖新。',32,'全唐诗/poet.song.142000.json','["却爲迎賓得探春，白門官柳早尖新。", "如何霜瓦纔逢日，半作青瑶半作銀。"]'),
('2982c17b-b4a4-449e-a04f-47b72413600e','清曉出郭迓客七里莊二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','偏得春憐是柳條，腰支別作一般嬌。',32,'全唐诗/poet.song.142000.json','["偏得春憐是柳條，腰支別作一般嬌。", "微風不動渠猶舞，剛道東風轉舞腰。"]'),
('6d9adbfd-8fca-432f-a7f3-fb35322ade0a','探杏二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','紅藍細細糝晴包，紫玉森森走膩條。',32,'全唐诗/poet.song.142000.json','["紅藍細細糝晴包，紫玉森森走膩條。", "枯梗折教無一寸，併驅春力奔花梢。"]'),
('05d50aa9-a956-4357-8ea9-d1026db07e93','探杏二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','曾見乾條撼雪飛，一暄爆出萬萸枝。',32,'全唐诗/poet.song.142000.json','["曾見乾條撼雪飛，一暄爆出萬萸枝。", "從今日日須來看，看到紅紅白白時。"]'),
('a8762cbb-ea39-42d7-a5f1-d0c36fd868d7','梅花二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','東風微破野梅心，著骨清香已不禁。',32,'全唐诗/poet.song.142000.json','["東風微破野梅心，著骨清香已不禁。", "綠刺一尖雙莟子，錯書小字带懸針。"]'),
('684c1daf-4d4a-4108-a8c4-4fdfb68163c2','梅花二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','带雪雖奇祗粉粧，酣晴別是好風光。',32,'全唐诗/poet.song.142000.json','["带雪雖奇祗粉粧，酣晴別是好風光。", "却緣白日青天裏，照得花明暖得香。"]'),
('7806dd67-5d40-4b80-a9f3-ae7b8aa91be4','跋汪省幹詩卷二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','向來劉翰有詩聲，近日汪經更得名。',32,'全唐诗/poet.song.142000.json','["向來劉翰有詩聲，近日汪經更得名。", "月在梅花冰在月，與君句子各爭清。"]'),
('e8e745a9-d57d-407d-b72a-80336afbfe18','跋汪省幹詩卷二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','自古詩人太瘦生，可憐辛苦選虛名。',32,'全唐诗/poet.song.142000.json','["自古詩人太瘦生，可憐辛苦選虛名。", "詩家雜壓君知麽，壓盡三公況九卿。"]'),
('e5d6bb8c-789c-41c7-a7de-68481f38f5d0','和謝石湖先生寄二詩韻  其一','楊萬里','宋','宋诗','song-poetry','','[]','一張五色石湖雲，天上吹來墮小軒。',64,'全唐诗/poet.song.142000.json','["一張五色石湖雲，天上吹來墮小軒。", "化作虹橋倚鍾阜，渡將老子到吳門。", "黄鐘路鼓鳴清廟，玉戚金支舞泰尊。", "乃是寄儂詩數紙，却拈瓌怪向誰論。"]'),
('f80fbc05-279f-4424-b1ff-33e93a2af57f','和謝石湖先生寄二詩韻  其二','楊萬里','宋','宋诗','song-poetry','','[]','康鼎才來頓解頤，盧能自笑未經師。',64,'全唐诗/poet.song.142000.json','["康鼎才來頓解頤，盧能自笑未經師。", "分無楓落吳江句，博得池生春草詩。", "木李拋將引瓊玖，詩筒從此走符移。", "蛤蜊龜殻非難辦，只問先生汗漫期。"]'),
('097e8da7-3bef-41e6-add7-7d5b43cc47d4','領客南園二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','南園多日不曾來，領客閑行始此回。',32,'全唐诗/poet.song.142000.json','["南園多日不曾來，領客閑行始此回。", "獨樹小梅開一朶，被它欄住勸三杯。"]'),
('37f6c105-7ca0-49b4-a1be-4dd231bdee9f','領客南園二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','人間俗殺是公筵，最苦沉煙雜燭煙。',32,'全唐诗/poet.song.142000.json','["人間俗殺是公筵，最苦沉煙雜燭煙。", "何似大家行幾步，逢花即飲醉還眠。"]'),
('30f7f747-4971-4bbd-a0a9-1264f42f2212','和余處恭尚書清凉寺勸農','楊萬里','宋','宋诗','song-poetry','','[]','石城諸峰入天半，曾隨騎吹經行遍。',160,'全唐诗/poet.song.142000.json','["石城諸峰入天半，曾隨騎吹經行遍。", "梅花換歲初不驚，驚報行春再出城。", "官甑晨炊雲子玉，兵厨夜壓秦淮綠。", "尚書親餉老農夫，塞道夫須兼獨速。", "勸農文字不怪奇，知道尚書愁我饑。", "有如山農出南溪，老穉隨觀韓退之。", "叟携羣穉穉扶叟，一生祗識茅柴酒。", "尚書賜酒誰得嘗，瓦盆滿引無升斗。", "今年好風來自東，五風十雨堯日同。", "尚書歸去作相公，當寄豐年書一封。"]'),
('ec9ee425-d0f3-4558-aae6-0131883211eb','與次公幼輿二子登伏龜樓','楊萬里','宋','宋诗','song-poetry','','[]','周遭故國是山圍，對境方知此句奇。',32,'全唐诗/poet.song.142000.json','["周遭故國是山圍，對境方知此句奇。", "偶上伏龜樓上望，一環碧玉缺城西。"]'),
('2ef63cfc-e54d-41bc-ae87-ef0ce7b0a626','寒食前一日行部過牛首山七首  其一','楊萬里','宋','宋诗','song-poetry','','[]','嶺花袍紫不知名，澗草茸青取次生。',32,'全唐诗/poet.song.142000.json','["嶺花袍紫不知名，澗草茸青取次生。", "便是常州草蟲本，只無蚱蜢與蜻蜓。"]'),
('8c0487e5-bfa9-45ee-872d-6e565e80c702','寒食前一日行部過牛首山七首  其二','楊萬里','宋','宋诗','song-poetry','','[]','頭上高垂碧玉盆，誰將漂絮尚殘痕。',32,'全唐诗/poet.song.142000.json','["頭上高垂碧玉盆，誰將漂絮尚殘痕。", "青天幸自秋江樣，須惹三絲兩縷雲。"]'),
('ba7e7de3-96c2-4284-95e8-0e2c7dcaa063','寒食前一日行部過牛首山七首  其三','楊萬里','宋','宋诗','song-poetry','','[]','綿山恨骨已寒灰，儘禁厨煙肯更回。',32,'全唐诗/poet.song.142000.json','["綿山恨骨已寒灰，儘禁厨煙肯更回。", "老病不禁餿食冷，杏花餳粥湯將來。"]'),
('7e1e0706-4c4c-4bbc-9702-debe80b34512','寒食前一日行部過牛首山七首  其四','楊萬里','宋','宋诗','song-poetry','','[]','出了長干過了橋，紙錢風裏樹蕭騷。',32,'全唐诗/poet.song.142000.json','["出了長干過了橋，紙錢風裏樹蕭騷。", "若無六代英雄骨，牛首諸山肯爾高。"]'),
('7784264e-4405-405c-a038-faff102cb2da','寒食前一日行部過牛首山七首  其五','楊萬里','宋','宋诗','song-poetry','','[]','單車一節又行春，敢爲觀風惜病身。',32,'全唐诗/poet.song.142000.json','["單車一節又行春，敢爲觀風惜病身。", "只是擔頭無櫑子，枉教喚作踏青人。"]'),
('83cc8450-1a93-45e4-a853-d6605beb0be1','寒食前一日行部過牛首山七首  其六','楊萬里','宋','宋诗','song-poetry','','[]','擣藍作雨兩宵傾，生怕難乾急放晴。',32,'全唐诗/poet.song.142000.json','["擣藍作雨兩宵傾，生怕難乾急放晴。", "一路東皇新曬染，桑黄麥綠小楓青。"]'),
('20167ca1-8c74-496d-b5b0-474b38a03391','寒食前一日行部過牛首山七首  其七','楊萬里','宋','宋诗','song-poetry','','[]','一春今歲兩中和，信道韶華定較多。',32,'全唐诗/poet.song.142000.json','["一春今歲兩中和，信道韶華定較多。", "二月半頭花已盡，脫空日月退還他。"]'),
('c28a6a38-58a1-4069-b4b3-23e931fff550','宿金陵鎮棲隠寺望橫山','楊萬里','宋','宋诗','song-poetry','','[]','再見橫山滴眼新，山曾勸我脫官身。',64,'全唐诗/poet.song.142000.json','["再見橫山滴眼新，山曾勸我脫官身。", "燈籠簫鼓年年社，酒盞鶑花處處人。", "忽憶諸公牡丹會，轉頭五柞去年春。", "野雲墟月空荒寺，兩袖寒風一帽塵。"]'),
('2b9d8b1e-20e1-4996-9e93-0465485acf89','明發棲隠寺','楊萬里','宋','宋诗','song-poetry','','[]','木魚一呼衆僧聚，老夫登車欲前去。',156,'全唐诗/poet.song.142000.json','["木魚一呼衆僧聚，老夫登車欲前去。", "仰頭見天俯見路，明明是晝不是暮。", "如何今晨天地間，咄咄怪事滿眼前。", "將爲是夜著，月輪已沒星都落。", "將謂是晝休，銀河到曉爛不收。", "皎如江練橫天流，中流點綴金沙洲。", "元來海底蚤浴日，雲師閉關不教出。", "羲和揮斧斫雲關，取將一道天光還。", "天光淡青日光白，道是銀漢也則得。", "雲師强很趕不奔，堆作沙洲是碎雲。"]'),
('f78bbeae-817f-47bd-865a-75ed4daac9a0','寒食日晨炊姜家林初程之次日也','楊萬里','宋','宋诗','song-poetry','','[]','百五佳辰匹似無，合教追節却離居。',64,'全唐诗/poet.song.142000.json','["百五佳辰匹似無，合教追節却離居。", "萬家寒食初歸燕，一老春衫政蹇馿。", "耄柳已僧何再髮，孺槐纔爪可遲蔬。", "兒書早問歸程日，不用嗔渠只笑渠。"]'),
('48be9667-6f16-4b39-8cd7-edaad5f76ef2','午憩褚家方清風亭二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','此老忒疎放，與春無怨私。',48,'全唐诗/poet.song.142000.json','["此老忒疎放，與春無怨私。", "何須寒食日，恰是別家時。", "荒店兩三隻，野花千萬枝。", "前山有底恨，也學客間眉。"]'),
('9c4600be-2d29-4e3a-bbab-b0c24ed4fed1','午憩褚家方清風亭二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','莫道迎春好，迎春是送春。',48,'全唐诗/poet.song.142000.json','["莫道迎春好，迎春是送春。", "可憐一條路，知老幾多人。", "坦綠偏宜襪，飄紅併可絪。", "青帘好消息，今日榨頭新。"]'),
('1cd7ede2-d77a-44ab-ade1-a9979ce1b4e6','宿新市徐公店二首  其一','楊萬里','宋','宋诗','song-poetry','','["\u4e8c\u5e74\u7ea7\u4e0b\u518c", "\u6625", "\u5199\u666f", "\u519c\u6751", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u513f\u7ae5"]','籬落疎疎一逕深，樹頭新綠未成陰。',32,'全唐诗/poet.song.142000.json','["籬落疎疎一逕深，樹頭新綠未成陰。", "兒童急走追黄蝶，飛入菜花無處尋。"]'),
('5090d12f-2cc5-42bc-b236-5400d6b068de','宿新市徐公店二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','春光都在柳梢頭，揀折長條插酒樓。',32,'全唐诗/poet.song.142000.json','["春光都在柳梢頭，揀折長條插酒樓。", "便作在家寒食看，村歌社舞更風流。"]'),
('95fe09b0-e05b-4127-af67-a01df0a960fc','風花','楊萬里','宋','宋诗','song-poetry','','[]','海棠桃李雨中空，更著清明兩日風。',64,'全唐诗/poet.song.142000.json','["海棠桃李雨中空，更著清明兩日風。", "風似病癲無藉在，花如中酒不惺鬆。", "身行楚嶠遠更遠，家寄秦淮東復東。", "道是殘紅何足惜，後來併恐沒殘紅。"]'),
('fd4d3ad5-312c-4281-aed9-934d3033011e','曉過葉家橋二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雞唱嗔人睡，鴉啼唁客勞。',48,'全唐诗/poet.song.142000.json','["雞唱嗔人睡，鴉啼唁客勞。", "近山煙外遠，矮竹苣邊高。", "老矣猶長鋏，悠哉未大刀。", "繞圩無雜樹，一色柳新繅。"]'),
('c7b652cd-f999-4fc0-89cb-cb1ff208d2aa','曉過葉家橋二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','圩峻愁今路，山行羨昨朝。',48,'全唐诗/poet.song.142000.json','["圩峻愁今路，山行羨昨朝。", "閉窗深坐轎，合眼過危橋。", "岸近何由到，魂驚半欲銷。", "寄言薛丞相，最穩是輕舠。"]'),
('0bc9508a-c08c-4a0f-9d02-a75f52b54054','過楊二渡三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','春跡無痕可得尋，不將詩眼看春心。',32,'全唐诗/poet.song.142000.json','["春跡無痕可得尋，不將詩眼看春心。", "鶑邊楊柳鷗邊草，一日青來一日深。"]'),
('29d5209e-ad25-49c4-8503-24148005b823','過楊二渡三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','兩日山尋儘野花，今晨水眺始桑麻。',32,'全唐诗/poet.song.142000.json','["兩日山尋儘野花，今晨水眺始桑麻。", "春風嬌得千垂柳，恰限身才箇箇斜。"]'),
('c47f55e1-2647-4fc8-a3f8-dba8a89150ff','過楊二渡三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','柳見風時舞便輕，解將衮遍趁鶑聲。',32,'全唐诗/poet.song.142000.json','["柳見風時舞便輕，解將衮遍趁鶑聲。", "道它誇逞腰肢著，風罷元來倦不勝。"]'),
('603b50ac-58ab-4064-b850-d8389709e893','宿青山市四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','青山業主是玄暉，太白無錢典得伊。',32,'全唐诗/poet.song.142000.json','["青山業主是玄暉，太白無錢典得伊。", "總是詩仙休更訟，兩蓑分釣一魚磯。"]'),
('8fb7de07-7fa3-4b93-8521-248b60017197','宿青山市四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','雲塗霧抹澹葱曨，萬匹霜綃罩玉龍。',32,'全唐诗/poet.song.142000.json','["雲塗霧抹澹葱曨，萬匹霜綃罩玉龍。", "中有雙峰不爭長，諸峰情願長雙峰。"]'),
('7fc46cc0-2015-4a9a-a89d-f013694646da','宿青山市四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','近看青山却朗然，更無半點霧和煙。',32,'全唐诗/poet.song.142000.json','["近看青山却朗然，更無半點霧和煙。", "一峰是石高多少，到得峰頭即到天。"]'),
('15e9f586-7345-4972-bb09-ce1b540987ea','宿青山市四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','市心酒店客來嘗，且酹仙家十二郎。',32,'全唐诗/poet.song.142000.json','["市心酒店客來嘗，且酹仙家十二郎。", "鸚鵡鸕鷀何處覓，只將老瓦當瑶觴。"]'),
('b3b3fd80-c8e5-4fef-aa7c-dff333f55117','題青山市汪家店','楊萬里','宋','宋诗','song-poetry','','[]','小小樓臨短短牆，長春半架動紅香。',32,'全唐诗/poet.song.142000.json','["小小樓臨短短牆，長春半架動紅香。", "楊花知得人孤寂，故故飛來入竹窗。"]'),
('f29d83fb-e254-4559-9854-2e7ba007d3c7','過廣濟圩三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','圩田歲歲鎮逢秋，圩戶家家不識愁。',32,'全唐诗/poet.song.142000.json','["圩田歲歲鎮逢秋，圩戶家家不識愁。", "夾路垂楊一千里，風流國是太平州。"]'),
('4072d5a7-4711-4712-9aea-3a72c4ab05be','過廣濟圩三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','兩渠水夾一堤寬，箇是東皇大御園。',32,'全唐诗/poet.song.142000.json','["兩渠水夾一堤寬，箇是東皇大御園。", "旋插綠楊能幾日，新枝已自不勝繁。"]'),
('b3fa9fc8-cc86-41fc-90f3-11a28062bb79','過廣濟圩三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','桑疇一眼鬰金黄，麥壠千機綠錦坊。',32,'全唐诗/poet.song.142000.json','["桑疇一眼鬰金黄，麥壠千機綠錦坊。", "詩卷且留燈下看，轎中只好看春光。"]'),
('d8fe8073-89d6-49c3-a9b5-1763826c5ed4','清明日午憩黄池鎮','楊萬里','宋','宋诗','song-poetry','','[]','莫笑孤村小市頭，花邊人出浦邊游。',64,'全唐诗/poet.song.142000.json','["莫笑孤村小市頭，花邊人出浦邊游。", "綠楊拂水雙浮鴨，碧草粘天一落鷗。", "嬾困風光酣午睡，陰沉天氣嫁春愁。", "阿誰道是清明節，我對清明喚作秋。"]'),
('38026905-1988-4628-b089-8333f2a4e223','宿橫岡','楊萬里','宋','宋诗','song-poetry','','[]','我豈忘懷一畝居，誰令愛讀數行書。',64,'全唐诗/poet.song.142000.json','["我豈忘懷一畝居，誰令愛讀數行書。", "秋南春北雁相似，柳思花情鶑不如。", "上市魚蝦村店酒，带花菘芥晚春蔬。", "長亭一醉非難事，造物相撩莫管渠。"]'),
('261b39a4-d6b2-4a16-af85-af249e3fb606','夜雨曉發橫岡','楊萬里','宋','宋诗','song-poetry','','[]','醖造通宵雨，殷勤數日風。',48,'全唐诗/poet.song.142000.json','["醖造通宵雨，殷勤數日風。", "加三濃穉綠，第一淡蔫紅。", "潤物初非惠，司春豈有功。", "老農私獨喜，不羨去年豐。"]'),
('1c37c017-9e28-49cb-830a-717fb7a8e7dd','道旁雨中松','楊萬里','宋','宋诗','song-poetry','','[]','莫信秦人五大夫，一生清苦不敷腴。',32,'全唐诗/poet.song.142000.json','["莫信秦人五大夫，一生清苦不敷腴。", "也將青玉琱釵子，一一釵頭綴雨珠。"]'),
('9865e5aa-f04a-4189-bd90-ccac6fb4138a','宿新豐坊詠瓶中牡丹因懷故園二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','客子泥塗正可憐，天香國色一枝鮮。',64,'全唐诗/poet.song.142000.json','["客子泥塗正可憐，天香國色一枝鮮。", "雨中晚斂寒如此，燭底宵暄笑粲然。", "自覺玉容微婉軟，急將翠掌護嬋娟。", "江南也有新豐市，未羨賓王酌聖賢。"]'),
('9964ddd2-e03c-4b1a-bcc0-ee21ca8eef79','宿新豐坊詠瓶中牡丹因懷故園二首  其二','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','天下花王絕世無，儂家移得洛徽蘇。',64,'全唐诗/poet.song.142000.json','["天下花王絕世無，儂家移得洛徽蘇。", "花頭每朶一千葉，親手前春五百株。", "雪白猩紅相映带，嬌黄釅紫更敷腴。", "鄉魂開眼歸將去，飛過長江彭蠡湖。"]'),
('133b8e1f-3a6e-48e1-b070-1f3f84976118','宛陵道中','楊萬里','宋','宋诗','song-poetry','','[]','溪繚雙衣带，橋森百足蟲。',48,'全唐诗/poet.song.142000.json','["溪繚雙衣带，橋森百足蟲。", "傘聲松徑雨，巢影柳塘風。", "犬誤隨行客，牛偏識牧童。", "追程非要緩，路滑試匆匆。"]'),
('6a1fd8bd-17e7-4278-9328-e1d5e9c439b0','題趙昌父山居八詠 竹隠','楊萬里','宋','宋诗','song-poetry','','[]','大隠隠於酒，小隠隠於竹。',24,'全唐诗/poet.song.142000.json','["大隠隠於酒，小隠隠於竹。", "何不呼麴生，來同此君宿。"]'),
('a7221a1f-9554-41f6-b46b-0a15ecb3826e','題趙昌父山居八詠 晏齋','楊萬里','宋','宋诗','song-poetry','','[]','五陵槿梢花，千駟草頭露。',24,'全唐诗/poet.song.142000.json','["五陵槿梢花，千駟草頭露。", "富貴人始傳，屢空今不數。"]'),
('5628d5d3-2235-422d-916a-6958beb46b27','題趙昌父山居八詠 苔竹軒','楊萬里','宋','宋诗','song-poetry','','[]','青士長得瘦，翠兄工買貧。',24,'全唐诗/poet.song.142000.json','["青士長得瘦，翠兄工買貧。", "向來素愛者，已賺一詩人。"]'),
('b8cd20d1-e066-4033-aeb8-8a7067d6803c','題趙昌父山居八詠 兩峰堂','楊萬里','宋','宋诗','song-poetry','','[]','踏得草鞋穿，行得汗脚損。',24,'全唐诗/poet.song.142000.json','["踏得草鞋穿，行得汗脚損。", "却換一枝藤，拄到雙玉笋。"]'),
('759b6748-f3da-4575-b49f-0524a52691e4','題趙昌父山居八詠 已矣軒','楊萬里','宋','宋诗','song-poetry','','[]','蠻觸無休日，菟裘有別天。',24,'全唐诗/poet.song.142000.json','["蠻觸無休日，菟裘有別天。", "撫松非已矣，采菊未悠然。"]'),
('37be7f22-e5ae-4b49-ae17-421d7a34be5f','題趙昌父山居八詠 倚雲亭','楊萬里','宋','宋诗','song-poetry','','[]','俗子令眼白，瑞峰令眼青。',24,'全唐诗/poet.song.142000.json','["俗子令眼白，瑞峰令眼青。", "自移聽雨榻，且上倚雲亭。"]'),
('ecc46d02-60b3-412b-b516-9e2f90e7ca3b','題趙昌父山居八詠 霞牖','楊萬里','宋','宋诗','song-poetry','','[]','夕借月爲燭，晨將霞作簾。',24,'全唐诗/poet.song.142000.json','["夕借月爲燭，晨將霞作簾。", "猶言貧到骨，不悟取傷廉。"]'),
('f8bfc2da-4c57-431b-9855-ea4d24fd3bc8','題趙昌父山居八詠 青氈堂','楊萬里','宋','宋诗','song-poetry','','[]','客來借氈看，笑指一書策。',24,'全唐诗/poet.song.142000.json','["客來借氈看，笑指一書策。", "不管賣不行，且圖偷不得。"]'),
('b450f1e3-79be-4f12-9046-f0115ec38cc7','曉晴發黄杜驛二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','望後月不落，偏於水底明。',48,'全唐诗/poet.song.142000.json','["望後月不落，偏於水底明。", "對懸雙玉鏡，併照一金鉦。", "忽值山都合，渾無路可行。", "多情小花徑，導我度千縈。"]'),
('7d774d33-23e3-4565-9000-4afcfcd44aae','曉晴發黄杜驛二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','巷竹欹將倒，林花濕不飛。',48,'全唐诗/poet.song.142000.json','["巷竹欹將倒，林花濕不飛。", "總將枝上雨，洒入轎間衣。", "晴色猶全嫩，春寒肯便歸。", "祗能欺客子，戶戶閉荆扉。"]'),
('393da8ae-2788-4b59-9803-1d30bf766225','初曉明朗忽然霧起已而日出光景奇怪','楊萬里','宋','宋诗','song-poetry','','[]','明發望遠山，一一粲可數。',204,'全唐诗/poet.song.142000.json','["明發望遠山，一一粲可數。", "幽人萌望心，便被山靈妬。", "逡巡出神通，變化足驚怖。", "初將兜羅綿，擘作霏微絮。", "週遭裹世界，仰視失天宇。", "高懸赤瑛盤，不計丈尺許。", "下照空濛間，紅光貫輕素。", "中有人物影，紛紜競來去。", "亦各有所持，莫辨是何具。", "猶嫌未奇怪，別出奇怪處。", "珠立一路幢，瑶森四山樹。", "橫空金橋梁，拔地玉窣堵。", "駭目方諦觀，捲地急收去。", "恍疑刮眼膜，依舊認山路。", "那知幻與真，不記夢兼寤。", "神遊峨眉山，誑俗笑佛祖。", "笑誑却被誑，佛祖還笑汝。"]'),
('a90e2149-261e-42ca-8c33-205daed43c98','晨炊杜遷市煮笋','楊萬里','宋','宋诗','song-poetry','','[]','金陵竹笋硬如石，石猶有髓笋不及。',80,'全唐诗/poet.song.142000.json','["金陵竹笋硬如石，石猶有髓笋不及。", "杜遷市裏笋如酥，笋味清絕酥不如。", "带雨斸來和籜煮，中含柘漿雜甘露。", "可齏可膾最可羹，繞齒蔌蔌冰雪聲。", "不須呪笋莫成竹，頓頓食笋莫食肉。"]'),
('6363734e-221a-4b70-87b4-5e3ce0a5b6f1','新路店道中','楊萬里','宋','宋诗','song-poetry','','[]','去秋行部慘山容，得似春山意態濃。',64,'全唐诗/poet.song.142000.json','["去秋行部慘山容，得似春山意態濃。", "嫩綠峰當新雨後，亂紅花發爛晴中。", "仙姿玉骨丹青寫，霧鬢風鬟錦綉幪。", "染得筆頭生五色，急將描取入詩筒。"]'),
('ac960205-f697-4dbe-b63f-3de4525b7efa','嘲道旁楓松相倚','楊萬里','宋','宋诗','song-poetry','','[]','雙楓一松相後前，可憐老翁依少年。',72,'全唐诗/poet.song.142000.json','["雙楓一松相後前，可憐老翁依少年。", "少年翡翠新衫子，老翁深衣青布被。", "更看秋風清露時，少年再換輕紅衣。", "莫教一夜霜雪落，少年赤立無衣著，老翁深衣却不惡。"]'),
('31de7e30-3fcf-47fa-b496-cc87af5c958d','雨後田間雜紀五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','稻田滴水價千金，溪澗求分不肯分。',32,'全唐诗/poet.song.142000.json','["稻田滴水價千金，溪澗求分不肯分。", "一雨萬畦都水足，却將傾瀉作溪渾。"]'),
('11064f17-f267-4009-a071-ec814cd5922c','雨後田間雜紀五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','田水高低各鬭鳴，溪流奔放更驩聲。',32,'全唐诗/poet.song.142000.json','["田水高低各鬭鳴，溪流奔放更驩聲。", "小兒倒撚青梅朶，獨立茅簷看客行。"]'),
('4514d1bd-c9ad-4400-a45e-634a24ce3ccf','雨後田間雜紀五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','行到深村麥更深，放低小轎過桑陰。',32,'全唐诗/poet.song.142000.json','["行到深村麥更深，放低小轎過桑陰。", "再三傳語春寒道，好爲農家惜綠針。"]'),
('d59f574f-fcdb-4695-a7cf-701a138621e2','雨後田間雜紀五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','晴路無泥亦未埃，野雲儘薄不全開。',32,'全唐诗/poet.song.142000.json','["晴路無泥亦未埃，野雲儘薄不全開。", "滿山都是長松樹，無數楊花何處來。"]'),
('1fbe07aa-927a-49da-bc40-d46e9188c35d','雨後田間雜紀五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','正是山花最閙時，濃濃淡淡未離披。',32,'全唐诗/poet.song.142000.json','["正是山花最閙時，濃濃淡淡未離披。", "映山紅與昭亭紫，挽住行人贈一枝。"]'),
('d181aa99-b817-4a8a-8212-1b4f7f90e8f6','宿白雲山奉聖禪寺','楊萬里','宋','宋诗','song-poetry','','[]','徑夾長松照地青，眼看高閣與雲平。',64,'全唐诗/poet.song.142000.json','["徑夾長松照地青，眼看高閣與雲平。", "出林殿脊先知寺，滿路花枝未見鶑。", "上到峰頭千嶂合，下臨嶺脚一溪橫。", "山寒入骨冰相似，冰殺人來却道清。"]'),
('be844a69-d755-4b1d-bd4e-e592553014ec','登奉聖寺千佛閣四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','一隻奇峰入眼中，看來隻隻是奇峰。',32,'全唐诗/poet.song.142000.json','["一隻奇峰入眼中，看來隻隻是奇峰。", "好山道是無重數，少說青蒼十萬重。"]'),
('862a2198-7fcf-4e2c-9434-74237ced91c1','登奉聖寺千佛閣四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','遠山細膩近山粗，別處求粗也則無。',32,'全唐诗/poet.song.142000.json','["遠山細膩近山粗，別處求粗也則無。", "更向遠山山外看，教君病眼一雙枯。"]'),
('ad972062-9d57-4546-b117-aa70329fcf29','登奉聖寺千佛閣四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','長誦懸崖置屋牢，此詩此閣晚相遭。',32,'全唐诗/poet.song.142000.json','["長誦懸崖置屋牢，此詩此閣晚相遭。", "閣中未覺高低在，下到山門始是高。"]'),
('d43f92f5-b56d-4e6f-9f7c-ed2bf967c67e','登奉聖寺千佛閣四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','何許飛來雙白鷗，碧山貼出雪花浮。',32,'全唐诗/poet.song.142000.json','["何許飛來雙白鷗，碧山貼出雪花浮。", "倚欄只管移床立，看到雙鷗沒處休。"]'),
('2cb8b745-8e76-4962-8477-6a26a5c47451','過寧國縣','楊萬里','宋','宋诗','song-poetry','','[]','薄日烘雲未作霞，好峰怯冷著輕紗。',64,'全唐诗/poet.song.142000.json','["薄日烘雲未作霞，好峰怯冷著輕紗。", "絕憐山色能隨我，政用花時不在家。", "騎吏那愁千里遠，牡丹各插一枝斜。", "細看文脊空多肉，不似青陽看九華。"]'),
('bd028011-6b83-46db-a98a-4c5b6ec87c00','桑茶坑道中八首  其一','楊萬里','宋','宋诗','song-poetry','','[]','兩邊山束一溪風，盡日行程在井中。',32,'全唐诗/poet.song.142000.json','["兩邊山束一溪風，盡日行程在井中。", "猶喜天圍能里許，井中那得箇寬通。"]'),
('155a95ae-8acf-4382-97b8-357c4de20d95','桑茶坑道中八首  其二','楊萬里','宋','宋诗','song-poetry','','[]','田塍莫笑細於椽，便是桑園與菜園。',32,'全唐诗/poet.song.142000.json','["田塍莫笑細於椽，便是桑園與菜園。", "嶺脚置錐留結屋，盡驅柿栗上山顛。"]'),
('ecc56773-f632-4b93-919a-4ebe9fceb58e','桑茶坑道中八首  其三','楊萬里','宋','宋诗','song-poetry','','[]','沙鷗數箇點山腰，一足如鉤一足翹。',32,'全唐诗/poet.song.142000.json','["沙鷗數箇點山腰，一足如鉤一足翹。", "乃是山農墾斜崦，倚鉏無力政無聊。"]'),
('3573af7a-5acd-43b0-94c2-449655fc58d3','桑茶坑道中八首  其四','楊萬里','宋','宋诗','song-poetry','','[]','下山入屋上山鉏，圖得生涯總近居。',32,'全唐诗/poet.song.142000.json','["下山入屋上山鉏，圖得生涯總近居。", "桑眼未開先著椹，麥胎纔茁便生鬚。"]'),
('3839e177-9169-4086-b5b4-d34b373ae76c','桑茶坑道中八首  其五','楊萬里','宋','宋诗','song-poetry','','[]','秧疇夾岸隔深溪，東水何緣到得西。',32,'全唐诗/poet.song.142000.json','["秧疇夾岸隔深溪，東水何緣到得西。", "溪面祗銷橫一枧，水從空裏過如飛。"]'),
('d122f061-7098-4383-b821-00d91ee70f5f','桑茶坑道中八首  其六','楊萬里','宋','宋诗','song-poetry','','[]','蠶麰今歲十分强，催得農家日夜忙。',32,'全唐诗/poet.song.142000.json','["蠶麰今歲十分强，催得農家日夜忙。", "已縛桁竿等新麥，更將丫木撐欹桑。"]'),
('e72e3b56-c46d-4d1b-a227-bdf611fdac2c','桑茶坑道中八首  其七','楊萬里','宋','宋诗','song-poetry','','["\u6625\u5929", "\u5199\u666f", "\u513f\u7ae5", "\u751f\u6d3b"]','晴明風日雨乾時，草滿花隄水滿溪。',32,'全唐诗/poet.song.142000.json','["晴明風日雨乾時，草滿花隄水滿溪。", "童子柳陰眠正著，一牛喫過柳陰西。"]'),
('0c854d57-6f79-4258-af70-767d0e39e0e4','桑茶坑道中八首  其八','楊萬里','宋','宋诗','song-poetry','','[]','山根一徑抱溪斜，片地纔寬便數家。',32,'全唐诗/poet.song.142000.json','["山根一徑抱溪斜，片地纔寬便數家。", "漫插漫成堤上柳，半開半落路旁花。"]'),
('02a11e5d-c999-4028-a89e-cf8380c3ad36','明發周村彎','楊萬里','宋','宋诗','song-poetry','','[]','不住寬鄉住甕門，那知世上有乾坤。',64,'全唐诗/poet.song.142000.json','["不住寬鄉住甕門，那知世上有乾坤。", "環將峻嶺包深谷，圍出餘天與別村。", "茅屋相挨無著處，花溪百摺不教奔。", "江淮地迥寒無價，宣歙山寒更莫論。"]'),
('f1156a22-ba83-4c12-82c5-144c09a17829','過主嶺','楊萬里','宋','宋诗','song-poetry','','[]','昨日山行尚有村，今朝嶺塞更無門。',64,'全唐诗/poet.song.142000.json','["昨日山行尚有村，今朝嶺塞更無門。", "仰攀苔磴上絕頂，却倒籃輿下峻巒。", "身覺去天纔寸許，岸臨無地不堪看。", "前頭尚有芙蓉在，此嶺難登未是難。"]'),
('19d29b81-f0e5-4358-b8b2-3f3d0dbfd379','過胡駱坑二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','說盡山寒未識寒，此間寒不是人間。',64,'全唐诗/poet.song.142000.json','["說盡山寒未識寒，此間寒不是人間。", "巖崖泉凍琉璃澗，冰雪雲封翡翠山。", "一擔衣裳都著盡，兩邊窗子更深關。", "聳肩縮頸仍呵手，無策能溫兩脚頑。"]'),
('76a892da-568b-4b49-9672-8012e91c08ba','過胡駱坑二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','已被山寒病老身，車徒溪涉更艱勤。',64,'全唐诗/poet.song.142000.json','["已被山寒病老身，車徒溪涉更艱勤。", "霧皆成點元非雨，日出多時未脫雲。", "猿鳥一聲人不見，松杉四塞徑無痕。", "十分晴暖儂何福，肯借曦光三五分。"]'),
('7e3402aa-b7b9-461f-973d-2fa9f89b11c1','安樂廟頭','楊萬里','宋','宋诗','song-poetry','','[]','誰遣詩家酷愛山，愛山說得口瀾翻。',64,'全唐诗/poet.song.142000.json','["誰遣詩家酷愛山，愛山說得口瀾翻。", "千峰萬嶺爭投奔，一陟三休却倦煩。", "堆案滿前何處著，枯腸飽後豈能餐。", "殘嵐剩翠渾無用，包寄金陵同社看。"]'),
('0d1f026d-e642-417a-b781-137f78277760','未至安樂坊隔林望見霜鏗嶺兩峰特奇','楊萬里','宋','宋诗','song-poetry','','[]','天知老子厭凡山，別放潜瓌伏寶看。',64,'全唐诗/poet.song.142000.json','["天知老子厭凡山，別放潜瓌伏寶看。", "一行橫林遮嶺脚，兩峰如笋出雲端。", "舉頭瞥見還驚遯，到骨清奇特地寒。", "彼此相遭有緣法，悔將嗔喜觸巑岏。"]'),
('84c10172-269d-4573-8d72-e9ffc25af533','安樂坊牧童','楊萬里','宋','宋诗','song-poetry','','[]','前兒牽牛渡溪水，後兒騎牛回問事。',80,'全唐诗/poet.song.142000.json','["前兒牽牛渡溪水，後兒騎牛回問事。", "一兒吹笛笠簪花，一牛載兒行引子。", "春溪嫩水清無滓，春洲細草碧無瑕。", "五牛遠去莫管它，隔溪便是羣兒家。", "忽然頭上數點雨，三笠四蓑趕將去。"]'),
('9b223af1-d22b-4f90-bf48-0bc6d63f2f74','宣歙道中','楊萬里','宋','宋诗','song-poetry','','[]','天齊玉立萬孱顔，三日深行紫翠間。',64,'全唐诗/poet.song.142000.json','["天齊玉立萬孱顔，三日深行紫翠間。", "便是昨來千佛閣，望中見此兩州山。", "詩家寒刮少陵骨，宮樣高梳西子鬟。", "祗好遥看莫登覽，今晨登處鬢都斑。"]'),
('b3185c32-e17e-4c85-a65e-1e33c7760d0d','新安江水自績溪發源','楊萬里','宋','宋诗','song-poetry','','[]','金陵江水只鹹腥，敢望新安江水清。',64,'全唐诗/poet.song.142000.json','["金陵江水只鹹腥，敢望新安江水清。", "皺底玻璃還解動，瑩然酃淥却消酲。", "泉從山骨無泥氣，玉漱花汀作珮聲。", "水記茶經都未識，謫仙句裏萬年名。"]'),
('e880f6a1-8ddd-4d16-85d9-b4075965b241','宿黄土龕五更聞子規','楊萬里','宋','宋诗','song-poetry','','[]','通宵不睡睡方奇，夢裏驚聞新子規。',64,'全唐诗/poet.song.142000.json','["通宵不睡睡方奇，夢裏驚聞新子規。", "祗是一聲已腸斷，況當三月落花時。", "不論客子愁無那，便遣家人聽亦悲。", "歸到江西歸始了，江東歸得未爲歸。"]'),
('f79baf91-b2dd-492e-bed0-427cdbdf36f2','明發黄土龕過高路','楊萬里','宋','宋诗','song-poetry','','[]','又過崢嶸兩峽間，也無溪水也無田。',64,'全唐诗/poet.song.142000.json','["又過崢嶸兩峽間，也無溪水也無田。", "嶺雲放脚寒垂地，山麥掀髯翠拂天。", "碧玉屏風吹不倒，青綾步障買無錢。", "詩人富貴非人世，猶自淒涼意惘然。"]'),
('f104bc0e-b31c-43c2-86eb-d4fc63b0b2d7','寄題周元吉左司山居三詠 酣賦亭','楊萬里','宋','宋诗','song-poetry','','[]','詩酒如今誰主盟，須還酣賦老先生。',64,'全唐诗/poet.song.142000.json','["詩酒如今誰主盟，須還酣賦老先生。", "三杯兩盞鶑花底，一斗百篇談笑成。", "太白自翻新樂府，小蠻度入妙歌聲。", "生前身後名兼飲，二事何曾有重輕。"]'),
('ea3d22d2-5380-41a6-a611-04d377d838c6','寄題周元吉左司山居三詠 可止亭','楊萬里','宋','宋诗','song-poetry','','[]','金印龍章屬市朝，清風明月屬漁樵。',64,'全唐诗/poet.song.142000.json','["金印龍章屬市朝，清風明月屬漁樵。", "世皆蠻觸君知止，渠自王公我豈驕。", "真箇歸田何必賦，自家甘隠不緣招。", "老夫三徑都荒了，松菊雖存已半凋。"]'),
('0b96ef59-55e5-4f68-94bf-5aff2c8a75dc','寄題周元吉左司山居三詠 適菴','楊萬里','宋','宋诗','song-poetry','','[]','莫道蓴鱸不近名，儘談鵬鷃未忘情。',64,'全唐诗/poet.song.142000.json','["莫道蓴鱸不近名，儘談鵬鷃未忘情。", "醉中賭得苕溪月，醒後還輸茂苑鶑。", "豈但二豪俱不見，向來三傑亦何成。", "有人來問適菴趣，便是公榮也一觥。"]'),
('eed77a2b-4e01-4770-975c-7e8c1b8170a6','晨炊泉水塘村店無肉只賣笋蕨嘲亭父','楊萬里','宋','宋诗','song-poetry','','[]','屠門深閉底須愁，土銼無煙也莫羞。',64,'全唐诗/poet.song.142000.json','["屠門深閉底須愁，土銼無煙也莫羞。", "笋便落林猶勝肉，蕨纔出土更燒油。", "萬錢下箸今安在，一飯流匙飽即休。", "吾道藜羹元不糝，至今諱殺古陳州。"]'),
('12712a7d-3230-4fe6-9555-8b65f84f6751','高枧石嶺雨中雲氣蔽虧山色隠顯','楊萬里','宋','宋诗','song-poetry','','[]','絕頂仙人富寶熏，水沉山子不論斤。',64,'全唐诗/poet.song.142000.json','["絕頂仙人富寶熏，水沉山子不論斤。", "堆從平地到天半，併作清香一炷焚。", "煙繞翠鬟蒼玉佩，身披白縠素羅裙。", "更將萬斛薔薇露，酒作桑麻萬頃雲。"]'),
('2178475d-8fe2-427e-9d7b-37020c130e4d','詠績溪道中牡丹二種 絲頭粉紅','楊萬里','宋','宋诗','song-poetry','','[]','看盡徽蘇譜與園，牡丹未見粉絲君。',64,'全唐诗/poet.song.142000.json','["看盡徽蘇譜與園，牡丹未見粉絲君。", "春羅淺染醋紅色，玉板蹙成裙摺紋。", "頭重醉餘扶不起，肌香淑處澹仍芬。", "老夫生有栽花癖，客裏相看爲一醺。"]'),
('a756c5d1-9185-4d8d-b92f-3cadf43375b2','詠績溪道中牡丹二種 重臺九心淡紫進退格','楊萬里','宋','宋诗','song-poetry','','[]','紫玉盤盛碎紫綃，碎綃擁出九嬌饒。',64,'全唐诗/poet.song.142000.json','["紫玉盤盛碎紫綃，碎綃擁出九嬌饒。", "却將些子鬰金粉，亂點中央花片梢。", "葉葉鮮明還互照，婷婷風韻不勝妖。", "折來細雨輕寒裏，正是東風拆半包。"]'),
('5c468757-ffa6-41f9-98e2-308e659667e1','宿三里店溪聲聒睡終夕','楊萬里','宋','宋诗','song-poetry','','[]','破驛荒村山路邊，斜風細雨客燈前。',32,'全唐诗/poet.song.142000.json','["破驛荒村山路邊，斜風細雨客燈前。", "子規一夜啼到曉，更待溪聲始不眠。"]'),
('5fb467e2-25bd-4910-acb4-6009669654ff','曉行道旁杜鵑花','楊萬里','宋','宋诗','song-poetry','','[]','泣露啼紅作麽生，開時偏值杜鵑聲。',32,'全唐诗/poet.song.142000.json','["泣露啼紅作麽生，開時偏值杜鵑聲。", "杜鵑口血能多少，不是征人淚滴成。"]'),
('68c23cdb-a083-429e-9293-9b979ce437e4','曉行聞竹雞二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','山行三日厭泥行，幸自今晨得一晴。',32,'全唐诗/poet.song.142000.json','["山行三日厭泥行，幸自今晨得一晴。", "又聽數聲泥滑滑，情知浪語也心驚。"]'),
('bc71e5f1-03a1-4e15-9ae5-5b7df7528fc5','曉行聞竹雞二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一番行路一番愁，還自兒時到白頭。',32,'全唐诗/poet.song.142000.json','["一番行路一番愁，還自兒時到白頭。", "路不喚君君自去，爲誰著急不歸休。"]'),
('62eaa3da-f1a2-4f1c-a62d-dc51d0f9914a','曉過新安江望紫陽山懷朱元晦','楊萬里','宋','宋诗','song-poetry','','[]','紫陽山下紫陽翁，今住閩山第幾峰。',32,'全唐诗/poet.song.142000.json','["紫陽山下紫陽翁，今住閩山第幾峰。", "退院歸來罷行脚，被他强占一江風。"]'),
('cbcf839b-fb37-45f6-adb9-9d4fba3baca4','明發茅田見鷺有感','楊萬里','宋','宋诗','song-poetry','','[]','自歎平生老道塗，不堪泥雨又驅車。',32,'全唐诗/poet.song.142000.json','["自歎平生老道塗，不堪泥雨又驅車。", "鷺鷥第一清高底，拂曉溪中有幹無。"]'),
('6d654175-1c45-4c11-b816-055391374a3d','雨中春山','楊萬里','宋','宋诗','song-poetry','','[]','誰作春山新幛子，尖峰爲筆天爲紙。',80,'全唐诗/poet.song.142000.json','["誰作春山新幛子，尖峰爲筆天爲紙。", "近看點綴八九山，山外遠山三萬里。", "紙痕慘淡遠山昏，上有長松青到雲。", "自嫌松色太青在，旋拈粉筆輕輕蓋。", "須臾粉淡松復青，至竟遠山描不成。"]'),
('2f29d07f-1f35-4726-804a-e7e4f370f691','明發西館晨炊藹岡四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','盤蔬盂飯趁朝饑，爭指枯腸作地基。',32,'全唐诗/poet.song.142000.json','["盤蔬盂飯趁朝饑，爭指枯腸作地基。", "不覺南山新笋蕨，攙先占却未多時。"]'),
('f0595c8a-4062-42a2-87d8-c2473f1b44a9','明發西館晨炊藹岡四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','人家爭住水東西，不是臨溪即背溪。',32,'全唐诗/poet.song.142000.json','["人家爭住水東西，不是臨溪即背溪。", "拶得一家無去處，跨溪結屋更清奇。"]'),
('d900eac3-ab26-44ec-a891-ad13167b7414','明發西館晨炊藹岡四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','也知水碓妙通神，長聽舂聲不見人。',32,'全唐诗/poet.song.142000.json','["也知水碓妙通神，長聽舂聲不見人。", "若要十分無漏逗，莫將戽斗鎮隨身。"]'),
('7e579913-a725-4b1d-a4c8-3b488b00f5fa','明發西館晨炊藹岡四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','何須名苑看春風，一路山花不負儂。',32,'全唐诗/poet.song.142000.json','["何須名苑看春風，一路山花不負儂。", "日日錦江呈錦樣，清溪倒照映山紅。"]'),
('2e0ba080-a9b8-4b8a-9860-9807788451ad','明發祁門悟法寺溪行險絕六首  其一','楊萬里','宋','宋诗','song-poetry','','[]','右緣絕壁左深溪，頭上春霖脚底泥。',32,'全唐诗/poet.song.142000.json','["右緣絕壁左深溪，頭上春霖脚底泥。", "溪裏仰看應落膽，閉窗關轎不教知。"]'),
('fd155628-844c-4e01-bd9b-e46ab4632635','明發祁門悟法寺溪行險絕六首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一派泉從千丈崖，轟霆跳雪瀉將來。',32,'全唐诗/poet.song.142000.json','["一派泉從千丈崖，轟霆跳雪瀉將來。", "無論驚殺行人著，兩岸諸峰震欲摧。"]'),
('01b6c5d2-085a-4091-be79-1cd70ddfbd18','明發祁門悟法寺溪行險絕六首  其三','楊萬里','宋','宋诗','song-poetry','','[]','山不人煙水不橋，溪聲浩浩雨蕭蕭。',32,'全唐诗/poet.song.142000.json','["山不人煙水不橋，溪聲浩浩雨蕭蕭。", "何須雙鷺相溫暖，鷺過還教轉寂寥。"]'),
('ed395527-4d68-4440-b899-90c4b9180bb7','明發祁門悟法寺溪行險絕六首  其四','楊萬里','宋','宋诗','song-poetry','','[]','溪行盡處却穿山，忽有人家併有田。',32,'全唐诗/poet.song.142000.json','["溪行盡處却穿山，忽有人家併有田。", "幸自驚心小寧貼，誤看田水作深川。"]'),
('f2bf7a6d-e509-46b6-96ab-21cce4e6390a','明發祁門悟法寺溪行險絕六首  其五','楊萬里','宋','宋诗','song-poetry','','[]','山行政好又逢溪，況是危峰斗下時。',32,'全唐诗/poet.song.142000.json','["山行政好又逢溪，況是危峰斗下時。", "知與此溪有何隙，遣它不去祗相隨。"]'),
('6f4c0c18-64e5-468d-bf20-e2f4f8b7e0e0','明發祁門悟法寺溪行險絕六首  其六','楊萬里','宋','宋诗','song-poetry','','[]','已是山寒更水寒，酸風苦雨併無端。',32,'全唐诗/poet.song.142000.json','["已是山寒更水寒，酸風苦雨併無端。", "詩人瘦骨無半把，一任殘春料理看。"]'),
('9340a4a9-0c7e-4239-a50e-b3c8bebc8a10','過閶門溪','楊萬里','宋','宋诗','song-poetry','','[]','黟祁二邑水分源，到此同流怒政奔。',64,'全唐诗/poet.song.142000.json','["黟祁二邑水分源，到此同流怒政奔。", "忽值兩山盤作峽，更峨雙石插爲門。", "中通翠浪纔容線，仰看青天細似盆。", "灧澦瞿唐姑未問，祗經此險已銷魂。"]'),
('d9f81348-4616-4ab5-86a0-1235430c07c3','閶門外登溪船五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','步下新船試水初，打頭攬載適逢予。',64,'全唐诗/poet.song.142000.json','["步下新船試水初，打頭攬載適逢予。", "一椽板屋纔經雨，兩面油窗好讀書。", "剩買春風木芍藥，亂篸棐几竹籧篨。", "清溪浮取松亭子，賞徧千山不要馿。"]'),
('6704a419-35e5-4108-b585-c04dd590c7e0','閶門外登溪船五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','上得船來恰對山，一山頃刻變多般。',64,'全唐诗/poet.song.142000.json','["上得船來恰對山，一山頃刻變多般。", "初堆翠被百千摺，忽拔青瑶三兩竿。", "夾岸兒童天上立，數村樓閣電中看。", "平生快意何曾夢，老向閶門下急灘。"]'),
('753cd259-fdf8-4b0d-8501-23e29f7c8819','閶門外登溪船五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','當面峰頭些子雲，坐看吹作雨紛紛。',64,'全唐诗/poet.song.142000.json','["當面峰頭些子雲，坐看吹作雨紛紛。", "朝來山路能愁我，今者溪船正要君。", "遠嶺輕盈橫皺縠，明窗撩亂觸驚蚊。", "猶爭新漲一篙碧，遮莫飄蕭二十分。"]'),
('b324745b-d893-474b-8e03-69ef8ade5a9a','閶門外登溪船五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','選甚天時晴未晴，舟行終是勝山行。',64,'全唐诗/poet.song.142000.json','["選甚天時晴未晴，舟行終是勝山行。", "篷忺雨點斜偏好，枕慣波聲夢不驚。", "幸自車徒小休息，又聞鼓笛閙將迎。", "偶然回首來時路，一夜霜毛一倍生。"]'),
('c9ba5413-1357-4556-8e63-08c4cc3f0527','閶門外登溪船五首  其五','楊萬里','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','無家不住曲溪邊，祗種高山不種田。',64,'全唐诗/poet.song.142000.json','["無家不住曲溪邊，祗種高山不種田。", "絕壁入天天入水，亂篙鳴石石鳴船。", "百灘春浪雪頭過，兩岸林花鏡底眠。", "歸路商量更舟楫，廬山彭蠡好風煙。"]'),
('693d91b2-7aa9-4fdd-a3a0-20de9f1571ae','舟過城門村清曉雨止日出  其一','楊萬里','宋','宋诗','song-poetry','','[]','五日銀絲織一籠，金烏捉取送籠中。',32,'全唐诗/poet.song.142000.json','["五日銀絲織一籠，金烏捉取送籠中。", "知誰放在扶桑樹，祗怪滿溪煙浪紅。"]'),
('99687b9c-4f0b-4301-9163-b4ee9fdf1991','舟過城門村清曉雨止日出  其二','楊萬里','宋','宋诗','song-poetry','','[]','深村可笑是居民，生長深山野水濱。',32,'全唐诗/poet.song.142000.json','["深村可笑是居民，生長深山野水濱。", "總出籬東携穉子，走來岸上看官人。"]'),
('602f1a56-ac87-4b67-ae2a-8f513464e97b','舟過城門村清曉雨止日出  其三','楊萬里','宋','宋诗','song-poetry','','[]','䰒鬆睡起攬詩編，信手繙來誦數篇。',32,'全唐诗/poet.song.142000.json','["䰒鬆睡起攬詩編，信手繙來誦數篇。", "忽有篙聲仍絕叫，隔篷知是上灘船。"]'),
('003afb6d-4371-4f1d-91ed-46065bdc8be1','舟過城門村清曉雨止日出  其四','楊萬里','宋','宋诗','song-poetry','','[]','行人都上半山青，記得前朝傍險行。',32,'全唐诗/poet.song.142000.json','["行人都上半山青，記得前朝傍險行。", "左右回身看不徹，兩邊已失一灘聲。"]'),
('a43bc39c-b9bd-49c4-a7a6-65176c092ffc','舟過城門村清曉雨止日出  其五','楊萬里','宋','宋诗','song-poetry','','[]','地錦花鋪地錦衣，碧茸上織紫花枝。',32,'全唐诗/poet.song.142000.json','["地錦花鋪地錦衣，碧茸上織紫花枝。", "垂楊舞罷鶑停唱，不捲華絪待阿誰。"]'),
('32d68aa8-c05d-4603-b9bd-32d79aaf2b1d','入浮梁界','楊萬里','宋','宋诗','song-poetry','','[]','濕日雲間淡，晴峰雨後鮮。',48,'全唐诗/poet.song.142000.json','["濕日雲間淡，晴峰雨後鮮。", "水吞隄柳膝，麥到野童肩。", "漚漩嬉浮葉，炊煙倒入船。", "順流風更順，只道不雙全。"]'),
('18f4f19a-3781-4914-a03a-612728cc9b9f','小灘三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','溪水無情知有情，落灘告訴不堪聽。',32,'全唐诗/poet.song.142000.json','["溪水無情知有情，落灘告訴不堪聽。", "前波到此方嗚咽，後浪依前作許聲。"]'),
('71b7f822-b264-4be3-92f4-5c029707be95','小灘三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','水到灘頭似語離，自知無復再歸溪。',32,'全唐诗/poet.song.142000.json','["水到灘頭似語離，自知無復再歸溪。", "臨流莫灑離人淚，幸自灘聲未苦悲。"]'),
('abf71058-10da-4c14-a28a-6357201be833','小灘三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','船裏征人政念歸，居人來看却嗟咨。',32,'全唐诗/poet.song.142000.json','["船裏征人政念歸，居人來看却嗟咨。", "居人祗羨征人著，世世安生不自知。"]'),
('63fbaef7-e969-4b77-9148-301eac7d5844','秧疇','楊萬里','宋','宋诗','song-poetry','','[]','田底泥中跡尚深，折花和葉插畦心。',64,'全唐诗/poet.song.142000.json','["田底泥中跡尚深，折花和葉插畦心。", "晚秧初撚金狨線，先種輸它綠玉針。", "雲壟霧疇俱水響，絲風毛雨政春陰。", "莫聽布穀相煎急，且爲提壺强滿斟。"]'),
('c028fa2d-1bc9-4912-8932-a485d02bf410','水中山花影','楊萬里','宋','宋诗','song-poetry','','[]','閉轎那知山色濃，山花影落水田中。',32,'全唐诗/poet.song.142000.json','["閉轎那知山色濃，山花影落水田中。", "水中細數千紅紫，點對山花一一同。"]'),
('af5e5638-bc23-405f-afbc-aef0a5b9ed15','宿樂平縣北十里西塘','楊萬里','宋','宋诗','song-poetry','','[]','破店能無漏，孤燈肯更明。',48,'全唐诗/poet.song.142000.json','["破店能無漏，孤燈肯更明。", "中間通客路，終夜有人聲。", "坐又坐不得，眠來眠未成。", "如何故山友，抵死怨躬耕。"]'),
('2a1e7075-e41e-4dc5-bb32-dc7dfb335b5b','道旁桐花','楊萬里','宋','宋诗','song-poetry','','[]','春色來時物喜初，春光歸日興闌餘。',32,'全唐诗/poet.song.142000.json','["春色來時物喜初，春光歸日興闌餘。", "更無人餞春行色，猶有桐花管領渠。"]'),
('bfed4f90-8637-4b32-bf54-20264d610f9b','過樂平縣','楊萬里','宋','宋诗','song-poetry','','[]','笋蕨都無且則休，菜無半葉也堪羞。',32,'全唐诗/poet.song.142000.json','["笋蕨都無且則休，菜無半葉也堪羞。", "滿城都賣雪花薺，昨日愁人未是愁。"]'),
('d12b09f5-2fd3-4f4b-b990-89b8ea57903e','過翥山渡','楊萬里','宋','宋诗','song-poetry','','[]','千重溪水萬重山，半月深行井底天。',32,'全唐诗/poet.song.142000.json','["千重溪水萬重山，半月深行井底天。", "井外還來天大在，江心一眼四無邊。"]'),
('34e602cd-13fe-4be8-b9c0-eba2f0dac698','過白土嶺望見芙蓉峰七八峰最東一峰特奇里人名爲芙蓉尖云','楊萬里','宋','宋诗','song-poetry','','[]','看山須是高處看，低處看來元不見。',112,'全唐诗/poet.song.142000.json','["看山須是高處看，低處看來元不見。", "君看矮子仰高人，只識長身那識面。", "今晨雨止昇火輪，一光銷盡千山雲。", "千山數日眼中失，今晨頭角都爭出。", "初登峻嶺也心驚，上到絕頂忽眼明。", "天外數枝青玉筆，飛入錦囊寒突兀。", "問來還是芙蓉尖，闊開兩窗高捲簾。"]'),
('e281281c-444b-4fab-a7a5-cf792b55b5b3','田路泥行','楊萬里','宋','宋诗','song-poetry','','[]','路是新泥作，泥逢積雨滂。',48,'全唐诗/poet.song.142000.json','["路是新泥作，泥逢積雨滂。", "如緣大鮎脊，更繞九羊腸。", "前店看殊近，行人覺轉長。", "商量避五嶺，辛苦恰相當。"]'),
('8a19cf61-d9b7-4522-9aad-09daa216ee40','入弋陽界道旁兩石山一曰蘆山絕妙一曰石人峰次焉上有一石起立如人形云','楊萬里','宋','宋诗','song-poetry','','[]','一色將蒼玉，雙堆作假山。',48,'全唐诗/poet.song.142000.json','["一色將蒼玉，雙堆作假山。", "峰巒妙天下，花草半巖間。", "舊瘦天風骨，新晞雨髻鬟。", "何人緣底恨，化石立孱顔。"]'),
('8a16caaf-195f-4319-82b0-a2770def2f52','芙蓉渡酒店前金沙芍藥盛開','楊萬里','宋','宋诗','song-poetry','','[]','山店春光也自妍，芙容渡口數家村。',64,'全唐诗/poet.song.142000.json','["山店春光也自妍，芙容渡口數家村。", "笋輿低過金沙架，籬落疎圍芍藥軒。", "孤客倦游殊寂寞，兩花作意與溫存。", "可憐經眼匆匆去，不折紅香倒綠尊。"]'),
('a9b89d59-9bd5-46d7-ad50-c74e97f7f287','晨炊橫塘橋酒家小窗','楊萬里','宋','宋诗','song-poetry','','[]','饑望炊煙眼欲穿，可人最是一青帘。',64,'全唐诗/poet.song.142000.json','["饑望炊煙眼欲穿，可人最是一青帘。", "雙渠走水穿三店，獨樹欹流蔭兩簷。", "窗扇透明仍挂上，爐香未燼更多添。", "山村祗苦無良醖，嫌殺芳醪似蜜甜。"]'),
('9317f058-016d-4787-94fe-fc7b98b24cd9','午憩馬家店','楊萬里','宋','宋诗','song-poetry','','[]','兩日田間路，泥深惱殺儂。',48,'全唐诗/poet.song.142000.json','["兩日田間路，泥深惱殺儂。", "却從平地上，再入亂山中。", "水送隨行日，窗留退後峰。", "生衣兼草靸，年例試春風。"]'),
('6ed80819-531c-4a51-9e0f-784aa6c8aaf6','過松源晨炊漆公店六首  其一','楊萬里','宋','宋诗','song-poetry','','[]','側塞千山縫也無，上天下井萬崎嶇。',32,'全唐诗/poet.song.142000.json','["側塞千山縫也無，上天下井萬崎嶇。", "昨朝曾過芙蓉渡，尋到溪源一線初。"]'),
('ed04cc19-8b8c-4428-9c20-a9c70a2537f7','過松源晨炊漆公店六首  其二','楊萬里','宋','宋诗','song-poetry','','[]','山北溪聲一路迎，山南溪響送人行。',32,'全唐诗/poet.song.142000.json','["山北溪聲一路迎，山南溪響送人行。", "也知流向金陵去，若過金陵莫寄聲。"]'),
('fc83fd7d-c7d5-4b96-8789-aa94fe726204','過松源晨炊漆公店六首  其三','楊萬里','宋','宋诗','song-poetry','','[]','後山勒水向東馳，却被前山勒向西。',32,'全唐诗/poet.song.142000.json','["後山勒水向東馳，却被前山勒向西。", "道是水柔無性氣，急聲聲怒慢聲悲。"]'),
('366dbd80-da29-49bb-846e-be62b9888c0b','過松源晨炊漆公店六首  其四','楊萬里','宋','宋诗','song-poetry','','[]','日高谷底始微暄，嵐翠依然透骨寒。',32,'全唐诗/poet.song.142000.json','["日高谷底始微暄，嵐翠依然透骨寒。", "說與行人忙底事，金雞聲裏促銀鞍。"]'),
('259b8675-b648-44c4-a056-987af47789f7','過松源晨炊漆公店六首  其五','楊萬里','宋','宋诗','song-poetry','','[]','莫言下嶺便無難，賺得行人錯喜懽。',32,'全唐诗/poet.song.142000.json','["莫言下嶺便無難，賺得行人錯喜懽。", "政入萬山圍子裏，一山放出一山攔。"]'),
('750d9107-73d2-4062-a8d4-609411fc6b05','過松源晨炊漆公店六首  其六','楊萬里','宋','宋诗','song-poetry','','[]','政是行人腸斷時，子規得得向人啼。',32,'全唐诗/poet.song.142000.json','["政是行人腸斷時，子規得得向人啼。", "若能淚得居人臉，始信春愁總爲伊。"]'),
('0d5eee98-f42e-40b0-a6ba-4fa0f5f19940','獵橋午憩坐睡','楊萬里','宋','宋诗','song-poetry','','[]','路是山腰带，苔爲石面花。',48,'全唐诗/poet.song.142000.json','["路是山腰带，苔爲石面花。", "隔溪聞鳥語，疎竹見人家。", "雨足晴須耐，神勞睡却佳。", "睡魔推不去，知我怯新茶。"]'),
('46f849b1-c507-4564-8bd5-8d319c3f42c0','答徐子材談絕句','楊萬里','宋','宋诗','song-poetry','','[]','受業初參且半山，終須投換晚唐間。',32,'全唐诗/poet.song.142000.json','["受業初參且半山，終須投換晚唐間。", "國風此去無多子，關捩挑來祗等閑。"]'),
('61e828b1-539d-42ad-84c5-5623e0ac8e73','過丫頭巖','楊萬里','宋','宋诗','song-poetry','','[]','告老身心日互催，又將烏帽點黄埃。',32,'全唐诗/poet.song.142000.json','["告老身心日互催，又將烏帽點黄埃。", "丫頭巖下來仍往，四十三年十二回。"]'),
('8f797cfb-3e74-4e33-a4ba-d33dd4f57878','野薔薇','楊萬里','宋','宋诗','song-poetry','','[]','紅殘綠暗已多時，路上山花也則稀。',32,'全唐诗/poet.song.142000.json','["紅殘綠暗已多時，路上山花也則稀。", "藞苴餘春還子細，燕脂濃抹野薔薇。"]'),
('fa916325-941c-4f69-80f3-605fccaac3fb','道旁石榴花','楊萬里','宋','宋诗','song-poetry','','[]','待闕南風欲炷香，東風打併住西堂。',32,'全唐诗/poet.song.142000.json','["待闕南風欲炷香，東風打併住西堂。", "石榴已著乾紅蕾，却問春歸有底忙。"]'),
('666b05b9-c4df-4371-b696-493ea621d8ad','宿月巖','楊萬里','宋','宋诗','song-poetry','','[]','月華無滿亦無虧，天借寒光劣半規。',64,'全唐诗/poet.song.142000.json','["月華無滿亦無虧，天借寒光劣半規。", "長挂冰盤下弦魄，新生丹桂出輪枝。", "偏令南省登金客，爭賦東堂片玉詩。", "傳語姮娥還有妹，請分一箇住幽奇。"]'),
('96c889c0-0f79-4d3b-a44b-2a0af8d3ea01','解舟上饒明暉閣前','楊萬里','宋','宋诗','song-poetry','','[]','玉水風船擘岸開，一帆飛到雨花臺。',32,'全唐诗/poet.song.142000.json','["玉水風船擘岸開，一帆飛到雨花臺。", "思量饒歙山溪路，夢裏征行也莫來。"]'),
('59c6e9e3-f161-4c00-b614-0da5e6b3c026','和王道父山歌二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','東家娘子立花邊，長笑花枝脆不堅。',32,'全唐诗/poet.song.142000.json','["東家娘子立花邊，長笑花枝脆不堅。", "却被花枝笑娘子，嫁期已是蹉春前。"]'),
('43d0af6e-7fb0-4c90-a381-875ef6587dc3','和王道父山歌二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','阿婆辛苦住西鄰，豈愛無家更願貧。',32,'全唐诗/poet.song.142000.json','["阿婆辛苦住西鄰，豈愛無家更願貧。", "秋月春風擔閣了，白頭始嫁不羞人。"]'),
('b1e9f127-8bdb-4a56-8496-cc3768d539b2','雨後泊舟小箬回望靈山','楊萬里','宋','宋诗','song-poetry','','[]','靈山相識已平生，雨後精神見未曾。',64,'全唐诗/poet.song.142000.json','["靈山相識已平生，雨後精神見未曾。", "一朶碧蓮三萬丈，數來花片八千層。", "雲姿霧態排天出，竹杖芒鞋欠我登。", "羨殺峰頭頭上寺，厭山不看是諸僧。"]'),
('2e9a0f9b-428f-4c49-8886-fdef3da73d41','小箬舟中望月','楊萬里','宋','宋诗','song-poetry','','[]','偶於古柳繫春船，雲放千峰月滿川。',64,'全唐诗/poet.song.142000.json','["偶於古柳繫春船，雲放千峰月滿川。", "跳入廣寒宮裏坐，下看碧玉鏡中天。", "斯須萬象都成雪，遮莫三更且未眠。", "歸到金陵入官府，夢中說夢也無緣。"]'),
('efb6a547-2415-4b49-bd3f-394670a7f806','過龜峰','楊萬里','宋','宋诗','song-poetry','','[]','大龜昂首瞻南天，仙人赤脚騎龜肩。',64,'全唐诗/poet.song.142000.json','["大龜昂首瞻南天，仙人赤脚騎龜肩。", "小龜一雙走隨母，指爪穿盡追不前。", "仙人不知卜何事，踏脫綠毛紛滿地。", "老夫也要鑽一鑽，何日故園遂歸計。"]'),
('4ef0c092-c002-4e9e-b4ce-8422342e1408','寄題程元成給事山居三詠 葵心堂','楊萬里','宋','宋诗','song-poetry','','[]','人笑戎葵定自癡，不愁曦景蚤兼遲。',64,'全唐诗/poet.song.142000.json','["人笑戎葵定自癡，不愁曦景蚤兼遲。", "便令隔霧光難到，也則傾心苦爲誰。", "衛足平生非我志，向陽一點只天知。", "話頭試問伯休父，休父丹衷便是葵。"]'),
('cac1f3fa-b42c-4bbf-aa6d-3c084027d1ab','寄題程元成給事山居三詠 秀野堂','楊萬里','宋','宋诗','song-poetry','','[]','梅竹來禽带月栽，牡丹菡萏照江開。',64,'全唐诗/poet.song.142000.json','["梅竹來禽带月栽，牡丹菡萏照江開。", "新安見底正如此，舊雨故人從不來。", "秀色野香供雪飲，名章俊語用雲裁。", "無論獨樂兼同樂，盞面春風翠作堆。"]'),
('41ab18a6-2a95-41e6-bbe6-e1e80a5acc29','寄題程元成給事山居三詠 攬有亭','楊萬里','宋','宋诗','song-poetry','','[]','葵心一岫卓南涯，秀野諸峰走北來。',64,'全唐诗/poet.song.142000.json','["葵心一岫卓南涯，秀野諸峰走北來。", "中起新亭雙奄有，盡驅景物四邊回。", "木居士作煨塵歎，孤竹君真梁棟材。", "知有此亭無此樣，併煩與可灑松煤。"]'),
('e9a59724-13bd-4236-9481-d8409ad8158b','野荼𧃲二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','去歲諸司賞物華，荼糜一會屬儂家。',32,'全唐诗/poet.song.142000.json','["去歲諸司賞物華，荼糜一會屬儂家。", "今年不識荼糜面，却買茅柴對野花。"]'),
('9dc7c16d-5d96-407f-8497-359a3bf227b7','野荼𧃲二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','不識荼糜恨殺人，野花香裏度芳晨。',32,'全唐诗/poet.song.142000.json','["不識荼糜恨殺人，野花香裏度芳晨。", "寄牋爲報東皇道，不理今年一箇春。"]'),
('41309c69-84e3-475a-a463-195b64f951ca','舟過安仁五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','恰則油窗雨點聲，霎時花嶼日華明。',32,'全唐诗/poet.song.142000.json','["恰則油窗雨點聲，霎時花嶼日華明。", "不須覆手仍翻手，可殺春雲沒十成。"]'),
('7c58d67f-3630-4b5a-b5a9-3424ece7bc7e','舟過安仁五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','初受遥山獻畫圖，忽然卷去淡如無。',32,'全唐诗/poet.song.142000.json','["初受遥山獻畫圖，忽然卷去淡如無。", "莫欺老眼猶明在，和霧和煙數得渠。"]'),
('2a63ff16-9798-4ac6-b10e-a66f7802f301','舟過安仁五首  其三','楊萬里','宋','宋诗','song-poetry','','["\u513f\u7ae5", "\u4e94\u5e74\u7ea7\u4e0b\u518c", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u8d5e\u7f8e", "\u884c\u821f"]','一葉漁船兩小童，收篙停棹坐船中。',32,'全唐诗/poet.song.142000.json','["一葉漁船兩小童，收篙停棹坐船中。", "怪生無雨都張傘，不是遮頭是使風。"]'),
('4c925ce2-9e5a-4bfe-83da-499157ec3aea','舟過安仁五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','南風作雨北風休，豈是春雲得自由。',32,'全唐诗/poet.song.142000.json','["南風作雨北風休，豈是春雲得自由。", "只者天時過湖得，長年報道不須愁。"]'),
('ac052b10-4120-444b-96c9-98ea52f78150','舟過安仁五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','渭川千頃在詩胸，不管屠羊肆裏空。',32,'全唐诗/poet.song.142000.json','["渭川千頃在詩胸，不管屠羊肆裏空。", "踏破菜園妨底事，莫教踏到竹園中。"]'),
('4a831f38-cd6f-4cbc-b3f6-65f30ec2e7dc','過鄱陽湖天晴風順','楊萬里','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','湖外廬山已見招，春風好送木蘭橈。',64,'全唐诗/poet.song.142000.json','["湖外廬山已見招，春風好送木蘭橈。", "青天挾日波中浴，白晝繁星地上跳。", "萬頃琉璃吹一葉，半簪霜雪快今朝。", "廬陵歸路從西去，却峭東帆趁落潮。"]'),
('25077d2e-2936-47bc-b132-bfdd88422ee8','舟至湖心望豫章西山雲起風雨驟至','楊萬里','宋','宋诗','song-poetry','','[]','橫洲送我忽俱還，四顧無邊已慘顔。',64,'全唐诗/poet.song.142000.json','["橫洲送我忽俱還，四顧無邊已慘顔。", "雪浪撞天吞几子，礮雲將雨起西山。", "一聲霹靂從空下，萬丈金蛇掣斗間。", "舟子驚呼總無色，平生忠信且今番。"]'),
('e4c77317-e213-4e0c-995a-f5011df5cb17','悶歌行十二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','山行舊路不堪重，及汎湖波又阻風。',32,'全唐诗/poet.song.142000.json','["山行舊路不堪重，及汎湖波又阻風。", "世上舟車無一穩，乾坤可是剩詩翁。"]'),
('a8610139-fe97-488b-9e20-d2bb43af7da5','悶歌行十二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','同列諸公總勸予，歸時切莫過重湖。',32,'全唐诗/poet.song.142000.json','["同列諸公總勸予，歸時切莫過重湖。", "婺源五嶺祁門峽，今是危塗是坦塗。"]'),
('4144bbaa-a2ef-42c0-a54c-2e39458c3b0f','悶歌行十二首  其三','楊萬里','宋','宋诗','song-poetry','','[]','一夜顛風翻却天，簸將白浪到天邊。',32,'全唐诗/poet.song.142000.json','["一夜顛風翻却天，簸將白浪到天邊。", "康郎尚自無根脚，斗大洲頭却繫船。"]'),
('4c43b213-0a3f-4e1a-bd68-ef72b2da2863','悶歌行十二首  其四','楊萬里','宋','宋诗','song-poetry','','[]','問來鄔子到南康，水路都來兩日强。',32,'全唐诗/poet.song.142000.json','["問來鄔子到南康，水路都來兩日强。", "屈指行程誰道遠，如今不敢問都昌。"]'),
('de879923-6d6e-4fdf-8c9f-8416e0660fb5','悶歌行十二首  其五','楊萬里','宋','宋诗','song-poetry','','[]','書策看來已覺煩，詩篇厭了更休論。',32,'全唐诗/poet.song.142000.json','["書策看來已覺煩，詩篇厭了更休論。", "客心未便無安頓，試數油窗雨點痕。"]'),
('7c85b3a3-4485-4d36-b2a2-91a3db7c06b2','悶歌行十二首  其六','楊萬里','宋','宋诗','song-poetry','','[]','一風拋起萬瓊樓，几子康郎總掉頭。',32,'全唐诗/poet.song.142000.json','["一風拋起萬瓊樓，几子康郎總掉頭。", "莫怕浪高洲盡沒，海船下碇併無洲。"]'),
('b2edced9-9e77-4bf8-9739-0fa32aa665c5','悶歌行十二首  其七','楊萬里','宋','宋诗','song-poetry','','[]','新詩哦罷倦來眠，蝴蝶飛游八極邊。',32,'全唐诗/poet.song.142000.json','["新詩哦罷倦來眠，蝴蝶飛游八極邊。", "船外風濤如霹靂，一聲不到睡鄉天。"]'),
('4e8f4681-d95b-4c6a-bdfe-c7909ec752b2','悶歌行十二首  其八','楊萬里','宋','宋诗','song-poetry','','[]','湖心何許有人煙，上下雙天兩點山。',32,'全唐诗/poet.song.142000.json','["湖心何許有人煙，上下雙天兩點山。", "犬吠雞鳴四船裏，旋成水國一家村。"]'),
('040b6df0-8f51-4e49-bba2-36e829bebba9','悶歌行十二首  其九','楊萬里','宋','宋诗','song-poetry','','[]','船上猶餘一日糧，湖心糧盡糴何鄉。',32,'全唐诗/poet.song.142000.json','["船上猶餘一日糧，湖心糧盡糴何鄉。", "仙家辟穀從誰學，明日無炊即秘方。"]'),
('9b07dd13-da12-4dc7-8be0-d9635a03f9c9','悶歌行十二首  其一○','楊萬里','宋','宋诗','song-poetry','','[]','南人方理北歸舟，北地風來便作愁。',32,'全唐诗/poet.song.142000.json','["南人方理北歸舟，北地風來便作愁。", "不道北船等多日，北風不作不成休。"]'),
('d1724b27-b24e-436b-ae45-eb7647c56df2','悶歌行十二首  其一一','楊萬里','宋','宋诗','song-poetry','','[]','大風動地卷波頭，索酒頻添醉未休。',32,'全唐诗/poet.song.142000.json','["大風動地卷波頭，索酒頻添醉未休。", "不判明朝教作病，却圖今夕要忘愁。"]'),
('9a4c9cac-dc74-421b-90ab-47d1d92d7f5f','悶歌行十二首  其一二','楊萬里','宋','宋诗','song-poetry','','[]','風力掀天浪打頭，只須一笑不須愁。',32,'全唐诗/poet.song.142000.json','["風力掀天浪打頭，只須一笑不須愁。", "近看兩日遠三日，氣力窮時會自休。"]'),
('20e80b0e-3a07-4601-97d9-445dad33e774','明發康郎山下亭午過湖入港小泊棠陰砦回望豫章西山慨然感興','楊萬里','宋','宋诗','song-poetry','','[]','大江日東流，我坐自向西。',180,'全唐诗/poet.song.142000.json','["大江日東流，我坐自向西。", "亦復拜新月，不爲學蛾眉。", "恭惟月生處，下臨故園池。", "青松一萬株，牡丹三千枝。", "床下枕北山，簷前漱南溪。", "歲歲身不到，夜夜魂必歸。", "魂歸諒何益，夢覺心自怡。", "魂夢尚如許，而況真歸兮。", "前日至鄔子，西山出湖湄。", "如見鄉人面，一笑相娛嬉。", "旅情得暫欣，鄉愁動長思。", "今朝發康郎，一路能相隨。", "我船趨都昌，回首尚見之。", "偶爾轉港汊，極目煙水迷。", "不得一揖別，悔懊庸可追。"]'),
('110de320-31f9-4079-9842-ba4fd6b16c27','解舟棠陰砦','楊萬里','宋','宋诗','song-poetry','','[]','湖盡有殘渺，情知無博瀾。',120,'全唐诗/poet.song.142000.json','["湖盡有殘渺，情知無博瀾。", "縱眺猶杳空，至竟濟者安。", "回思遇險時，分晷過亦難。", "亦豈有奇畫，死生聽之天。", "安知天矜否，此外無控摶。", "一風動旬月，三日忽自闌。", "未涉浪自怖，既涉焉用驩。", "畏塗已數踐，老命偶再全。", "還家切勿訴，空遺兒女潸。", "亦勿訴同列，同列已預言。"]'),
('d60eb793-2186-4b28-bf32-9bdea0760f27','宿四望山下望廬山','楊萬里','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','過湖見遠岫，澹若橫碧煙。',156,'全唐诗/poet.song.142000.json','["過湖見遠岫，澹若橫碧煙。", "晨蔚動霽暉，春滋涵雨鮮。", "人世那有此，必疑是廬山。", "宿驚恍未定，欲問無暇言。", "落日泊四望，諸峰森在前。", "老夫急親指，舟子答果然。", "平地起屏障，倚空開旗旜。", "潜抱秀潤質，不露奇怪顔。", "乃知名山尊，未與凡嶺班。", "嚴重王公體，雍容德人賢。", "何必出鋒銳，要駭俗子觀。", "坐令我生敬，瞻仰忘憂端。", "更待孤月出，開篷望晴巒。"]'),
('9b698a11-a829-43a1-9f22-0e706820d9fe','明發四望山過都昌縣入彭蠡湖','楊萬里','宋','宋诗','song-poetry','','[]','衆船爭取疾，直赴兩山口。',60,'全唐诗/poet.song.142000.json','["衆船爭取疾，直赴兩山口。", "吾船獨橫趨，甘在衆船後。", "問來風不正，法當走山右。", "不辭用盡力，要與風相就。", "忽然挂孤帆，吾船却先走。"]'),
('07683830-6014-4df0-b0bd-0675b76746e0','宿廬山栖賢寺示如清長老','楊萬里','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u8861\u5c71", "\u957f\u6c5f"]','清風迎衣襟，白雲捧脚底。',156,'全唐诗/poet.song.142000.json','["清風迎衣襟，白雲捧脚底。", "飄然徑上廬山頭，誰道栖賢三十里。", "鄉禪引到獅子峰，旃檀噴出香霧濃。", "此一瓣香爲五老，一笑問我顔猶紅。", "右看南嶽左東海，方丈祝融抹輕黛。", "羣仙遥勸九霞觴，金盤玉箸鯨魚膾。", "急呼清風與白雲，送我更往會列真。", "鄉禪恐我忽飛去，挽著衣襟復留住。", "下視落星石一拳，長江一線湖一涓。", "醉掬玉淵亭下泉，磨作墨汁灑醉篇。"]'),
('e9f4ddc1-c87c-4298-bd08-8671c057ab12','題栖賢寺三峽橋','楊萬里','宋','宋诗','song-poetry','','[]','栖賢與楞伽，初本共一山。',156,'全唐诗/poet.song.142000.json','["栖賢與楞伽，初本共一山。", "古潭宅神龍，睡醒厭久跧。", "是夕起雷雨，震得天地翻。", "此山拆爲兩，一溪斷中間。", "下窺黑無地，上攀青到天。", "從此兩禪寺，路絕不往還。", "祖師見之笑，彈指降神姦。", "問天借橫蜺，搭渡溪兩邊。", "倒傾千崖雪，飛下一玉淵。", "餘怒尚雷吼，聲拔諸峰根。", "我來不能去，輕生倚危欄。", "忽然心爲動，毛骨森以寒。", "上人指斷岸，猶带初拆痕。"]'),
('43db8d95-2cb4-49bb-832f-431f48b67296','徧游廬山示萬杉長老大璉','楊萬里','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','肩輿小斑筠，地志古青冊。',192,'全唐诗/poet.song.142000.json','["肩輿小斑筠，地志古青冊。", "初穿千長松，忽仰萬絕壁。", "觀山不知名，披志失山色。", "行行問不住，一一漸可識。", "何代五老人，登峰化爲石。", "年齡今幾春，齒牙諒無力。", "天賜五玉乳，與渠供朝食。", "淵明醉眠處，石上印耳迹。", "逸少養鵝池，蘚花漬餘墨。", "鶴鳴南天青，龜拜北斗白。", "栖賢緣不淺，月枕借雲席。", "萬杉與開先，弄泉碎珠璧。", "病眸貪窮眺，趼趾怯周歷。", "同游多俊人，淡話半禪伯。", "茲來殆天假，不爾豈人及。", "歸船載曉星，回首兩相憶。"]'),
('a6a96b81-0898-478c-84cf-e30e2ad0e260','題漱玉亭示開先長老師序','楊萬里','宋','宋诗','song-poetry','','[]','山根玉泉仰面飛，飛出山頂却下馳。',64,'全唐诗/poet.song.142000.json','["山根玉泉仰面飛，飛出山頂却下馳。", "自從廬阜瀉雙練，至今銀灣乾兩支。", "雷聲驚裂龍伯眼，雪點濺濕姮娥衣。", "寄言蘇二李十二，莫愁瀑布無新詩。"]'),
('667f269f-bf2d-42ff-8c37-feb77e30627a','又跋東坡太白瀑布詩示開先序禪師','楊萬里','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','東坡太白兩詩翁，詩到廬山筆更鋒。',64,'全唐诗/poet.song.142000.json','["東坡太白兩詩翁，詩到廬山筆更鋒。", "倒挂銀河分一派，擘開玉峽出雙龍。", "天孫織錦機全別，仙子裁雲手自縫。", "界破青山安用洗，涴它瀑布却愁儂。"]'),
('c38b35e5-7b92-4380-9b7f-cb54182c7d87','贈歸宗長老道賢','楊萬里','宋','宋诗','song-poetry','','[]','地下歸宗天下傳，老夫剩欲到雲邊。',32,'全唐诗/poet.song.142000.json','["地下歸宗天下傳，老夫剩欲到雲邊。", "王弘送酒催歸去，且省遠公沽酒錢。"]'),
('529607c5-5d88-4b67-80d8-ff47f239bbd5','過江州岸回望廬山','楊萬里','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山山南刷銅綠，黄金鋸解純蒼玉。',120,'全唐诗/poet.song.142000.json','["廬山山南刷銅綠，黄金鋸解純蒼玉。", "廬山山北潑藍青，碧羅幛裹翡翠屏。", "昨日山南身歷徧，今朝山北舟中看。", "山南是我所部民，山北是我鄉中人。", "部民鄉人何厚薄，有人問我山美惡。", "詫南賒得鄉里嫌，評北又道月旦嚴。", "兩平只在一言內，山如西子破瓜歲，山南是面北是背。"]'),
('f4943bb5-9a67-4351-ba3f-c978b2545b47','大孤山','楊萬里','宋','宋诗','song-poetry','','[]','小姑小年嫁彭郎，大姑不嫁空自孀。',90,'全唐诗/poet.song.142000.json','["小姑小年嫁彭郎，大姑不嫁空自孀。", "小姑有夫似織女，大姑無夫如阿姮。", "廬慈也曾作媒妁，執柯教與五老約。", "東方一老差妙齡，匹似彭郎却老成。", "大姑背面啼更道，豈有老人會年少。", "大姑年來年去今亦老。"]'),
('a39b70e6-baac-4357-94bd-67f78bd66f55','過湖口縣上下石鐘山即東坡所記者是夕宿其下','楊萬里','宋','宋诗','song-poetry','','[]','上鐘山，下鐘山，兩鐘爾大何處懸。',136,'全唐诗/poet.song.142000.json','["上鐘山，下鐘山，兩鐘爾大何處懸。", "滄波作杵天作簴，懸在江湖都會間。", "蜀江西來一萬里，章江南來會於此。", "更著鄱陽與彭蠡，混同四水作一水。", "萬歲千秋撞不止，兩鐘可是難當抵。", "上鐘打得到骨髓，下鐘打穿胸腹底。", "世無坡老辨古器，誰知出自周與魏。", "老夫不能認款識，願聞大聲開病耳，今夜月明正無滓。"]'),
('325c234b-a7e5-4af2-8b24-7fb61f3d9ff7','發楊港渡入交石夾四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','朝雨匆匆霽，春山歷歷嘉。',48,'全唐诗/poet.song.142000.json','["朝雨匆匆霽，春山歷歷嘉。", "老青交幼綠，暗錦出明花。", "漁艇十數隻，雞聲三五家。", "人生須富貴，此輩亦生涯。"]'),
('74b91d86-2eb2-46ac-9268-b5ce2e718029','發楊港渡入交石夾四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','入夾寬中窄，臨流慢處深。',48,'全唐诗/poet.song.142000.json','["入夾寬中窄，臨流慢處深。", "朝陽明衆岫，西崦自多陰。", "脫袴嗔人儉，提壺侑我斟。", "老來除飲外，半點沒春心。"]'),
('9faeb673-ee77-4bdf-8041-b88eaeedd217','發楊港渡入交石夾四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','山斷情相接，江同派暫分。',48,'全唐诗/poet.song.142000.json','["山斷情相接，江同派暫分。", "無風猶細浪，有日却輕雲。", "生熟衣中半，陰晴氣兩熏。", "還家渾欲早，徐棹也堪欣。"]'),
('0383e429-5b65-4aae-a5dd-5c05d84e91d7','發楊港渡入交石夾四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','荻岸何時了，松舟幾日停。',48,'全唐诗/poet.song.142000.json','["荻岸何時了，松舟幾日停。", "波來全蜀白，樹去兩淮青。", "柔樐殊清響，征人自厭聽。", "不知誰子醉，垂手瞰江亭。"]'),
('1dbe6bf9-810b-4e40-9642-d23c8ca1eb2e','過彭澤縣望淵明祠堂','楊萬里','宋','宋诗','song-poetry','','[]','夢裏邯鄲熟，談間栗里親。',48,'全唐诗/poet.song.142000.json','["夢裏邯鄲熟，談間栗里親。", "不聞擔板漢，曾羨采薇人。", "停待容來日，商量尚小貧。", "只欺五斗米，典沒萬金身。"]'),
('a77acd1f-7787-4578-bbf3-80b102859ff3','小孤山','楊萬里','宋','宋诗','song-poetry','','[]','大姑老已醜，小姑少而秀。',60,'全唐诗/poet.song.142000.json','["大姑老已醜，小姑少而秀。", "婷婷獨立水精宮，羅襪生塵飄翠袖。", "彭郎坦腹方醉眠，小姑起舞春風前。", "古來同室無雙美，天壤乃有彭郎子。"]'),
('f63dd3e7-664d-42a4-be9c-f7cb2e37aec5','水螳蜋歌','楊萬里','宋','宋诗','song-poetry','','[]','清晨洗面開篷門，巨螳蜋在水上奔。',80,'全唐诗/poet.song.142000.json','["清晨洗面開篷門，巨螳蜋在水上奔。", "前怒兩臂秋竹竿，後拕一腹春漁船。", "偶然拾得破蛛網，挈取四角沉重淵。", "柳上螳蜋工捕蟬，水上螳蜋工捕鱣。", "捕蟬頓頓得蟬食，捕鱣何曾得魚喫。"]'),
('fef22ae7-24b0-445d-aa50-74fa3f25ec9e','阻風鄉口一日詰朝船進雨作再小泊雷江三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','朔吹憎船進，東暾讓雨行。',48,'全唐诗/poet.song.142000.json','["朔吹憎船進，東暾讓雨行。", "雲移青嶂動，鴉度白雲明。", "淹泊寧吾願，吟哦且客情。", "江邊一株柳，憔悴似餘生。"]'),
('e9bfd116-57ef-47c5-b0cb-bff7ee147622','阻風鄉口一日詰朝船進雨作再小泊雷江三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','幸自無多雨，其如不釅晴。',48,'全唐诗/poet.song.142000.json','["幸自無多雨，其如不釅晴。", "響窗疎復密，暈水滅還生。", "燕競波中影，山凝島外情。", "殘春只五日，留取作江行。"]'),
('aa026a0a-70a8-4f6c-841b-b646db645241','阻風鄉口一日詰朝船進雨作再小泊雷江三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','山已多姿了，雲仍太劣生。',48,'全唐诗/poet.song.142000.json','["山已多姿了，雲仍太劣生。", "濃橫半嶺白，淡掃數峰青。", "照水影顛倒，迎曦時晦明。", "吾泓不孤殺，天賜碧瑶屏。"]'),
('57e5f5ee-b7d5-441e-8b51-751832bf8d81','解舟雷江過東流縣','楊萬里','宋','宋诗','song-poetry','','[]','雲散煙還合，天昏日半烘。',48,'全唐诗/poet.song.142000.json','["雲散煙還合，天昏日半烘。", "青山猶淡白，碧水欲輕紅。", "棹進欣恬浪，公無怨逆風。", "回思五湖裏，敢望大江東。"]'),
('e34d360c-9198-4009-9978-2908fc5ac4ee','阻風泊舒州長風沙二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','苦被淮西市，苛留江表船。',48,'全唐诗/poet.song.142000.json','["苦被淮西市，苛留江表船。", "聞村紅酒賤，看網白魚鮮。", "元是滄浪客，況逢花柳天。", "山川嗔老我，醒眼對風煙。"]'),
('763a4d74-5b97-401a-9225-e9880bce5130','阻風泊舒州長風沙二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','解纜鸞溪北，浮舟雁汊東。',48,'全唐诗/poet.song.142000.json','["解纜鸞溪北，浮舟雁汊東。", "纔逢一日順，却阻四程風。", "萬事乘除裏，千年瞬息中。", "請君明著眼，造物一狙公。"]'),
('0e8c9dec-74e1-49e4-919e-2f1a9a4c2b20','江雨三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雨點飛來水面初，濕銀盤裏走真珠。',32,'全唐诗/poet.song.142000.json','["雨點飛來水面初，濕銀盤裏走真珠。", "龍宮可是忙收拾，萬斛齊傾半霎無。"]'),
('a3ed665d-6257-455d-87ae-8979825589d2','江雨三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','雨裏油窗莫要關，滴來堪翫洒堪聞。',32,'全唐诗/poet.song.142000.json','["雨裏油窗莫要關，滴來堪翫洒堪聞。", "萬珠貢入龍宮了，剩得簷前數顆看。"]'),
('b6b36f89-47ac-42bb-864e-b4781b078e4d','江雨三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','翡翠洲橫綠錦山，真珠汁洗水精磚。',32,'全唐诗/poet.song.142000.json','["翡翠洲橫綠錦山，真珠汁洗水精磚。", "江天萬景無拘管，乞與詩人塞滿船。"]'),
('8e41ea22-91a4-4f6e-a4c6-36bc09dfc372','三月晦日','楊萬里','宋','宋诗','song-poetry','','[]','春光九十更三旬，暗準三旬賺殺人。',32,'全唐诗/poet.song.142000.json','["春光九十更三旬，暗準三旬賺殺人。", "未到曉鐘君莫喜，暮鐘聲裏已無春。"]'),
('cf57c87f-28bd-4308-a7af-a9b7406252f7','過池陽舟中望九華山','楊萬里','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','役役催行邁，匆匆過此春。',48,'全唐诗/poet.song.142000.json','["役役催行邁，匆匆過此春。", "杯翻五湖月，筆掃九華雲。", "不是風煙好，何緣句子新。", "茲游四千里，今日過三分。"]'),
('cf98b827-8dee-4618-bb68-58938cf3f4a4','解舟銅陵望淮山白雲二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','天惜淮山不惜銀，渾銀砌起一長城。',32,'全唐诗/poet.song.142000.json','["天惜淮山不惜銀，渾銀砌起一長城。", "淮山裹在銀城裏，半出諸峰越樣青。"]'),
('76350257-de1e-4f07-b32a-18798d3c1e82','解舟銅陵望淮山白雲二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','銀城遮不盡淮山，許事何緣便達天。',32,'全唐诗/poet.song.142000.json','["銀城遮不盡淮山，許事何緣便達天。", "誰遣詩人强饒舌，和山失却忽蒼然。"]'),
('34761d95-8440-40f3-8649-81ba2fe91550','隔岸','楊萬里','宋','宋诗','song-poetry','','[]','隔岸淮南樹，中流渡北人。',24,'全唐诗/poet.song.142000.json','["隔岸淮南樹，中流渡北人。", "數來無急務，一數一回新。"]'),
('d2bdf5e1-1945-4095-93be-9456567e8173','題東西二梁山三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','二梁雙黛點東西，牛渚看來活底眉。',32,'全唐诗/poet.song.142000.json','["二梁雙黛點東西，牛渚看來活底眉。", "阿敞畫時微失手，一眉高著一眉低。"]'),
('ecc016c6-609b-47db-86aa-5b5fdba739e8','題東西二梁山三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','莫恨當初畫得偏，却因偏處反成妍。',32,'全唐诗/poet.song.142000.json','["莫恨當初畫得偏，却因偏處反成妍。", "喜來舒展愁來蹙，各樣嬌饒更可憐。"]'),
('6e4e589d-1eef-44c9-b796-c8e88716474b','題東西二梁山三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','傳道臨春昔麗華，不從陳帝入隋家。',32,'全唐诗/poet.song.142000.json','["傳道臨春昔麗華，不從陳帝入隋家。", "獨將亡國千年恨，留下雙顰寄岸花。"]'),
('f452202b-109c-4d9b-b139-c7e4e5008e71','舟過凌歊臺望見謝家青山','楊萬里','宋','宋诗','song-poetry','','[]','南風久別忽言還，又苦河流九曲灣。',32,'全唐诗/poet.song.142000.json','["南風久別忽言還，又苦河流九曲灣。", "若要順風兼順水，柂頭背指謝家山。"]'),
('4c756ae8-28c9-470a-8c29-7f179bc76bde','發慈湖過烈山望見歷陽一带山二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','夢繞天津月再灣，慈湖解纜已開顔。',32,'全唐诗/poet.song.142000.json','["夢繞天津月再灣，慈湖解纜已開顔。", "淮山到眼渾相識，直北青梢是定山。"]'),
('2018589b-4ed7-48db-9f66-8e87a056742f','發慈湖過烈山望見歷陽一带山二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一出還添二百詩，風光投到費推辭。',32,'全唐诗/poet.song.142000.json','["一出還添二百詩，風光投到費推辭。", "江湖物色休吟盡，留取西歸一半題。"]'),
('f291e1b2-95e3-4031-905d-e51b65c4abbb','舟過鵝行口回望和州雞籠山','楊萬里','宋','宋诗','song-poetry','','[]','兩月青山不暫離，入城未見有山時。',32,'全唐诗/poet.song.142000.json','["兩月青山不暫離，入城未見有山時。", "萬峰送我都回去，只有雞籠未肯辭。"]'),
('a6d912df-ca75-469a-bd7d-c03e0a86a14e','讀唐人于濆劉駕詩','楊萬里','宋','宋诗','song-poetry','','[]','劉駕及于濆，死愛作愁語。',132,'全唐诗/poet.song.142000.json','["劉駕及于濆，死愛作愁語。", "未必真許愁，說得乃爾苦。", "一字入人目，蜇出兩睫雨。", "莫教雨入心，一滴一痛楚。", "坐令無事人，吞刃割肺腑。", "我不識二子，偶覽二子句。", "兒曹勸莫讀，讀著恐愁去。", "我云寧有是，試讀亦未遽。", "一篇讀未竟，永慨聲已屢。", "忽覺二子愁，併來遮不住。", "何物與解圍，伯雅煩盡護。"]'),
('b2f1b33f-5a5c-4222-bdac-3438aaaaf4bc','跋常寧縣丞葛齊松子固衡永道中行紀詩卷','楊萬里','宋','宋诗','song-poetry','','[]','宜江風月冉溪雲，總與誠齋是故人。',32,'全唐诗/poet.song.142000.json','["宜江風月冉溪雲，總與誠齋是故人。", "老向煙波詩句裏，一朝雙看兩州春。"]'),
('55631aea-9080-45f1-ac3d-2039ee8e7e9b','跋葛子固題蘇道士江行圖','楊萬里','宋','宋诗','song-poetry','','[]','江行圖上指君山，寄語煙波不用看。',32,'全唐诗/poet.song.142000.json','["江行圖上指君山，寄語煙波不用看。", "蒸水買船歸霅水，全家搬入畫圖間。"]'),
('04c033b0-2f24-4524-bd87-b177654a212c','送丘宗卿帥蜀三首  其一','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','人似隆中漢卧龍，韻如江左晉諸公。',64,'全唐诗/poet.song.142000.json','["人似隆中漢卧龍，韻如江左晉諸公。", "四川全國牙旗底，萬里長江羽扇中。", "玉壘頓清開宿霧，雪山增重起秋風。", "近來廊廟多西帥，出相誰言只在東。"]'),
('704b8ed7-cea2-4a61-a574-f324f1112855','送丘宗卿帥蜀三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','諭蜀宣威百萬兵，不須號令自精明。',64,'全唐诗/poet.song.142000.json','["諭蜀宣威百萬兵，不須號令自精明。", "酒揮勃律天西椀，鼓卧蓬婆雪外城。", "二月海棠傾國色，五更杜宇說鄉情。", "少陵山谷千年恨，不遇丘遲眼爲青。"]'),
('8c793630-4ae8-4f0c-8263-70b54e191af3','送丘宗卿帥蜀三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','蜀人詫蜀不能休，花作江山錦作州。',64,'全唐诗/poet.song.142000.json','["蜀人詫蜀不能休，花作江山錦作州。", "老我無緣更行脚，羨君來歲領遨頭。", "碧雞金馬端誰見，酒肆琴臺訪昔游。", "收入西征詩集裏，憶儂還解寄儂不。"]'),
('d2859ba5-bcf7-4d11-964b-7a141e7b82a6','題曾無疑雲巢','楊萬里','宋','宋诗','song-poetry','','[]','蘭芷溪頭子曾子，日飯蘭花飲溪水。',144,'全唐诗/poet.song.142000.json','["蘭芷溪頭子曾子，日飯蘭花飲溪水。", "猶嫌塵土涴荷衣，移家龍山西復西。", "清晨芒屨上山觜，瞥見寸雲石邊起。", "急追捉得絮一毬，襟包袖裹不放休。", "須臾奔騰觸懷出，散滿晴空那可收。", "雲師却與曾子戲，展爲大幕褰爲帔。", "獨携曾子登雲巢，其上無天下無地。", "忽聞阿香笑一呼，曾子驚顧巢亦無。", "歸來作巢學雲樣，夜夜雲來宿巢上。"]'),
('523cb624-4ceb-4140-a599-480a9b7ea75c','寄題廬山楞伽寺三賢堂呈南康太守曾致虛','楊萬里','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','山房牙籤三萬軸，六丁下取歸羣玉。',96,'全唐诗/poet.song.142000.json','["山房牙籤三萬軸，六丁下取歸羣玉。", "空餘坡老枯木枝，雪骨霜筋插雲屋。", "楞伽老僧懷兩賢，作堂要與祠千年。", "只供清風薦明月，不用秋菊兼寒泉。", "江西社裏曾常伯，李家玉潤蘇家客。", "併遣巫陽招取來，分坐廬山泉上石。"]'),
('bbdb2b05-0b7b-4b65-bc95-7a937c1fd381','自金陵得郡西歸曉發梅根市舟中望九華山進退格','楊萬里','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','山外雲濃白，峰頭日淺紅。',48,'全唐诗/poet.song.142000.json','["山外雲濃白，峰頭日淺紅。", "橫拕一疋絹，直掃九芙蓉。", "奔走來船裏，提携入袖中。", "寄言杜陵老，不用剪吳松。"]'),
('e591e01a-1471-4dbd-a339-5e8b16e322cb','發趙屯得風宿楊林池是日行二百里','楊萬里','宋','宋诗','song-poetry','','[]','動地風來覺地浮，拍天浪起带天流。',64,'全唐诗/poet.song.142000.json','["動地風來覺地浮，拍天浪起带天流。", "舞翻柳樹知何喜，拜殺蘆花未肯休。", "兩岸萬山如走馬，一帆千里送歸舟。", "出籠病鶴孤飛後，回首金籠始欲愁。"]'),
('124a7420-54b0-4e1a-aa1b-0033a6b1cc38','題謝昌國桂山堂','楊萬里','宋','宋诗','song-poetry','','[]','艮齋引袖出明光，歸卧西江一草堂。',64,'全唐诗/poet.song.142000.json','["艮齋引袖出明光，歸卧西江一草堂。", "種滿山中渾是桂，怪來月窟更無香。", "九秋金粟供朝飯，三徑黄花併夕糧。", "履上星辰冠上豸，一時脫却濯滄浪。"]'),
('ffafd2ce-752a-41ed-bede-762c61f8f65f','自金陵西歸至豫章發南浦亭宿黄家渡','楊萬里','宋','宋诗','song-poetry','','[]','過了重湖雪浪堆，章江欲盡淦江來。',32,'全唐诗/poet.song.142000.json','["過了重湖雪浪堆，章江欲盡淦江來。", "到家無此江山景，畫舫行遲不用催。"]'),
('82c94e40-3db6-4dcf-bcd4-72df73ba1147','送劉惠卿二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','活却千人藥一囊，陰功吹作滿城香。',32,'全唐诗/poet.song.142000.json','["活却千人藥一囊，陰功吹作滿城香。", "靈椿丹桂君家有，莫羨燕山竇十郎。"]'),
('e7008ddb-8a6d-4818-89e2-5238dec7927a','送劉惠卿二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','舊病詩狂與酒狂，新來泉石又膏肓。',32,'全唐诗/poet.song.142000.json','["舊病詩狂與酒狂，新來泉石又膏肓。", "不醫則是醫還是，更問無方定有方。"]'),
('cf8bc0b4-9c65-42e6-b926-f8be289ac185','十月四日同子文克信子潜子直材翁子立諸弟訪三十二叔祖於小蓬萊酌酒摘金橘小集戲成長句','楊萬里','宋','宋诗','song-poetry','','[]','誠齋老子不奈靜，偶拄烏藤出苔徑。',288,'全唐诗/poet.song.142000.json','["誠齋老子不奈靜，偶拄烏藤出苔徑。", "獨游無伴却成愁，羣從同行還起興。", "每過一家添一人，須臾保社如煙雲。", "褰裳涉溪溪水淺，著屨度橋橋柱新。", "蓬萊一點出塵外，南溪裹在千花裏。", "芙蓉照波上下紅，琅玕繞屋東西翠。", "槿籬竹戶重復重，雞鳴犬吠青霞中。", "蓬萊老仙出迎客，朱顔綠髮仍方瞳。", "餐菊爲糧露爲醑，染霧作巾雲作屨。", "欣然領客到仙家，行盡蓬萊日未斜。", "更傾仙瓢酌仙酒，酒外瓢邊亦何有。", "偶看小樹雙團欒，碧瑠璃葉黄金丸。", "主人忍喫不忍摘，笑道未霜猶带酸。", "小僮隨我勇過我，不管仙翁惜仙果。", "爭挽風枝揀霜顆，爭獻滿盤來飣坐。", "隔水蓬萊看絕奇，蓬萊看水海如池。", "主人勸客對絕境，不飲令儂怒生癭。", "何如寄下未盡瓢，留待早梅賞疎影。"]'),
('bb8bfefb-e5de-42db-ab1e-5b3eeb8d74e3','水仙盛開留子上弟小酌','楊萬里','宋','宋诗','song-poetry','','[]','手種凌波香，今歲便十斛。',72,'全唐诗/poet.song.142000.json','["手種凌波香，今歲便十斛。", "要知誠齋中，富底水仙國。", "有酒偏欠花，有花恨無客。", "與子對花前，不醉便了得。", "待勸已非真，不勸兩自索。", "安知醉與醒，今夕定何夕。"]'),
('90e0951f-a4e5-46e4-8368-ab32105ce3ea','癸丑正月新開東園','楊萬里','宋','宋诗','song-poetry','','[]','長恨無錢買好園，好園還在屋東邊。',32,'全唐诗/poet.song.142000.json','["長恨無錢買好園，好園還在屋東邊。", "週遭旋闢三三徑，只怕芒鞋却費錢。"]'),
('1d3b7130-29a7-4a07-9f8c-c5f7421749d0','與子上雪中入東園望春','楊萬里','宋','宋诗','song-poetry','','[]','草草東園未整齊，却於看雪最清奇。',32,'全唐诗/poet.song.142000.json','["草草東園未整齊，却於看雪最清奇。", "莫嫌踏濕青鞋子，自有瓊瑶隔路泥。"]'),
('8d21ce05-6145-4bc4-8329-dcb02a65e703','松關','楊萬里','宋','宋诗','song-poetry','','[]','竹林行盡到松關，分付雙松爲把門。',32,'全唐诗/poet.song.142000.json','["竹林行盡到松關，分付雙松爲把門。", "若放俗人來一箇，罰渠老瓦十分盆。"]'),
('ed59b16a-b42f-4469-b1bd-86ae8fcadb99','萬花川谷','楊萬里','宋','宋诗','song-poetry','','[]','無數花枝略說些，萬花兩字即非夸。',32,'全唐诗/poet.song.142000.json','["無數花枝略說些，萬花兩字即非夸。", "東山西畔南溪北，更沒溪山只有花。"]'),
('e70539cf-34de-458c-9e1e-25d92bc71262','度雪臺','楊萬里','宋','宋诗','song-poetry','','[]','二月盡頭三月來，紅紅白白一齊開。',32,'全唐诗/poet.song.142000.json','["二月盡頭三月來，紅紅白白一齊開。", "酴醾正要金沙映，莫道金沙只漫栽。"]'),
('7051986e-ba23-4490-bad6-5fcbadcf88fd','碧瑶洞天','楊萬里','宋','宋诗','song-poetry','','[]','青松萬樹竹千竿，蒼翠中間別一天。',32,'全唐诗/poet.song.142000.json','["青松萬樹竹千竿，蒼翠中間別一天。", "從此洞天三十七，初頭且數碧瑶仙。"]'),
('dd2b65ca-b8f1-4871-8037-214b4bc00fb9','三三徑','楊萬里','宋','宋诗','song-poetry','','[]','三徑初開自蔣卿，再開三徑是淵明。',32,'全唐诗/poet.song.142000.json','["三徑初開自蔣卿，再開三徑是淵明。", "誠齋奄有三三徑，一徑花開一徑行。"]'),
('fa1b663f-5113-4410-8b19-39e5bbe8c036','雪後東園午望','楊萬里','宋','宋诗','song-poetry','','[]','天色輕陰小霽中，晝眠初醒未惺鬆。',64,'全唐诗/poet.song.142000.json','["天色輕陰小霽中，晝眠初醒未惺鬆。", "梅橫破屋無多雪，雲放東山第一峰。", "不道風光虧此老，將何功業答殘冬。", "土羔菜甲鵝兒酒，醉入梅林化作蜂。"]'),
('3d8f3f11-c414-45ae-9724-8079c7a8ca3f','玉盤盂','楊萬里','宋','宋诗','song-poetry','','[]','旁招近侍自江都，兩歲何曾見國姝。',64,'全唐诗/poet.song.142000.json','["旁招近侍自江都，兩歲何曾見國姝。", "看盡滿欄紅芍藥，只消一朶玉盤盂。", "水精淡白非真色，珠璧空明得似無。", "欲比此花無可比，且云冰骨雪肌膚。"]'),
('6100c8ef-47c0-42cb-9f25-271d516ffbb9','泉石軒初秋乘凉小荷池上','楊萬里','宋','宋诗','song-poetry','','[]','芙蕖落片自成船，吹泊高荷傘柄邊。',32,'全唐诗/poet.song.142000.json','["芙蕖落片自成船，吹泊高荷傘柄邊。", "泊了又離離又泊，看它走徧水中天。"]'),
('78781d38-7371-4d69-9941-b49eabee627b','寄朱元晦長句以牛尾貍黄雀冬貓笋伴書','楊萬里','宋','宋诗','song-poetry','','[]','大武尾裔名季貍，目如點漆膚凝脂。',96,'全唐诗/poet.song.142000.json','["大武尾裔名季貍，目如點漆膚凝脂。", "江夏無雙字子羽，九月授衣先著絮。", "何如苗國孤竹君，排霜傲雪高拂雲。", "子孫總角遁歸根，金相玉質芝蘭芬。", "三士脂韋與風節，借箸酒池俱勝絕。", "先生胸次有皂白，一醉不須向人說。"]'),
('a8fd8708-7d2c-449a-95eb-b1ddc9609f84','跋臨川梁譯居士孝德記二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雪裏星奔避亂兵，母先子後赴寒冰。',32,'全唐诗/poet.song.142000.json','["雪裏星奔避亂兵，母先子後赴寒冰。", "祗知判得身俱死，不料還同母再生。"]'),
('51170ede-a701-4c4c-8fc4-4c539248e3d7','跋臨川梁譯居士孝德記二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','祗箇當時發一心，通天通地總渠臨。',32,'全唐诗/poet.song.142000.json','["祗箇當時發一心，通天通地總渠臨。", "芝蘭玉樹今爭秀，豈但一枝生桂林。"]'),
('4295c5e8-dd3b-4336-a7b5-2dd9177841a2','南齋前衆樹披猖紅梅居間不肆因爲翦剔','楊萬里','宋','宋诗','song-poetry','','[]','道是司花定有神，元來造化在詩人。',32,'全唐诗/poet.song.142000.json','["道是司花定有神，元來造化在詩人。", "掃除碧樹無情朶，放出紅梅恣意春。"]'),
('5af35f37-274d-4546-9a48-3a1c7918b386','七字長句敬餞提刑寺丞胡元之持節桂林','楊萬里','宋','宋诗','song-poetry','','[]','江西太守說誰子，只說吉州有新事。',197,'全唐诗/poet.song.142000.json','["江西太守說誰子，只說吉州有新事。", "棘闈照日動碧鱗，粉堞入雲橫爛銀。", "三年八邑邑邑熟，一任千日日日春。", "君不見吉州太守清何似，白鷺江心秋見底。", "除却太倉五升米，不曾遣人來向市。", "四鄰束脩來相看，不將入家將入官。", "清名襲人冰霜寒，隨風一夜入九關。", "帝曰桂林五千里，象犀珠玉生海裏。", "安得使者人人皆如此，金捐於山珠抵水。", "却從吉州奪吾侯，一州奪與三十州。", "梅花一笑迎漢節，桂花八株吹嶺雪。", "使星歸去作台星，跳過郎星與卿月。"]'),
('249fb713-0f85-4872-81c5-24d6877b06cf','答賦永豐宰黄巖老投贈五言古句','楊萬里','宋','宋诗','song-poetry','','[]','吾友蕭東夫，今日陳后山。',108,'全唐诗/poet.song.142000.json','["吾友蕭東夫，今日陳后山。", "道肥詩彌瘦，世忙渠自閑。", "不見逾星終，每思即淒然。", "鄰邑黄永豐，與渠中表間。", "黄語似蕭語，已透最上關。", "道黄不是蕭，蕭乃墮我前。", "佳句鬼所泣，盛名天甚慳。", "詩人只言黠，犯之取饑寒。", "端能不懼者，放君據詩壇。"]'),
('46a5ae9e-f675-43f9-94fb-945c86bfe8f6','甲寅二月十八日牡丹初發','楊萬里','宋','宋诗','song-poetry','','[]','排日上牙牌，記花先後開。',24,'全唐诗/poet.song.142000.json','["排日上牙牌，記花先後開。", "看花不子細，過了却重回。"]'),
('2708becc-7f91-4c06-940a-d38d48148ce0','燕脂樓子','楊萬里','宋','宋诗','song-poetry','','[]','樓子燕脂色，燈前艷更鮮。',24,'全唐诗/poet.song.142000.json','["樓子燕脂色，燈前艷更鮮。", "看花直到曉，今夕不成眠。"]'),
('757512bc-baae-49ac-84cb-59bbbca2517a','賞牡丹','楊萬里','宋','宋诗','song-poetry','','[]','把酒看花繞畫欄，病身只得忍輕寒。',32,'全唐诗/poet.song.142000.json','["把酒看花繞畫欄，病身只得忍輕寒。", "主人半醉花微倦，下却珠簾放牡丹。"]'),
('efc06ad0-3437-47b7-8781-f7b2a9be60e2','上巳日周丞相少保來訪敝廬留詩爲贈和謝','楊萬里','宋','宋诗','song-poetry','','[]','相國來臨處士家，山間草木也光華。',64,'全唐诗/poet.song.142000.json','["相國來臨處士家，山間草木也光華。", "高軒行李能過李，小隊尋花到浣花。", "留贈新詩光奪月，端令老子氣成霞。", "無論藏弆傳詒厥，拈向田夫野老誇。"]'),
('e7468f32-abf6-44d1-b8c2-94f39a32742d','因種酴醾金沙作度雪臺以下臨之酴醾瘁而金沙獨茂','楊萬里','宋','宋诗','song-poetry','','[]','獨種酴醾冷却伊，金沙作伴暖相依。',32,'全唐诗/poet.song.142000.json','["獨種酴醾冷却伊，金沙作伴暖相依。", "酴醾枯了來年補，且看金沙也自奇。"]'),
('42c90c7b-1606-402f-bc14-5137483f31da','東園牆隅雙松可愛栽酴醾金沙以繞其上','楊萬里','宋','宋诗','song-poetry','','[]','雙松樹子碧團欒，紅錦纏頭白錦冠。',32,'全唐诗/poet.song.142000.json','["雙松樹子碧團欒，紅錦纏頭白錦冠。", "儘放花枝過牆去，不妨分與路人看。"]'),
('35fe7960-0dad-4449-9b57-61e1e340c00b','登度雪臺','楊萬里','宋','宋诗','song-poetry','','[]','欲問金沙信，聊登度雪臺。',24,'全唐诗/poet.song.142000.json','["欲問金沙信，聊登度雪臺。", "碧桃良解事，開過架梢來。"]'),
('77d032e9-e3ce-44d6-be6c-bc6a5b89ad30','雨後登度雪臺','楊萬里','宋','宋诗','song-poetry','','[]','三日東園近却賒，東風翦翦雨斜斜。',32,'全唐诗/poet.song.142000.json','["三日東園近却賒，東風翦翦雨斜斜。", "春容雨打風吹盡，猶有金沙最後花。"]'),
('ec76e7f5-250a-4bb0-8dde-f4522e302f08','東園幽步見東山四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','日日花開日日新，問天乞得自由身。',32,'全唐诗/poet.song.142000.json','["日日花開日日新，問天乞得自由身。", "不知白髮蒼顔裏，更看南溪幾箇春。"]'),
('3b894326-a1d3-4d14-ae47-b1144f6aec3f','東園幽步見東山四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','何曾一日不思歸，請看誠齋八集詩。',32,'全唐诗/poet.song.142000.json','["何曾一日不思歸，請看誠齋八集詩。", "到得歸來身已病，是儂歸早是歸遲。"]'),
('8c8fc296-83e6-44d1-97b5-1e978c57f3ae','東園幽步見東山四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','爲愛東園日日來，未曾動脚眼先開。',32,'全唐诗/poet.song.142000.json','["爲愛東園日日來，未曾動脚眼先開。", "南溪頃刻都行徧，更到東山頂上回。"]'),
('d7317e99-d215-4512-9e0c-a4f2a8fd42e5','東園幽步見東山四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','天賜東園食實封，東山加賜在園東。',32,'全唐诗/poet.song.142000.json','["天賜東園食實封，東山加賜在園東。", "東山山色渾無定，陰處青蒼曬處紅。"]'),
('b70b13d6-4dd5-4ae6-97bc-71463b494e14','東園新種桃李結子成陰喜而賦之','楊萬里','宋','宋诗','song-poetry','','[]','桃李今春勝去春，添新換舊却重新。',64,'全唐诗/poet.song.142000.json','["桃李今春勝去春，添新換舊却重新。", "冥搜奇特根窠底，妙簡團欒樹子勻。", "移處带花非差事，登時著子亦娛人。", "坡云十載方成蔭，未解誠齋別有神。"]'),
('ec0848d0-2d5e-412a-ae5c-c3fda96423fa','芍藥宅','楊萬里','宋','宋诗','song-poetry','','[]','何以築花宅，筆直松樹子。',144,'全唐诗/poet.song.142000.json','["何以築花宅，筆直松樹子。", "何以蓋花宅，雪白清江紙。", "紙將碧油透，松作畫棟峙。", "鋪紙便成瓦，瓦色水精似。", "金鴉暖未焰，銀竹響無水。", "汗容漬不泣，晴態嬌非醉。", "盡收香世界，關在閑天地。", "風日幾曾來，蜂蝶獨得至。", "勸春入宅莫歸休，勸花住宅且小留。", "昨日花開開一半，今日花飛飛數片。", "留花不住春竟歸，不如折插瓶中看。"]'),
('9508b23a-9fc6-40e4-95ca-e3d9e8c564d1','爲牡丹去草','楊萬里','宋','宋诗','song-poetry','','[]','手種名花夢亦隨，一年年望好花枝。',32,'全唐诗/poet.song.142000.json','["手種名花夢亦隨，一年年望好花枝。", "爲花去草優饒處，兩袖青苔十指泥。"]'),
('df2acc6a-2680-4488-8c76-3381fa642665','雨後步東園','楊萬里','宋','宋诗','song-poetry','','[]','晴繅金線不勝垂，寒勒青針未放齊。',32,'全唐诗/poet.song.142000.json','["晴繅金線不勝垂，寒勒青針未放齊。", "拄杖能言忽相報，三三徑裏已無泥。"]'),
('d883feff-1cb4-4517-9b5c-5310680b7eaf','初夏即事','楊萬里','宋','宋诗','song-poetry','','[]','旋作東陂已水聲，纔經急雨恰新晴。',64,'全唐诗/poet.song.142000.json','["旋作東陂已水聲，纔經急雨恰新晴。", "提壺醒眼看人醉，布穀催農不自耕。", "一似老夫堪笑死，萬方口業拙謀生。", "嘲紅侮綠成何事，自古詩人沒十成。"]'),
('5cd4e16e-125d-4501-81c1-cbc8dbf15aef','枕上聞子規二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','半世征行怕子規，一聞一歎一霑衣。',32,'全唐诗/poet.song.142000.json','["半世征行怕子規，一聞一歎一霑衣。", "如今聽著渾如夢，我自高眠汝自啼。"]'),
('1243cf8e-5775-47ca-b2af-482ee06a4999','枕上聞子規二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','去年借宅寄生兒，今歲羣兒又學伊。',32,'全唐诗/poet.song.142000.json','["去年借宅寄生兒，今歲羣兒又學伊。", "羞面見它鶑與燕，向人强道不如歸。"]'),
('f826d6c3-a82d-4bd6-8e8f-cd1a2cda40df','趙村','楊萬里','宋','宋诗','song-poetry','','[]','杏花千樹洛陽春，白傅年年愛趙村。',32,'全唐诗/poet.song.142000.json','["杏花千樹洛陽春，白傅年年愛趙村。", "月蕊晴葩風露格，老夫移得在東園。"]'),
('2b40288e-b29b-4646-852f-7dc862564313','有歎','楊萬里','宋','宋诗','song-poetry','','[]','飽喜饑嗔笑殺儂，鳳皇未可笑狙公。',32,'全唐诗/poet.song.142000.json','["飽喜饑嗔笑殺儂，鳳皇未可笑狙公。", "儘逃暮四朝三外，猶在桐花竹實中。"]'),
('c6f237c1-666a-486d-a6d1-4f38796a5954','四月三日登度雪臺感興','楊萬里','宋','宋诗','song-poetry','','[]','高臺喜登眺，登眺觸老情。',120,'全唐诗/poet.song.142000.json','["高臺喜登眺，登眺觸老情。", "入夏又涉三，餘春安得停。", "雨欄漂耄丹，風架舞壯青。", "秧生麥將熟，桑盡繭已成。", "盛衰亦其常，無顇豈有榮。", "古今非千載，一瞬即古今。", "慨然顧八荒，此理誰與評。", "我友諒無益，有益或麴生。", "生雖不能言，其言如震霆。", "但令我懷遣，未問醉與醒。"]'),
('ab7a411c-0da8-4ceb-a4a0-8803e190c9e9','寄陸務觀','楊萬里','宋','宋诗','song-poetry','','[]','君居東浙我江西，鏡裏新添幾縷絲。',64,'全唐诗/poet.song.142000.json','["君居東浙我江西，鏡裏新添幾縷絲。", "花落六回疎信息，月明千里兩相思。", "不應李杜翻鯨海，更羨夔龍集鳳池。", "道是樊川輕薄殺，猶將萬戶比千詩。"]'),
('1d9bc02d-8c6b-4d07-974c-2544fd4df9fe','寄張功父','楊萬里','宋','宋诗','song-poetry','','[]','問訊子張子，詩狂除未除。',48,'全唐诗/poet.song.142000.json','["問訊子張子，詩狂除未除。", "年時一健步，寄我數行書。", "舊矣哦招隠，誰歟誦子虛。", "江湖隔京洛，不是愛相疎。"]'),
('8d6d7995-2aed-406d-a22a-ac57d68dc6d6','清曉行散','楊萬里','宋','宋诗','song-poetry','','[]','清曉東園政好嬉，忽然竚立小遲遲。',32,'全唐诗/poet.song.142000.json','["清曉東園政好嬉，忽然竚立小遲遲。", "爲逢咫尺青松上，無數羣鶑政亂啼。"]'),
('838751d4-98ae-4774-a26e-63998a17b0d5','喜雨','楊萬里','宋','宋诗','song-poetry','','[]','欲知一雨愜羣情，聽取溪流動地聲。',64,'全唐诗/poet.song.142000.json','["欲知一雨愜羣情，聽取溪流動地聲。", "風亂萬疇青錦褥，雲摩千嶂翠瑶屏。", "行人隔水遥相語，立鷺摧枝忽自驚。", "歲歲只愁炊與釀，今愁無甑更無瓶。"]'),
('c527a4d2-9f87-4264-8276-9c13d3d1146e','雨後子文伯莊二弟相訪同游東園','楊萬里','宋','宋诗','song-poetry','','[]','北阮稀相見，東園肯到無。',48,'全唐诗/poet.song.142000.json','["北阮稀相見，東園肯到無。", "鞋留沙跡淺，扇答雨聲疎。", "新長水三尺，倒漂梅一株。", "炊煙起山崦，好箇晚村圖。"]'),
('da19aac1-75ca-4a76-9c2d-4073b77e0dca','嘗桃','楊萬里','宋','宋诗','song-poetry','','[]','金桃兩飣照銀杯，一是栽來一買來。',32,'全唐诗/poet.song.142000.json','["金桃兩飣照銀杯，一是栽來一買來。", "香味比嘗無兩樣，人情畢竟愛親栽。"]'),
('f305775b-b6a7-4541-9cf9-60e82d2a722c','菊夏摘則秋茂朝凉試手','楊萬里','宋','宋诗','song-poetry','','[]','種菊君須莫惜它，摘教秃秃不留些。',32,'全唐诗/poet.song.142000.json','["種菊君須莫惜它，摘教秃秃不留些。", "此花賤相君知麽，從此千千萬萬花。"]'),
('740cb74f-7aca-4cfc-86f4-f7e4d256943d','雲際院小池荷花纔落一葉急承之','楊萬里','宋','宋诗','song-poetry','','[]','欲落荷花先自愁，如何落後免沉浮。',32,'全唐诗/poet.song.142000.json','["欲落荷花先自愁，如何落後免沉浮。", "誰將碧玉圓盤子，和蕊和花一一收。"]'),
('bce88e6e-1c71-4c17-be5c-7997d4a22fc1','六月初四日往雲際院田間雨足喜而賦之二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','高下田疇水鬭鳴，泥深路滑不堪行。',32,'全唐诗/poet.song.142000.json','["高下田疇水鬭鳴，泥深路滑不堪行。", "請君聽取行人語，只箇愁聲是喜聲。"]'),
('b7f113ee-bb7b-4705-856f-792d946945f7','六月初四日往雲際院田間雨足喜而賦之二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','去年今日政迎神，禱雨朝朝禱得晴。',32,'全唐诗/poet.song.142000.json','["去年今日政迎神，禱雨朝朝禱得晴。", "今歲神祠免煎炒，更饒簫鼓賽秋成。"]'),
('5cc27e71-f09d-43ca-a3f2-4cfc369fe47e','題王才臣南山隠居六詠 莊敬日强齋','楊萬里','宋','宋诗','song-poetry','','[]','居人晏猶眠，行子夕未宿。',24,'全唐诗/poet.song.142000.json','["居人晏猶眠，行子夕未宿。", "此心從何生，却道力不足。"]'),
('f9ea3d92-dd19-4e66-a525-191cacfbccc0','題王才臣南山隠居六詠 格齋','楊萬里','宋','宋诗','song-poetry','','[]','讀書輪何知，問羊馬何與。',24,'全唐诗/poet.song.142000.json','["讀書輪何知，問羊馬何與。", "二理仍兩心，終無研究處。"]'),
('3e6f5de8-2b55-4134-aa54-fff444859164','題王才臣南山隠居六詠 南谷','楊萬里','宋','宋诗','song-poetry','','[]','我生本南溪，我長寓南谷。',24,'全唐诗/poet.song.142000.json','["我生本南溪，我長寓南谷。", "是子底無良，奪我谷中菊。"]'),
('69c8ef97-4cac-4dad-913c-8dc673896268','題王才臣南山隠居六詠 竹亭','楊萬里','宋','宋诗','song-poetry','','[]','春亦只如是，冬亦只如是。',24,'全唐诗/poet.song.142000.json','["春亦只如是，冬亦只如是。", "別有一清風，請君參此味。"]'),
('37c5757e-eda0-41fe-a543-f2a3100a888f','題王才臣南山隠居六詠 松庵','楊萬里','宋','宋诗','song-poetry','','[]','與花不同色，與竹元同德。',24,'全唐诗/poet.song.142000.json','["與花不同色，與竹元同德。", "風月偏相尋，携手清涼國。"]'),
('94763c51-472d-41eb-a11e-6711c2fb77d2','題王才臣南山隠居六詠 腴亭','楊萬里','宋','宋诗','song-poetry','','[]','蜀張與蜀花，鄉人相解后。',24,'全唐诗/poet.song.142000.json','["蜀張與蜀花，鄉人相解后。", "人存花更腴，人去花亦瘦。"]'),
('48de68cc-06c4-4219-b89e-2242c7e79a58','夏夜誠齋望月','楊萬里','宋','宋诗','song-poetry','','[]','山居道是沒空庭，不道誠齋敞更明。',64,'全唐诗/poet.song.142000.json','["山居道是沒空庭，不道誠齋敞更明。", "萬里青天元是水，半輪皎月忽成冰。", "只今夏熱已如此，若到秋高何似生。", "玉兔素娥兼老子，三家一樣雪鬅鬙。"]'),
('f7ca2dcb-570a-44de-bccf-af4b92f3a7b4','誠齋步月  其一','楊萬里','宋','宋诗','song-poetry','','[]','先生散髮步庭中，孤月行天露滿空。',32,'全唐诗/poet.song.142000.json','["先生散髮步庭中，孤月行天露滿空。", "已入廣寒宮裏去，如何別覓廣寒宮。"]'),
('f175de26-eaeb-4087-9b26-84c53c9bff99','誠齋步月  其二','楊萬里','宋','宋诗','song-poetry','','[]','桂樹何曾不長枝，月輪却有不圓時。',32,'全唐诗/poet.song.142000.json','["桂樹何曾不長枝，月輪却有不圓時。", "若教桂樹只管長，拶拆月輪誰補伊。"]'),
('0aeb9f34-066d-4c1c-be5a-f1b2bfc20e50','誠齋步月 止酒','楊萬里','宋','宋诗','song-poetry','','[]','止酒先立約，庶幾守得堅。',180,'全唐诗/poet.song.142000.json','["止酒先立約，庶幾守得堅。", "自約復自守，事亦未必然。", "約語未出口，意已慘不驩。", "平生死愛酒，愛酒寧棄官。", "憶昔少年日，與酒爲忘年。", "醉則卧香草，落花爲繡氈。", "覺來月已上，復飲落花前。", "衰腸不禁酒，此事今莫論。", "因酒屢作病，自祟非關天。", "朝來腹告痛，飲藥痛不痊。", "銳欲絕伯雅，已書絕交篇。", "如何酒未絕，告至愁已先。", "我與意爲仇，意慘我何便。", "不如且快意，伯雅再遣前。", "來日若再病，旋旋商量看。"]'),
('d1bab91e-b636-464e-9f8b-90f74bbd9d5f','跋蕭彥毓梅坡詩集','楊萬里','宋','宋诗','song-poetry','','[]','西昌有客學南昌，衣鉢真傳快閣旁。',64,'全唐诗/poet.song.142000.json','["西昌有客學南昌，衣鉢真傳快閣旁。", "坡底詩人梅底醉，花爲句子蕊爲章。", "想渠蹋月枝枝瘦，贈我盈編字字香。", "若畫江西後宗派，不愁禽賊不禽王。"]'),
('c855c988-3840-47a9-ae34-7bc0cd2b9cba','入郡城泊文家宅子夜熱不寐','楊萬里','宋','宋诗','song-poetry','','[]','毒熱通宵不得眠，起來弄水繞庭前。',32,'全唐诗/poet.song.142000.json','["毒熱通宵不得眠，起來弄水繞庭前。", "大星跳下銀盆底，翻動琉璃一鏡天。"]'),
('0692e851-e9f7-4171-b33e-b53e403d8b75','六月將晦夜出凝歸門','楊萬里','宋','宋诗','song-poetry','','[]','暑裏街頭可久停，今宵無月也宵征。',64,'全唐诗/poet.song.142000.json','["暑裏街頭可久停，今宵無月也宵征。", "一天星點明歸路，十里荷香送出城。", "山轎聲聲柔艣緊，葛衣眼眼野風清。", "五更月出還家了，不早相期作伴行。"]'),
('b772dd8a-eea9-4e11-9abe-31ee09670776','荷池小立','楊萬里','宋','宋诗','song-poetry','','[]','點鐵成金未是靈，若教無鐵也難成。',32,'全唐诗/poet.song.142000.json','["點鐵成金未是靈，若教無鐵也難成。", "阿誰得似青荷葉，解化清泉作水精。"]'),
('c1a07151-8cd1-43ca-a0cf-60913bd0b198','幽居感興','楊萬里','宋','宋诗','song-poetry','','[]','葛製冰餐消幾錢，雲棲水宿本臞仙。',32,'全唐诗/poet.song.142000.json','["葛製冰餐消幾錢，雲棲水宿本臞仙。", "回頭背汗渾如雨，賺却閑身四十年。"]'),
('9392f16b-b6b3-4e7b-b860-f44f07525abe','觀魚','楊萬里','宋','宋诗','song-poetry','','[]','老夫不奈熱，跣足坐瓦鼓。',72,'全唐诗/poet.song.142000.json','["老夫不奈熱，跣足坐瓦鼓。", "臨池觀游魚，定眼再三數。", "魚兒殊畏人，欲度不敢度。", "一魚試行前，似報無他故。", "衆魚初欲隨，幡然竟回去。", "時時傳一杯，忽忽日將暮。"]'),
('286bcd23-9145-4144-b7dd-1079fed160cf','秋凉晚酌','楊萬里','宋','宋诗','song-poetry','','[]','寄老山林度懶殘，新秋又是一年年。',64,'全唐诗/poet.song.142000.json','["寄老山林度懶殘，新秋又是一年年。", "青編翠竹風窗月，白酒紅蕖水檻天。", "暑欲謝時偏更毒，儂當醉後恕渠顛。", "者稀尚隔來年在，且釂今宵藥玉船。"]'),
('b96dd624-0cfc-45f4-9d37-d8995bf05427','荷池觀魚','楊萬里','宋','宋诗','song-poetry','','[]','截山剜沼貯泉流，旋種鯈魚絕善游。',64,'全唐诗/poet.song.142000.json','["截山剜沼貯泉流，旋種鯈魚絕善游。", "細數未齊還已亂，羣嬉半沒忽全浮。", "荷錢荇带來復去，雪片銀花稀却稠。", "我樂自知魚似我，何緣惠子會莊周。"]'),
('d49097b4-4c08-467d-90f1-dd8f1f4eb324','同子文材翁子直蕭巨濟中元夜東園望月二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雜碎輕雲白錦鱗，十分圓月濕銀盆。',32,'全唐诗/poet.song.142000.json','["雜碎輕雲白錦鱗，十分圓月濕銀盆。", "錦鱗散盡銀盆在，依舊青天無點痕。"]'),
('3e68ebde-f848-4bb1-9b14-516775c15f72','同子文材翁子直蕭巨濟中元夜東園望月二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','月到東園分外光，行行坐坐間傳觴。',32,'全唐诗/poet.song.142000.json','["月到東園分外光，行行坐坐間傳觴。", "生愁踏碎千花影，回顧千花總不妨。"]'),
('a2d82861-49b3-4dd5-807d-f7cdcc424176','十六日夜再同子文巨濟李叔粲南溪步月','楊萬里','宋','宋诗','song-poetry','','[]','際晚溪游暮欲歸，追涼逐勝却成遲。',64,'全唐诗/poet.song.142000.json','["際晚溪游暮欲歸，追涼逐勝却成遲。", "月如醉眼生紅暈，山作愁眉带淡姿。", "天下無人閑似我，秋邊有句說從誰。", "弟兄一再更相送，行到更深笑不知。"]'),
('2694583c-7d5b-48ce-a3b0-07934e5ee2aa','重九前四日晝睡獨覺','楊萬里','宋','宋诗','song-poetry','','[]','睡思初酣過午强，起來四顧已斜陽。',64,'全唐诗/poet.song.142000.json','["睡思初酣過午强，起來四顧已斜陽。", "添糊窗隔無風氣，旋曬衣裘有日香。", "舊雨不來從草綠，新豐獨酌又花黄。", "去年重九窮忙過，可遣今年更作忙。"]'),
('6da5f37f-53f1-414c-866a-4c3c20a0026e','重九後二日同徐克章登萬花川谷月下傳觴','楊萬里','宋','宋诗','song-poetry','','[]','老夫渴急月更急，酒落杯中月先入。',128,'全唐诗/poet.song.142000.json','["老夫渴急月更急，酒落杯中月先入。", "領取青天併入來，和月和天都蘸濕。", "天既愛酒自古傳，月不解飲真浪言。", "舉杯將月一口吞，舉頭見月猶在天。", "老夫大笑問客道，月是一團還兩團。", "酒入詩腸風火發，月入詩腸冰雪潑。", "一杯未盡詩已成，誦詩向天天亦驚。", "焉知萬古一骸骨，酌酒更吞一團月。"]'),
('0b5e07f2-9338-4f19-a129-1ce58773f142','寄題劉巨卿家六詠 詣齋','楊萬里','宋','宋诗','song-poetry','','[]','紫鸞自超詣，一日可天地。',24,'全唐诗/poet.song.142000.json','["紫鸞自超詣，一日可天地。", "兒郎但讀書，聖處底難至。"]'),
('7d49cc6b-07fc-45a7-87cb-a64c6a34fcd7','寄題劉巨卿家六詠 蒙齋','楊萬里','宋','宋诗','song-poetry','','[]','是心如維斗，萬物所取正。',24,'全唐诗/poet.song.142000.json','["是心如維斗，萬物所取正。", "蒙之以微雲，孤光更淵靚。"]'),
('012f8dc9-4ee2-4235-909f-fe509b3d45ea','寄題劉巨卿家六詠 拙庵','楊萬里','宋','宋诗','song-poetry','','[]','天下無箇事，巧著事便生。',24,'全唐诗/poet.song.142000.json','["天下無箇事，巧著事便生。", "濂溪一賦在，座右不須銘。"]'),
('9141d089-5c06-42ae-a1e3-d034035119c9','寄題劉巨卿家六詠 西隠','楊萬里','宋','宋诗','song-poetry','','[]','山林與朝市，隠處俱未是。',24,'全唐诗/poet.song.142000.json','["山林與朝市，隠處俱未是。", "只箇西枝西，默坐且求志。"]'),
('ef83d56f-7d93-4c01-9d1c-008147ed9fae','寄題劉巨卿家六詠 壺天','楊萬里','宋','宋诗','song-poetry','','[]','其大彌九蒼，其小貯一壺。',24,'全唐诗/poet.song.142000.json','["其大彌九蒼，其小貯一壺。", "靜觀性中天，大小竟何如。"]'),
('d4fea605-d7be-475b-a215-639abcab1ad9','寄題劉巨卿家六詠 來薰軒','楊萬里','宋','宋诗','song-poetry','','[]','薰風自南來，萬象皆披襟。',24,'全唐诗/poet.song.142000.json','["薰風自南來，萬象皆披襟。", "老子本不熱，看他度青林。"]'),
('4b750879-3785-4d08-9429-cc05f6c22a4c','題玄潭觀雪浪閣','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','贛江西來千里許，流到閣前虎鬚怒。',72,'全唐诗/poet.song.142000.json','["贛江西來千里許，流到閣前虎鬚怒。", "旌陽橫劍居上頭，却喝長江教倒流。", "跳作漩花雪山立，濺得琳房滿山濕。", "即今水落未足觀，桃花浪起君來看，一波打窗君膽寒。"]'),
('a0b281ef-a35a-4594-8407-04cf3c0febf2','贈寫真劉敏叔秀才二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','冰鑑傳神苦未工，傳來恰恰五秋風。',32,'全唐诗/poet.song.142000.json','["冰鑑傳神苦未工，傳來恰恰五秋風。", "又將老醜形骸子，般入劉家畫苑中。"]'),
('0715b366-1d69-446e-a674-d707d4ec7298','贈寫真劉敏叔秀才二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','江右傳神下筆親，杉溪集裏識劉君。',32,'全唐诗/poet.song.142000.json','["江右傳神下筆親，杉溪集裏識劉君。", "君今有子能傳業，撞過煙樓更入神。"]'),
('931c54e6-04de-4801-9769-daeaeb5b4743','跋寫真劉敏叔八君子圖','楊萬里','宋','宋诗','song-poetry','','[]','一代一兩人，國已九鼎重。',48,'全唐诗/poet.song.142000.json','["一代一兩人，國已九鼎重。", "如何八君子，一日集吾宋。", "古人三不朽，諸老一一中。", "久別忽相逢，相對恍如夢。"]'),
('d12b8098-98be-433f-95e7-63af5947a2ce','詩人王季廉挽詩','楊萬里','宋','宋诗','song-poetry','','[]','手探盧溪頷下珠，詞林再嘯老於菟。',64,'全唐诗/poet.song.142000.json','["手探盧溪頷下珠，詞林再嘯老於菟。", "不餐煙火惟存骨，吟殺江山失却鬚。", "錦里鶑花餘故宅，灞橋風雪入新圖。", "只今醉卧長松下，猶要熊兒捉轡無。"]'),
('b15f3eda-b839-4570-9f1d-a36f5dcf03f3','乙卯春日三三徑行散有感','楊萬里','宋','宋诗','song-poetry','','[]','東園一日走千巡，又見龍飛第一春。',64,'全唐诗/poet.song.142000.json','["東園一日走千巡，又見龍飛第一春。", "桃李成陰儂已老，江山依舊歲還新。", "穿花踏影渾無日，隔徑聞聲不見人。", "學省同寮各星散，白雲珍重伴閑身。"]'),
('95db5fd3-ddd1-4477-a762-5aee8f4e62e6','立春檢校牡丹','楊萬里','宋','宋诗','song-poetry','','[]','牡丹又欲試春粧，惱得閑人也作忙。',64,'全唐诗/poet.song.142000.json','["牡丹又欲試春粧，惱得閑人也作忙。", "新舊年頭將替換，去留花眼費商量。", "東風從我袖中出，小蕾已含天上香。", "只道開時恐腸斷，未開先自斷人腸。"]'),
('d25132af-eecb-47cc-8415-b4ed164a278f','曉起探梅四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','一生劫劫只長塗，投老山林始定居。',32,'全唐诗/poet.song.142000.json','["一生劫劫只長塗，投老山林始定居。", "夢破燈青窗欲白，猶疑雪店聽雞初。"]'),
('e198132c-389a-45a2-8d11-e9b924c9d74f','曉起探梅四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','打併人間名利心，萬山佳處一溪深。',32,'全唐诗/poet.song.142000.json','["打併人間名利心，萬山佳處一溪深。", "仙家忍餓禪家苦，老子梅邊政醉吟。"]'),
('f666e5e7-b18d-4c1e-a0f1-142678e63d3e','曉起探梅四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','一祖南枝派五房，紅黄萼綠蠟鴛鴦。',32,'全唐诗/poet.song.142000.json','["一祖南枝派五房，紅黄萼綠蠟鴛鴦。", "杏紅千葉元無種，誰子翻騰箇樣粧。"]'),
('7de2359a-d96f-4d08-a825-556a6a648ec7','曉起探梅四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','江梅小樹打頭開，便有紅梅趁脚來。',32,'全唐诗/poet.song.142000.json','["江梅小樹打頭開，便有紅梅趁脚來。", "趲得杏紅開火急，春風已落第三回。"]'),
('9deffbd9-7646-4646-9609-9cd0a3822dc1','題曾無媿月窗','楊萬里','宋','宋诗','song-poetry','','[]','阿兄作雲巢，阿弟作月窗。',116,'全唐诗/poet.song.142000.json','["阿兄作雲巢，阿弟作月窗。", "乾坤清氣只雲月，一家兩手併取將。", "作巢不用木，只架雲爲屋。", "作窗不用櫺，只掇月爲庭。", "兜羅綿上住兄子，銀色界中著吾弟。", "阿兄雲向筆下生，阿弟月向詩中明。", "弟兄雲月兩清絕，雲月何曾有分別。", "不知雲月入胸中，爲復胸中有雲月。"]'),
('5cd3bc66-026d-49db-a16a-fc780f83362b','人日後歸自郡城','楊萬里','宋','宋诗','song-poetry','','[]','倦來睡思酒般醲，曉起東園看曉風。',32,'全唐诗/poet.song.142000.json','["倦來睡思酒般醲，曉起東園看曉風。", "孤負梅花三四日，新年人事到城中。"]'),
('2f1ea0b6-04c6-4b86-aeb5-bddb22afa8ce','久雨小霽東園行散','楊萬里','宋','宋诗','song-poetry','','[]','雨寒兩月勒春遲，初喜雲間漏霽暉。',32,'全唐诗/poet.song.142000.json','["雨寒兩月勒春遲，初喜雲間漏霽暉。", "道是攀花無雨點，忽然放手濺人衣。"]'),
('47718dc9-2c27-4cad-8570-1f85d985b56a','中和節日步東園三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','兩晨又不到東園，沙徑朝來合小乾。',32,'全唐诗/poet.song.142000.json','["兩晨又不到東園，沙徑朝來合小乾。", "可惜紅梅將落去，怕風怕雨不來看。"]'),
('611f56ac-96ac-4378-9c58-f3f982e08365','中和節日步東園三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','五出桃花千葉緋，團欒繞樹問芳菲。',32,'全唐诗/poet.song.142000.json','["五出桃花千葉緋，團欒繞樹問芳菲。", "攀來欲折還休去，看到殘紅教自飛。"]'),
('7f041030-eab8-4153-8b26-14177a2504b7','中和節日步東園三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','一年佳節又中和，三分春光一已過。',32,'全唐诗/poet.song.142000.json','["一年佳節又中和，三分春光一已過。", "莫恨峭寒花較晚，留連春色儘從他。"]'),
('28ec7ce7-2fc0-492a-a329-4e8536061403','二月十日留子西材翁二弟晚酌','楊萬里','宋','宋诗','song-poetry','','[]','丁流迷沉一小炷，聚作香雲散香霧。',128,'全唐诗/poet.song.142000.json','["丁流迷沉一小炷，聚作香雲散香霧。", "清尊相屬對花前，政是一年春好處。", "海棠初試川樣粧，垂絲新出濯錦江。", "杏花欲落桃李拆，牡丹未拆已國香。", "酒行莫忙且一盞，一盞一番一行散。", "徧行九徑却重行，莫遣一花不相見。", "酒教少酌花多看，看盡千花却深勸。", "今宵無月不須燈，千樹李花如晝明。"]'),
('7103cc4b-f58a-4466-8b44-8cc463b84f3d','登度雪臺下臨桃李徑','楊萬里','宋','宋诗','song-poetry','','[]','桃花夾外李當中，三徑花開兩徑紅。',32,'全唐诗/poet.song.142000.json','["桃花夾外李當中，三徑花開兩徑紅。", "獨繞畫簷無箇事，自携團扇撲黄蜂。"]'),
('6a032652-e312-4a5b-9930-a238b0640b29','萬花川谷海棠盛開進退格','楊萬里','宋','宋诗','song-poetry','','[]','四面週遭國豔叢，危亭頓在豔叢中。',64,'全唐诗/poet.song.142000.json','["四面週遭國豔叢，危亭頓在豔叢中。", "天開錦幄三千丈，日透紅粧一萬重。", "積雨乍晴偏楚楚，東風小緩莫匆匆。", "爲花一醉非難事，且道花醲復酒醲。"]'),
('eb5a17e3-a064-42f0-8bf5-b96c02d2e28b','積雨小止暫到東園雨作急歸','楊萬里','宋','宋诗','song-poetry','','[]','咫尺東園千里遥，欣逢小霽略逍遥。',64,'全唐诗/poet.song.142000.json','["咫尺東園千里遥，欣逢小霽略逍遥。", "鷺穿秧稻新黄脚，蟲秃金沙嫩紫條。", "城市簷間堪繫纜，山溪夜半失危橋。", "匆匆行散還歸去，一陣飄蕭不見饒。"]'),
('8b9c6f16-8da4-4381-bee8-c56e3413f01f','四月二十八日祠祿秩滿喜罷感恩進退格','楊萬里','宋','宋诗','song-poetry','','[]','隨牒江湖四十年，寄名臺閣兩三番。',64,'全唐诗/poet.song.142000.json','["隨牒江湖四十年，寄名臺閣兩三番。", "全家廩食皆天賜，晚歲祠官是地仙。", "匹似分司轉閑散，也無拜表及寒溫。", "明朝更省毛錐力，十字名銜尚請錢。"]'),
('490f90aa-48af-491c-b3d6-fbcd3a98d59c','荷池小立','楊萬里','宋','宋诗','song-poetry','','[]','池小泉多强欲留，留它不住恣它流。',32,'全唐诗/poet.song.142000.json','["池小泉多强欲留，留它不住恣它流。", "荷盤不放荷尖出，穿破盤來却又休。"]'),
('27f2be29-2d3a-4ea7-a044-930d44d57d2c','贈閣皂山嬾雲道士詩客張惟深二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','閣皂峰頭半朶雲，化爲道士到吾門。',32,'全唐诗/poet.song.142000.json','["閣皂峰頭半朶雲，化爲道士到吾門。", "問渠真箇如雲嬾，爲許隨風處處村。"]'),
('888248ac-84fc-4420-9ee1-39f4205b587c','贈閣皂山嬾雲道士詩客張惟深二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','羽客來從閣皂山，殷勤告訴病詩癲。',32,'全唐诗/poet.song.142000.json','["羽客來從閣皂山，殷勤告訴病詩癲。", "古今此病元無藥，癲到陰何便是仙。"]'),
('7036f062-ebab-428f-802e-50125b3b0541','料理小荷池','楊萬里','宋','宋诗','song-poetry','','[]','側塞浮荷更泛苔，爲芟數路水痕開。',32,'全唐诗/poet.song.142000.json','["側塞浮荷更泛苔，爲芟數路水痕開。", "魚兒便喜新開港，繞去繞來千百回。"]'),
('73d15f28-5f52-4c4f-bb2f-5a8ac08262bb','六月十六日夜南溪望月','楊萬里','宋','宋诗','song-poetry','','[]','溪水留我住，溪月愁我歸。',180,'全唐诗/poet.song.142000.json','["溪水留我住，溪月愁我歸。", "望後月更佳，昨宵未爲奇。", "大都月色好，一歲能幾時。", "人散長是早，月來長是遲。", "初出如大甕，纔露金半規。", "不知獨何急，下如有人推。", "忽然脫嶺尖，行空安不危。", "似愛溪水浄，下浴青瑠璃。", "明珠徑餘尺，沈在千頃陂。", "我欲刺雙手，就溪取團暉。", "白小忽亂跳，碎作萬金徽。", "須臾波痕定，化爲水銀池。", "夜久看未足，風露欺病肌。", "我能尚小留，瘦藤歌式微。", "一笑顧羣從，來夕肯集茲。"]'),
('5dbfa7d4-30fa-4549-afea-3a9ec5a15c23','送吉守趙山父移廣東提刑','楊萬里','宋','宋诗','song-poetry','','[]','越臺海山清更雄，曲江間出曲江公。',96,'全唐诗/poet.song.142000.json','["越臺海山清更雄，曲江間出曲江公。", "憲臺師表光且耿，濂溪留下濂溪井。", "趙侯端是宋間平，妙年策名千佛經。", "陽春有脚來江城，銀漢乘槎移使星。", "嶺上梅花莫遲發，先遣北枝迎玉節。", "寄聲多賀帽子峰，今歲峰頭有霜雪。"]'),
('4a0cb050-19c7-4571-8b3e-c37628f96547','擬吉州解試秋風楚竹冷詩','楊萬里','宋','宋诗','song-poetry','','[]','客子征行日，偏逢楚水秋。',72,'全唐诗/poet.song.142000.json','["客子征行日，偏逢楚水秋。", "一風來瑟瑟，萬竹冷脩脩。", "吹作清霜骨，聲酣古渡頭。", "斑林寒欲裂，碧節爽還幽。", "不復披襟快，長懷落帽愁。", "少陵詩思苦，送別更冥搜。"]'),
('0300f11c-045e-47a4-bd2f-2ac914114e1e','題星子縣黄宰世高問政堂','楊萬里','宋','宋诗','song-poetry','','[]','黄子儂故人，危子儂門生。',92,'全唐诗/poet.song.142000.json','["黄子儂故人，危子儂門生。", "向來同登漱玉亭，銀河洗面醉不醒。", "四年二子不見面，過眼光陰掣飛電。", "今晨忽得問政碑，黄子作堂危子詞。", "危子筆力乃爾進，黄子佳政不須問。", "寄言二子各努力，古人也是人作得。"]'),
('7de437c6-fe13-4f46-bfed-0f6239c7c658','大丞相益國周公訪予於碧瑶洞天劉敏叔寫以爲圖求予書其後','楊萬里','宋','宋诗','song-poetry','','[]','平叔曾過魏秀才，何如老子致元台。',32,'全唐诗/poet.song.142000.json','["平叔曾過魏秀才，何如老子致元台。", "蒼松翠竹青苔逕，也不傳呼宰相來。"]'),
('efa30178-2c42-480c-8b53-2f65f272b4e1','丞相周公招王才臣中秋賞梅花寄以長句','楊萬里','宋','宋诗','song-poetry','','[]','素娥大作中秋節，一夜廣寒桂花發。',96,'全唐诗/poet.song.142000.json','["素娥大作中秋節，一夜廣寒桂花發。", "天風吹墮綠野堂，夜半瑶階丈深雪。", "梅仙不知天尚秋，只驚香雪點搔頭。", "笑隨玉妃照粉水，洗粧同入月中游。", "晉公賞梅仍賞桂，獨招子猷雪前醉。", "明朝有客訴天公，不喚香山病居士。"]'),
('1cb1064e-4b7e-4b58-a682-73466ea1ba5a','寄題開州史君陳師宋柴扉','楊萬里','宋','宋诗','song-poetry','','[]','屋是茅一把，門是柴一束。',72,'全唐诗/poet.song.142000.json','["屋是茅一把，門是柴一束。", "是間著宇宙，太倉半粒粟。", "吾聞陳家扉，樣似陶家屋。", "孤松不須雙，五柳何用六。", "竹籬東復東，添種數叢菊。", "剩肯蚤歸來，盈尊酒初綠。"]'),
('53615c1f-040f-4b8c-9ca1-529cee527ca0','寄題吳仁傑架閣玩芳亭','楊萬里','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭波上木葉脫，巫山宅前野花發。',112,'全唐诗/poet.song.142000.json','["洞庭波上木葉脫，巫山宅前野花發。", "子規啼殺不見人，空令千載憶靈均。", "春蘭九畹百畝蕙，自榮自落誰能佩。", "澤國東山最上頭，有客玩芳杜若洲。", "扁舟夜上人鮓甕，手掇騷人衆芳種。", "歸來夢到閬風臺，靈均花草和露栽。", "寄言衆芳未要開，更待誠齋老子來。"]'),
('77bb71a4-891b-4016-a13b-09154a73e628','題子文弟南溪奇觀','楊萬里','宋','宋诗','song-poetry','','[]','行盡三江與五湖，江湖元只近吾居。',64,'全唐诗/poet.song.142000.json','["行盡三江與五湖，江湖元只近吾居。", "一陂秋水鎔銀汁，萬里青天落玉壺。", "每約弟兄人定後，恣看風露月來初。", "老夫詩句休拈出，漏洩南溪奇觀圖。"]'),
('791a4bec-26e4-4a31-9465-d1ada2e9d884','賞菊四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','老子平生不解愁，花開酒熟萬緣休。',32,'全唐诗/poet.song.142000.json','["老子平生不解愁，花開酒熟萬緣休。", "更教不爲黄花醉，枉却今年一片秋。"]'),
('9de898e6-514e-4f49-8efe-ed0365618713','賞菊四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','菊花肯爲別人黄，長怨先生不斷腸。',32,'全唐诗/poet.song.142000.json','["菊花肯爲別人黄，長怨先生不斷腸。", "兩鬢盡凋無地插，一杯細嚼入神香。"]'),
('819384ec-12bd-4152-9920-924ea0d6d28a','賞菊四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','菊生不是遇淵明，自是淵明遇菊生。',32,'全唐诗/poet.song.142000.json','["菊生不是遇淵明，自是淵明遇菊生。", "歲晚霜寒心獨苦，淵明元是菊花精。"]'),
('db86d6ab-7ac6-4b7f-8e1e-76cb2d8226de','賞菊四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','物性從來各一家，誰貪寒瘦厭妍華。',32,'全唐诗/poet.song.142000.json','["物性從來各一家，誰貪寒瘦厭妍華。", "菊花自擇風霜國，不是春光外菊花。"]'),
('765e1fdd-ba34-4e85-9ec5-146d5c45b8b8','白菊二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','白菊初開也自黄，開來開去白如霜。',32,'全唐诗/poet.song.142000.json','["白菊初開也自黄，開來開去白如霜。", "小蜂劣得針來大，不怕清寒嗅冷香。"]'),
('4c786668-83f0-4c42-b85e-feb13ccf02bf','白菊二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','霜後黄花頓不中，獨餘白菊鬭霜濃。',32,'全唐诗/poet.song.142000.json','["霜後黄花頓不中，獨餘白菊鬭霜濃。", "與霜更鬭晴天日，鬭得霜融菊不融。"]'),
('ea2656c7-fbcc-46af-9a20-f222d91c0bbc','芙蓉盛開戲簡子文克信','楊萬里','宋','宋诗','song-poetry','','[]','芙蓉得雨一齊開，開盡秋花客不來。',32,'全唐诗/poet.song.142000.json','["芙蓉得雨一齊開，開盡秋花客不來。", "到得客來花已老，晚粧猶可兩三杯。"]'),
('b8989481-a1be-4b7c-a606-9fc0f59695ec','曉穿芙蓉徑二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','晚粧懶困曉粧新，火急來看趁絕晨。',32,'全唐诗/poet.song.142000.json','["晚粧懶困曉粧新，火急來看趁絕晨。", "夾徑花枝欺我老，競將紅露灑烏巾。"]'),
('a127c8ca-8d9b-4ac8-8d87-e8a86c296d36','曉穿芙蓉徑二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','芙蓉佳處不勝佳，花不中藏祗外斜。',32,'全唐诗/poet.song.142000.json','["芙蓉佳處不勝佳，花不中藏祗外斜。", "恰似曲江聞喜宴，綠衣半醉戴宮花。"]'),
('4101c0cd-e1cb-4273-be64-e2836eaa7e8c','送簡壽玉主簿之官臨桂二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','蘭溪傾蓋杏風殘，桂嶺離裾菊露寒。',64,'全唐诗/poet.song.142000.json','["蘭溪傾蓋杏風殘，桂嶺離裾菊露寒。", "聽子新詩過夜半，吹儂秋思入雲端。", "往吟平地千蒼玉，還憶孤舟一釣竿。", "四海如今習鑿齒，大官莫作小官看。"]'),
('7ab95d1d-63d4-451b-93dd-e1af2456e730','送簡壽玉主簿之官臨桂二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','柴門草徑儘莓苔，不放黄塵俗子來。',64,'全唐诗/poet.song.142000.json','["柴門草徑儘莓苔，不放黄塵俗子來。", "詩客清晨衝雨入，梅花一夜爲君開。", "飄蕭落葉殘燈火，陸續清談濁酒杯。", "二十六年纔四見，驪駒抵死祗相催。"]'),
('8dac90d1-3eab-4c11-b3bb-7bbf8eb09130','殘菊','楊萬里','宋','宋诗','song-poetry','','[]','腸斷黄花霜後枝，花乾葉悴兩離披。',32,'全唐诗/poet.song.142000.json','["腸斷黄花霜後枝，花乾葉悴兩離披。", "一花忽秀枯叢裏，更勝初開乍見時。"]'),
('2c1209f5-61f8-4a3d-aa0c-3d426836fc8f','秋圃','楊萬里','宋','宋诗','song-poetry','','[]','何處秋深好，山林處士家。',48,'全唐诗/poet.song.142000.json','["何處秋深好，山林處士家。", "青霜紅碧樹，白露紫黄花。", "一熟讎頻雨，朝晴禱暮霞。", "連宵眠不著，猶自愛新茶。"]'),
('c956e755-6212-42fd-951c-5935baf31af1','與侯子雲溪上晚步','楊萬里','宋','宋诗','song-poetry','','[]','人入溪園自掩門，溪流新落兩三痕。',64,'全唐诗/poet.song.142000.json','["人入溪園自掩門，溪流新落兩三痕。", "杖藜紫菊霜風徑，送眼丹楓夕照村。", "行住忽然忘近遠，陰晴未肯定寒暄。", "多時不出今聊出，牧子樵兒一笑喧。"]'),
('94a6c50b-d8cc-497a-ad09-af8c6c1224b9','十一月朔早起','楊萬里','宋','宋诗','song-poetry','','[]','拋笏投簪四見秋，宦情世味兩俱休。',64,'全唐诗/poet.song.142000.json','["拋笏投簪四見秋，宦情世味兩俱休。", "塵隨日影穿窗喜，葉卷風聲刮地愁。", "文武自勻香底火，聖賢教带老時篘。", "夜來富貴非人世，夢釣滄浪雪滿舟。"]'),
('bcb002a8-aa1c-4d39-b7c4-690097a6a89a','新晴','楊萬里','宋','宋诗','song-poetry','','[]','瑶霜珠露兩相鮮，玉宇金鉦萬里寬。',64,'全唐诗/poet.song.142000.json','["瑶霜珠露兩相鮮，玉宇金鉦萬里寬。", "欲作一晴多少日，早知祗費數朝寒。", "暴禾場裏鷄豚樂，試筆窗前紙墨乾。", "兒女莫餐新淅飯，打頭荷甔且輸官。"]'),
('ec07ce8e-094f-4a20-a0d1-628b16a6d807','嘲蜂','楊萬里','宋','宋诗','song-poetry','','[]','薰籠供藥較香些，引得蜂兒繞室譁。',32,'全唐诗/poet.song.142000.json','["薰籠供藥較香些，引得蜂兒繞室譁。", "笑死老夫緣底事，蜂兒專用鼻看花。"]'),
('2f3c7e4a-fe12-49d9-b820-ac0496413e1e','留蕭伯和仲和小飲二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','野果山蔬未要多，濁醪清酒儘從他。',64,'全唐诗/poet.song.142000.json','["野果山蔬未要多，濁醪清酒儘從他。", "不於兩盞三杯裏，奈此千愁百惱何。", "山倒莫教扶玉樹，尊空別得借銀河。", "少陵一語君知麽，不見堂前東逝波。"]'),
('032ba715-18bb-4549-ae8a-45365b4a711c','留蕭伯和仲和小飲二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','誰曾白日上青天，誰羨千鍾況萬錢。',64,'全唐诗/poet.song.142000.json','["誰曾白日上青天，誰羨千鍾況萬錢。", "要入詩家須有骨，若除酒外更無仙。", "三杯未必通大道，一斗真能出百篇。", "李杜饑寒纔幾日，却教富貴不論年。"]'),
('1be0c400-af58-4d69-b6c2-6bdd46fb28af','新晴東園晚步二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','一月秋陰一日晴，山禽相賀太丁寧。',64,'全唐诗/poet.song.142000.json','["一月秋陰一日晴，山禽相賀太丁寧。", "不愁白髮千莖雪，隨喜黄庭一卷經。", "晚霧薄情憎遠嶺，夕陽死命戀危亭。", "孤吟道是無人覺，松竹喧傳菊細聽。"]'),
('2927f1aa-da2d-4303-ad4e-222a856d1262','新晴東園晚步二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','忙裏清流也带塵，閑中底物不長新。',64,'全唐诗/poet.song.142000.json','["忙裏清流也带塵，閑中底物不長新。", "水將樹影揮空帚，楓換秋容作好春。", "自是不歸歸便得，老來下筆筆如神。", "鶑花煎煼無虛日，賤相誠齋一老人。"]'),
('8b64ef32-e319-4a25-a72b-0bc377a1ca42','新霜','楊萬里','宋','宋诗','song-poetry','','[]','得得今年未有寒，天公小靳不全判。',64,'全唐诗/poet.song.142000.json','["得得今年未有寒，天公小靳不全判。", "欲呈瑞雪飛花樣，先遣濃霜起草看。", "瓦脊生塵總瓊玉，梅梢著粉忽琅玕。", "老夫到老嫌冬熱，十指朝來出袖難。"]'),
('8c9f215d-7c6a-4f1d-ba72-bb444097e5fc','餐霜醒酒','楊萬里','宋','宋诗','song-poetry','','[]','宿酒朝來醉尚殘，胸懷眊矂腹仍煩。',32,'全唐诗/poet.song.142000.json','["宿酒朝來醉尚殘，胸懷眊矂腹仍煩。", "牡丹壇上欄干脚，自刮霜毬衮舌端。"]'),
('169cf55e-8957-4fd2-8051-11d247116246','梅菊同插硯滴','楊萬里','宋','宋诗','song-poetry','','[]','兩枝殘菊兩枝梅，同入銀甖釀玉醅。',32,'全唐诗/poet.song.142000.json','["兩枝殘菊兩枝梅，同入銀甖釀玉醅。", "待得陶泓真箇渴，二花酒熟與三杯。"]'),
('c278314e-a41e-46ba-a0dd-bcb53d089fb3','冬至霜晴','楊萬里','宋','宋诗','song-poetry','','[]','油簾雪白日華紅，老子良圖策雋功。',64,'全唐诗/poet.song.142000.json','["油簾雪白日華紅，老子良圖策雋功。", "自曬綿裘并衲袴，誰知衣桁是薰籠。", "絕憐寒菊枯根底，留得殘霜過日中。", "舊說冬乾年定濕，試將今歲試南翁。"]'),
('f61aac23-7589-4359-83cb-4ad63f5740a8','朱伯勤同子文弟幼楚姪來訪書事','楊萬里','宋','宋诗','song-poetry','','[]','板橋再葺岸頭橫，茅屋新添樹外明。',64,'全唐诗/poet.song.142000.json','["板橋再葺岸頭橫，茅屋新添樹外明。", "山勢追回一溪水，波光飛到萬花亭。", "沉煙久冷爐猶馥，簾子閑垂脚自平。", "坐看千林總黄落，只餘蘭蕙向人青。"]'),
('62a77b58-5752-4fdc-8956-735ad61d526d','與伯勤子文幼楚同登南溪奇觀戲道傍群兒','楊萬里','宋','宋诗','song-poetry','','[]','䰒鬆睡眼熨難開，曳杖緣溪啄紫苔。',32,'全唐诗/poet.song.142000.json','["䰒鬆睡眼熨難開，曳杖緣溪啄紫苔。", "偶見羣兒聊與戲，布衫青底捉將來。"]'),
('4ffb687b-59be-4022-9cd2-9a0bdea73286','曉行東園','楊萬里','宋','宋诗','song-poetry','','[]','霜後前林一向疎，丹楓落盡況黄梧。',64,'全唐诗/poet.song.142000.json','["霜後前林一向疎，丹楓落盡況黄梧。", "犯寒侵早看殘菊，怕熱平生不擁爐。", "老眼讀書長作睡，病身得酒忽全蘇。", "好詩排闥來尋我，一字何曾撚白鬚。"]'),
('bad5b7bf-1278-4641-80d0-40ab83ff60dd','至後十日雪中觀梅','楊萬里','宋','宋诗','song-poetry','','[]','小樹梅花徹夜開，侵晨雪片趁花回。',64,'全唐诗/poet.song.142000.json','["小樹梅花徹夜開，侵晨雪片趁花回。", "即非雪片催梅發，却是梅花喚雪來。", "琪樹橫枝吹腦子，玉妃乘月上瑶臺。", "世間除却梅梢雪，便是冰霜也带埃。"]'),
('37137f37-b76b-4d20-931c-c85e98eab7f2','飲酒','楊萬里','宋','宋诗','song-poetry','','[]','今日偶不飲，無事亦有思。',180,'全唐诗/poet.song.142000.json','["今日偶不飲，無事亦有思。", "偶然舉一杯，事至我不知。", "豈獨忘萬事，此身亦如遺。", "此酒本何物，秫先麯還隨。", "飯秫祗醒眼，嚼麴無醉時。", "秫麴偶相逢，清泉媒妁之。", "不知獨何神，幻出忘世姿。", "莊周不須周，惠施不須施。", "貴賤與死生，不齊元自齊。", "我本非搢紳，金華牧羊兒。", "祗坐讀詩禮，一出不得歸。", "歸來今四年，似早其實遲。", "海中無蓬萊，蓬萊在酒池。", "今夕一杯酒，乘風駕雲旗。", "猶遭世緣縛，未掛神武衣。"]'),
('9a536b28-cfbf-4a51-a25c-8e5c66eda363','雪後領兒輩行散','楊萬里','宋','宋诗','song-poetry','','[]','今日意不愜，出游聊逍遥。',168,'全唐诗/poet.song.142000.json','["今日意不愜，出游聊逍遥。", "父子自爲伴，何須外招邀。", "過溪足小倦，臨流坐危橋。", "回頭顧吾廬，竹樹翳草寮。", "獨有萬花亭，巋然出山椒。", "高陂瀉溪水，環佩鏘瓊瑶。", "飛流迸空起，平水和天摇。", "舂淙到潭底，勢盡自浮漂。", "蟹眼沸不停，雪山湧還消。", "近觀絕洶洶，遠聽漸蕭蕭。", "忽逢綠頭公，携孥鼓丹橈。", "喧呼葦間出，得意似見驕。", "我行爲小立，流魚偶雙跳。", "人物各自適，茲游定誰超。"]'),
('b4faccda-6b89-4fa3-9471-ad240c8acd81','中塗小歇','楊萬里','宋','宋诗','song-poetry','','[]','山僮問游何許村，莫問何許但出門。',64,'全唐诗/poet.song.142000.json','["山僮問游何許村，莫問何許但出門。", "脚根倦時且小歇，山色佳處須細看。", "道逢田父遮儂住，說與前頭看山去。", "寄下君家老瓦盆，它日重游却來取。"]'),
('5113373d-225f-4efe-9cc5-657edabe7aba','雲際寺前山頂却望幡竿鷓鴣諸山二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','幡竿嶺带鷓鴣山，雪後霜前紫翠間。',32,'全唐诗/poet.song.142000.json','["幡竿嶺带鷓鴣山，雪後霜前紫翠間。", "自掇胡床移好處，莫教漏眼一煙鬟。"]'),
('39b5ec80-e74f-477a-84e5-2f182d9ab927','雲際寺前山頂却望幡竿鷓鴣諸山二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','遠近青山列畫屏，近山濃抹遠山輕。',32,'全唐诗/poet.song.142000.json','["遠近青山列畫屏，近山濃抹遠山輕。", "高屏已出低屏外，更有孤峰出一層。"]'),
('3af9d299-6542-4afa-819c-832a9c6ddbfc','游雲際寺諸僧皆出因過田家','楊萬里','宋','宋诗','song-poetry','','[]','游徧諸峰欲晚霞，倦投野寺覓煎茶。',32,'全唐诗/poet.song.142000.json','["游徧諸峰欲晚霞，倦投野寺覓煎茶。", "更無一箇殘僧在，歸路却投田舍家。"]'),
('b9139fbd-1bb7-450e-bd97-b4ac1fd13a5f','歸路過南溪橋二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','霜風一動嶺雲開，雲外樵歌暮更哀。',32,'全唐诗/poet.song.142000.json','["霜風一動嶺雲開，雲外樵歌暮更哀。", "童子隔溪呼伴侶，併驅水牯過溪來。"]'),
('022f3455-4af2-41e9-bdad-eb06a6e8a089','歸路過南溪橋二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','愛它風物重徘徊，歸路遲遲却快哉。',32,'全唐诗/poet.song.142000.json','["愛它風物重徘徊，歸路遲遲却快哉。", "曲折緣溪非細好，忽逢斷岸却回來。"]'),
('24061c81-92f9-442f-9092-bfc90d3af22f','荷池','楊萬里','宋','宋诗','song-poetry','','[]','小池歲晚石泉寒，荷葉低垂綠柄乾。',32,'全唐诗/poet.song.142000.json','["小池歲晚石泉寒，荷葉低垂綠柄乾。", "一似漁人暮歸後，敗蓑破笠掛魚竿。"]'),
('5cb6db54-314f-4809-abe6-c1caec4fa61b','簷滴','楊萬里','宋','宋诗','song-poetry','','[]','簷滴疎疎亦幾何，滴將苔砌出圜窠。',32,'全唐诗/poet.song.142000.json','["簷滴疎疎亦幾何，滴將苔砌出圜窠。", "就中漱滌偏精巧，泥土都無石子多。"]'),
('23454ef3-eab9-442c-a7e7-e09b3f25c844','與山莊子仁姪東園看梅四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','仰樹看花不見梅，聞香疑在別園開。',32,'全唐诗/poet.song.142000.json','["仰樹看花不見梅，聞香疑在別園開。", "更行數步偶回首，却被青松映出來。"]'),
('a731700a-76d5-49c4-a201-305106d4efc5','與山莊子仁姪東園看梅四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','梅花不是雪家仙，雪裏如何不怕寒。',32,'全唐诗/poet.song.142000.json','["梅花不是雪家仙，雪裏如何不怕寒。", "凍脫龍髯冰却海，千花試與鬭來看。"]'),
('40632ce0-a0f9-45dd-b765-dd4ceed6bf54','與山莊子仁姪東園看梅四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','手種江梅五百窠，小窠開早更花多。',32,'全唐诗/poet.song.142000.json','["手種江梅五百窠，小窠開早更花多。", "就中一樹尤清絕，惱殺先生看殺它。"]'),
('a068b24c-b22f-4c55-b594-b25340635764','與山莊子仁姪東園看梅四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','步繞梅花徧一園，得花妙處忽欣然。',32,'全唐诗/poet.song.142000.json','["步繞梅花徧一園，得花妙處忽欣然。", "元來別有看花眼，笑向山莊死不傳。"]'),
('fc488855-b39b-4b44-b400-45a6dd3ac987','歲暮歸自城中一病垂死病起遣悶四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','索居獨寡歡，巾車入城闉。',132,'全唐诗/poet.song.142000.json','["索居獨寡歡，巾車入城闉。", "親舊久不見，一見交相欣。", "挽衣招我飲，惟恐我出門。", "不招我亦往，不留我亦存。", "殷勤復如許，不住我豈真。", "是時梅始花，吹香落金尊。", "酒冽肴果富，咀啜俱芳珍。", "丞相我知己，太守吾故人。", "言非汰塵雜，塵雜不入言。", "初談聖賢髓，終談天地根。", "而況銜杯酒，不樂復何云。"]'),
('3134d7c3-5341-40a5-b338-30626501a596','歲暮歸自城中一病垂死病起遣悶四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','出郭雲尚明，及郊日忽暮。',144,'全唐诗/poet.song.142000.json','["出郭雲尚明，及郊日忽暮。", "不思日晷短，却信雲色誤。", "駿奔六七里，逢店破亦住。", "澆愁幸殘尊，照睡聊短炬。", "荒雞喚野夢，晨起念速步。", "升車乃復下，故疾動中腑。", "昏眩懔欲絕，低徊不能去。", "僮僕强我歸，偶不隕中路。", "老至猶倚强，疾在自不悟。", "及慈一委頓，去死僅寸許。", "人生信浮脆，可笑何足懼。", "所懼棄官晚，行樂今已遽。"]'),
('900eb666-a84d-4747-b02b-6c213537715f','歲暮歸自城中一病垂死病起遣悶四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','食罷游東園，慨然傷我懷。',132,'全唐诗/poet.song.142000.json','["食罷游東園，慨然傷我懷。", "昨日卧病時，自謂不復來。", "入門大風起，萬松聲頓哀。", "病骨念不堪，欲行重徘徊。", "裴徊南齋前，小倦坐苔階。", "齋前花不多，亦有兩古梅。", "似知我至此，頃刻忽盡開。", "多情梅間竹，偃風特奇哉。", "不知喜風舞，爲復怯風回。", "萬象皆迎春，我獨老病催。", "明日能來否，且歸撥爐灰。"]'),
('876e95b9-3c01-4925-a945-d7db937b16e8','歲暮歸自城中一病垂死病起遣悶四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','病起行不得，坐久情不舒。',108,'全唐诗/poet.song.142000.json','["病起行不得，坐久情不舒。", "倔强妻子前，欲扶羞索扶。", "且呼斑竹君，寸步與我俱。", "遠行亦未決，聊復循庭除。", "平地誰云覺，陟降即少徐。", "平生四方志，八極視若無。", "西飛折若木，東厲騎鯨魚。", "即今卧藜床，一起還九噓。", "力憊志猶在，床頭尋湛盧。"]'),
('ae08b426-9836-49f6-a554-222d6d887b2a','丙辰歲朝行東園','楊萬里','宋','宋诗','song-poetry','','[]','元日扶衰看早春，嫩苔一徑落梅新。',32,'全唐诗/poet.song.142000.json','["元日扶衰看早春，嫩苔一徑落梅新。", "何人舞罷凌波襪，踏匾真珠滿綠絪。"]'),
('bb88ff73-5576-4c33-bfb6-28ee8489e740','題張坦夫腴莊圖三首  其一','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','百里青山十里溪，荷花萬頃照紅衣。',32,'全唐诗/poet.song.142000.json','["百里青山十里溪，荷花萬頃照紅衣。", "臨平山下西湖上，總被腴莊掇取歸。"]'),
('4b47db0d-a863-4e80-831b-1db3160a938b','題張坦夫腴莊圖三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','花光泉響不相參，城市山林難兩兼。',32,'全唐诗/poet.song.142000.json','["花光泉響不相參，城市山林難兩兼。", "不分腴莊最無頼，一時奄有忒傷廉。"]'),
('613b9a09-4529-48d4-8ea1-67e3da8c870e','題張坦夫腴莊圖三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','花開還喜落還嗟，君被腴莊惱却些。',32,'全唐诗/poet.song.142000.json','["花開還喜落還嗟，君被腴莊惱却些。", "何似老夫展橫軸，一朝看盡四時花。"]'),
('1f6321f0-1276-4d61-af7e-af2f1024438d','東園晴步二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','淺暖疎寒十日晴，桃花紅暗李花明。',32,'全唐诗/poet.song.142000.json','["淺暖疎寒十日晴，桃花紅暗李花明。", "小蜂撲得渾無益，羽扇徒勞不作聲。"]'),
('c43b0afa-e836-4f09-8e2d-05e127b5a61a','東園晴步二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','金沙遶架卧春風，節節新條出嫩叢。',32,'全唐诗/poet.song.142000.json','["金沙遶架卧春風，節節新條出嫩叢。", "一色勻排綠瓶子，忽然半縷漏深紅。"]'),
('370c3582-595b-409d-b663-a6b5819a2c9d','曉登萬花川谷看海棠二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','夜雨朝晴花睡餘，海棠傾國萬花無。',32,'全唐诗/poet.song.142000.json','["夜雨朝晴花睡餘，海棠傾國萬花無。", "館娃一樣三千女，露滴燕脂洗面初。"]'),
('9e5fc99c-5f2f-4b2e-b82d-d7535f9a7bd8','曉登萬花川谷看海棠二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','準擬今春樂事醲，依前枉却一東風。',32,'全唐诗/poet.song.142000.json','["準擬今春樂事醲，依前枉却一東風。", "年年不带看花福，不是愁中即病中。"]'),
('d9f1f873-da71-4116-8ce9-9ce733d5b3ef','走筆送趙正則司戶來訪歸覲親庭','楊萬里','宋','宋诗','song-poetry','','[]','捧檄親庭歸帽斜，肯臨破屋玉川家。',64,'全唐诗/poet.song.142000.json','["捧檄親庭歸帽斜，肯臨破屋玉川家。", "小留詩客三杯酒，試看山園幾處花。", "君到東湖與南浦，時當芍藥替金沙。", "却來書滿參卿考，徑泛銀河犯斗槎。"]'),
('b0523705-f0fe-4b97-aaf0-d74627e13aee','東園社日','楊萬里','宋','宋诗','song-poetry','','[]','風雨摧殘桃李枝，東園無樹不離披。',32,'全唐诗/poet.song.142000.json','["風雨摧殘桃李枝，東園無樹不離披。", "海棠過後殘花在，恰似上春初發時。"]'),
('624e717d-61af-4565-836f-f2ee2319c8b1','觀社','楊萬里','宋','宋诗','song-poetry','','[]','作社朝祠有足觀，山農祈福更迎年。',64,'全唐诗/poet.song.142000.json','["作社朝祠有足觀，山農祈福更迎年。", "忽然簫鼓來何處，走殺兒童最可憐。", "虎面豹頭時自顧，野謳市舞各爭妍。", "王侯將相饒尊貴，不博渠儂一餉癲。"]'),
('18372fb8-1843-4aea-8d0f-dab8aae7b062','上巳後一日同子文伯莊永年步東園三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','兄弟相過看牡丹，牡丹看了看東園。',32,'全唐诗/poet.song.142000.json','["兄弟相過看牡丹，牡丹看了看東園。", "攀翻花木來還去，九徑還行十八番。"]'),
('4712edf6-5fb4-4f84-be2b-7ad29d653285','上巳後一日同子文伯莊永年步東園三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','九徑陰陰一一穿，前談後笑各欣然。',32,'全唐诗/poet.song.142000.json','["九徑陰陰一一穿，前談後笑各欣然。", "緩行不是身無力，滿地殘紅不忍前。"]'),
('34192d03-fe4f-4132-96dd-3e5fbe67538a','上巳後一日同子文伯莊永年步東園三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','只愛酴醾雪作葩，不知雪後減金沙。',32,'全唐诗/poet.song.142000.json','["只愛酴醾雪作葩，不知雪後減金沙。", "春歸道是無情著，試看游絲舞落花。"]'),
('79e53769-d13a-4d9a-805d-1d48d776bb5e','積雨小霽','楊萬里','宋','宋诗','song-poetry','','[]','雨足山雲半欲開，新秧猶待小暄催。',32,'全唐诗/poet.song.142000.json','["雨足山雲半欲開，新秧猶待小暄催。", "一雙百舌花梢語，四顧無人忽下來。"]'),
('561616f3-29ea-4748-b626-10ba2243a7c5','題劉高士看雲圖','楊萬里','宋','宋诗','song-poetry','','[]','偶爲看雲且罷琴，萬山寒隔一溪深。',32,'全唐诗/poet.song.142000.json','["偶爲看雲且罷琴，萬山寒隔一溪深。", "誰言嚥月餐雲客，中有憂時致主心。"]'),
('e7e00a71-f400-419d-b2ce-4d7b346dfaeb','送黄巖老通判全州','楊萬里','宋','宋诗','song-poetry','','[]','瀟湘之山可當一枝筆，瀟湘之水可充一硯滴。',116,'全唐诗/poet.song.142000.json','["瀟湘之山可當一枝筆，瀟湘之水可充一硯滴。", "白石得官斑竹林，天錫筆硯供醉吟。", "好將湘山點湘水，灑滿青天一張紙。", "臺家旁搜清廟珍，奇珍墮在湘水濱。", "烏衣樞相今水鏡，手提一道人材柄。", "外臺況復有三賢，看即吹噓送上天。", "歸來肯過誠齋裏，分似錦囊新句子。"]'),
('1c0a4e15-1d1c-49a1-8d6c-145e73278520','送劉北秀二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','劉子過逢二十年，別來風月幾千篇。',32,'全唐诗/poet.song.142000.json','["劉子過逢二十年，別來風月幾千篇。", "黄金賣盡延賓友，囊底何須看一錢。"]'),
('99aab3ec-f60a-40f8-a4d2-30f39df020dd','送劉北秀二首  其二','楊萬里','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','贈我盆花十小詩，菖蒲一詠最清奇。',32,'全唐诗/poet.song.142000.json','["贈我盆花十小詩，菖蒲一詠最清奇。", "洞庭卷入堅昆椀，更卷青天入寸漪。"]'),
('8741549d-5b33-4d54-b35f-6e445e2fb465','暑中早起東齋獨坐','楊萬里','宋','宋诗','song-poetry','','[]','松竹陰中逗曉光，無風有露自生涼。',32,'全唐诗/poet.song.142000.json','["松竹陰中逗曉光，無風有露自生涼。", "黄筠椅子十二隻，倚遍瑠璃背滿霜。"]'),
('fb6dd270-3bfa-4ee4-8875-b2240b9abb7b','誠齋待月','楊萬里','宋','宋诗','song-poetry','','[]','紅稠碧秀暗山園，只有誠齋眼界寬。',32,'全唐诗/poet.song.142000.json','["紅稠碧秀暗山園，只有誠齋眼界寬。", "月近竹梢偏不上，要人不看要人看。"]'),
('9f268007-b1ce-4a15-a2db-06f349b83382','六月晦日','楊萬里','宋','宋诗','song-poetry','','[]','今年六月熱全無，不是雲陰即雨餘。',32,'全唐诗/poet.song.142000.json','["今年六月熱全無，不是雲陰即雨餘。", "松葉落階休掃動，黄金線織滑氍毹。"]'),
('f8a0351b-63ae-45bc-b852-b2857c9d7380','寄題儋耳東坡故居尊賢堂太守譚景先所作二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','東坡無地頓危身，天賜黎山活逐臣。',64,'全唐诗/poet.song.142000.json','["東坡無地頓危身，天賜黎山活逐臣。", "萬里鯨波隔希奭，千年桂酒弔靈均。", "精忠塞得乾坤破，日月伴渠文字新。", "祇箇短簷高屋帽，青蓮未是謫仙人。"]'),
('a8653ce9-9d5f-41c5-8c7e-492d410d9381','寄題儋耳東坡故居尊賢堂太守譚景先所作二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','先生初落海南垂，茅屋三間不到伊。',64,'全唐诗/poet.song.142000.json','["先生初落海南垂，茅屋三間不到伊。", "更有高堂懸畫像，幸無過客首新詩。", "古來賢聖皆如此，身後功名屬阿誰。", "底事百年譚太守，却教賓主不同時。"]'),
('59ff31bc-acf4-455d-9c37-0f2901a95728','小池荷葉雨聲','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','午夢西湖泛煙水，畫船撐入荷花底。',64,'全唐诗/poet.song.142000.json','["午夢西湖泛煙水，畫船撐入荷花底。", "雨聲一陣打疎篷，驚開睡眼初䰒鬆。", "乃是池荷跳急雨，散了真珠又還聚。", "幸然聚作水銀泓，瀉入清波無覓處。"]'),
('c88213d7-8872-47d8-8f53-3aa58b063741','贈左元規','楊萬里','宋','宋诗','song-poetry','','[]','誰道古人今不如，龍生龍駒鳳鳳雛。',64,'全唐诗/poet.song.142000.json','["誰道古人今不如，龍生龍駒鳳鳳雛。", "太沖千載有孫子，筆端真可四三都。", "向來鹿鳴首送渠，至今銀袍雙袖烏。", "會逢玄晏爲拈出，殿前作賦聲第一。"]'),
('03964b5a-ee37-4446-9129-1927d8d22564','八月十二日夜誠齋望月','楊萬里','宋','宋诗','song-poetry','','["\u6708\u4eae", "\u548f\u7269", "\u548f\u7269\u8bd7"]','纔近中秋月已清，鴉青幕掛一團冰。',32,'全唐诗/poet.song.142000.json','["纔近中秋月已清，鴉青幕掛一團冰。", "忽然覺得今宵月，元不黏天獨自行。"]'),
('75a3a14e-7265-4f4a-ba54-2a5062f3c399','蛩聲','楊萬里','宋','宋诗','song-poetry','','[]','誠齋老子一歸休，最感蛩聲五報秋。',32,'全唐诗/poet.song.142000.json','["誠齋老子一歸休，最感蛩聲五報秋。", "細聽蛩聲元自樂，人愁却道是它愁。"]'),
('e5dca7b3-08e8-4a50-b033-eaf65045ea8c','送王子林節推之官融水','楊萬里','宋','宋诗','song-poetry','','[]','桂嶺梅花欲爭發，融水幕賓來訪別。',80,'全唐诗/poet.song.142000.json','["桂嶺梅花欲爭發，融水幕賓來訪別。", "可憐疋馬犯霜風，吟徧梅花更吟雪。", "我如病蠶已三眠，作繭不就黏壁乾。", "君如雲表秋健鶻，政好摶扶整羽翰。", "中書落筆看給札，歸時過我聊投轄。"]'),
('e15c64a1-b34a-422b-a574-c879ab556a41','寄餞湖廣總領張子儀少卿赴召','楊萬里','宋','宋诗','song-poetry','','[]','君不見紹興初載毗陵公，亂後身作夾日龍。',102,'全唐诗/poet.song.142000.json','["君不見紹興初載毗陵公，亂後身作夾日龍。", "功存社稷報不盡，祇遣千載高清風。", "當家衣鉢付誰子，蘭砌孫枝渾是似。", "哦詩五字如淵明，讀書萬卷如子美。", "士飽木牛今幾年，月昇金掌歸九天。", "胡不令舍人咄咄趣行李，早上星辰聽珠履。"]'),
('9f2a8857-1ef4-43b0-a188-c272584942b2','偶生得牛尾貍獻諸丞相益公侑以長句','楊萬里','宋','宋诗','song-poetry','','[]','風林露圃天欲霜，柿紅栗紫橘弄黄。',176,'全唐诗/poet.song.142000.json','["風林露圃天欲霜，柿紅栗紫橘弄黄。", "老夫忍饞不忍嘗，丁寧籩人莫取將。", "朝來栗姬羽化去，逋其木奴三百戶。", "烏椑士子散如煙，檢校不知渠去處。", "山僮相傳皂衣郎，字曰季貍氏奇章。", "上樹千回一霎强，連夜剽掠積廼倉。", "并吞又向黎侯國，羅人救黎遂禽獲。", "白茅面縛來獻俘，玄端貂裘瓠肥白。", "解驂薦渠登相門，立談封作糟丘君。", "旁招披綿拉通印，日侍尊俎嬉平園。", "玉肌生憎粗手削，須防東坡誦冤著。"]'),
('24cd60bc-0395-4372-9f62-b0edcc31fcc8','題益公丞相天香堂','楊萬里','宋','宋诗','song-poetry','','[]','君不見沉香亭北專東風，謫仙作頌天無功。',134,'全唐诗/poet.song.142000.json','["君不見沉香亭北專東風，謫仙作頌天無功。", "君不見君王殿後春第一，領袖衆芳捧堯日。", "此花司春轉化鈞，一風一雨萬物春。", "十分整頓春光了，收黄拾紫歸江表。", "天香染就山龍裳，餘芬却染山水鄉。", "青原白鷺萬松竹，被渠染作天上香。", "人間何曾識姚魏，相公新移洛中裔。", "呼酒先招野客看，不醉花前爲誰醉。"]'),
('912c3192-807c-44a7-9552-7c306dd0f0f5','冬暖絕句','楊萬里','宋','宋诗','song-poetry','','[]','今歲無寒祇有暄，臘前渾似半春天。',32,'全唐诗/poet.song.142000.json','["今歲無寒祇有暄，臘前渾似半春天。", "醉中苦有薰香癖，燒得春衫兩袖穿。"]'),
('30be4350-0ce7-40dc-a291-6887120a3b35','臘前月季','楊萬里','宋','宋诗','song-poetry','','[]','只道花無十日紅，此花無日不春風。',64,'全唐诗/poet.song.142000.json','["只道花無十日紅，此花無日不春風。", "一尖已剝臙脂筆，四破猶包翡翠茸。", "別有香超桃李外，更同梅鬭雪霜中。", "折來喜作新年看，忘却今晨是季冬。"]'),
('e9d67eaa-03f9-4707-9658-35a13d8f51a1','南齋前梅花二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','山園臘裏日疏蕪，只有南齋最起予。',32,'全唐诗/poet.song.142000.json','["山園臘裏日疏蕪，只有南齋最起予。", "竹映梅花花映竹，翠毛障子玉妃圖。"]'),
('3a8af44d-078a-4808-9015-e506f1246750','南齋前梅花二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','朝朝蚤起掛南窗，要看梅花試曉粧。',32,'全唐诗/poet.song.142000.json','["朝朝蚤起掛南窗，要看梅花試曉粧。", "兩樹相挨前後發，老夫一月不燒香。"]'),
('e00e7d40-d1e2-4300-8d96-82bca4914fd8','寄題周子中監丞萬象臺','楊萬里','宋','宋诗','song-poetry','','[]','昔從永和望青原，永和在地山在天。',112,'全唐诗/poet.song.142000.json','["昔從永和望青原，永和在地山在天。", "今從青原望萬象，青原在下臺在上。", "乘成先生學海龍，眼高四海空復空。", "如登中天騖八極，下視積蘇同絳宮。", "萬物一馬喻多少，漆園小家窮計校。", "須彌芥子亦未妙，葱嶺老胡烏知道。", "此詩解嘲仍索閙，舉似先生應絕倒。"]'),
('394d5113-62fc-4f3f-a60e-f3c258b564c4','添盆中石菖蒲水仙花水','楊萬里','宋','宋诗','song-poetry','','[]','舊詩一讀一番新，讀罷昏然一欠伸。',32,'全唐诗/poet.song.142000.json','["舊詩一讀一番新，讀罷昏然一欠伸。", "無數盆花爭訴渴，老夫却要作閑人。"]'),
('e3e028a1-767f-4772-bcba-adad0ecce8cc','小醉折梅','楊萬里','宋','宋诗','song-poetry','','[]','死愛花枝不忍吹，醉來恣意折芳菲。',32,'全唐诗/poet.song.142000.json','["死愛花枝不忍吹，醉來恣意折芳菲。", "鬢邊插得梅花滿，更撚南枝滿把歸。"]'),
('38732bd1-8a59-465e-a4b4-989c5dc68f90','送錢文季僉判','楊萬里','宋','宋诗','song-poetry','','[]','東海珠胎清廟珍，璧水秀孝第一人。',96,'全唐诗/poet.song.142000.json','["東海珠胎清廟珍，璧水秀孝第一人。", "胡爲俯首蓮泛淥，如有用我試治民。", "古來幕中要婉畫，君乃不肯作此客。", "囊篋細碎吾不能，玉壺清冰朱絲直。", "梅花雪片迎新年，送君摶風上九天。", "鳳池雞樹只咫尺，致君堯舜更努力。"]'),
('b761d865-972b-4d1b-9930-90faab27d6ff','南溪早春','楊萬里','宋','宋诗','song-poetry','','[]','還家五度見春容，長被春容惱病翁。',64,'全唐诗/poet.song.142000.json','["還家五度見春容，長被春容惱病翁。", "高柳下來垂處綠，小桃上去末梢紅。", "卷簾亭館酣酣日，放杖溪山款款風。", "更入新年足新雨，去年未當好時豐。"]'),
('05055d6a-cc4b-48b2-b555-03bb227200a6','春夜無睡思慮紛擾','楊萬里','宋','宋诗','song-poetry','','[]','不堪萬慮攪中腸，打破愁城入醉鄉。',64,'全唐诗/poet.song.142000.json','["不堪萬慮攪中腸，打破愁城入醉鄉。", "酒力盡時還又動，春宵短後却成長。", "浮思閑念紛無數，飛絮游絲徧八荒。", "看到東窗窗欲白，忽然一夢到羲皇。"]'),
('a78f475a-7528-4a94-bf61-104aef84ca72','雪後寄謝濟翁材翁聯騎來訪進退格','楊萬里','宋','宋诗','song-poetry','','[]','封胡連璧雨中來，目送歸鞍悵獨回。',64,'全唐诗/poet.song.142000.json','["封胡連璧雨中來，目送歸鞍悵獨回。", "隠几讀書寒入骨，開門落雪皓平階。", "急尋火閣溫雙手，自喚兒郎共一杯。", "念汝野梅官柳路，地爐松葉買茅柴。"]'),
('79fc64ef-6eae-4e37-9064-bc4b441bacbf','東園醉望暮山','楊萬里','宋','宋诗','song-poetry','','[]','我住北山下，南山橫我前。',132,'全唐诗/poet.song.142000.json','["我住北山下，南山橫我前。", "北山似懷抱，南山如髻鬟。", "懷抱冬獨暖，髻鬟春最鮮。", "松鬈沐初凈，山蘤插更妍。", "我來猶斜陽，我望忽夕煙。", "一望便應去，不合久憑欄。", "山意本日惜，如何許人看。", "急將白錦障，小隔青鬌顔。", "近翠成遠淡，縹渺天外仙。", "誰知絕奇處，政在有無間。", "頃刻萬姿態，可玩不可傳。"]'),
('5e1ad758-34a6-43a5-b899-f3206b391be6','小酌','楊萬里','宋','宋诗','song-poetry','','[]','酒入春逾勁，天寒燭始明。',24,'全唐诗/poet.song.142000.json','["酒入春逾勁，天寒燭始明。", "偶然傾一盞，政爾忽三更。"]'),
('d4dc06ae-6940-400c-9d54-46d1182d6a7a','芍藥初生','楊萬里','宋','宋诗','song-poetry','','[]','芍藥新移種，紅拳餐萬雛。',24,'全唐诗/poet.song.142000.json','["芍藥新移種，紅拳餐萬雛。", "看來已可愛，未問有花無。"]'),
('aa216250-3a26-4f9c-9cc5-1746b599d072','上章休致奉詔不允感恩書懷','楊萬里','宋','宋诗','song-poetry','','[]','納祿惟愁晚，蒙恩未聽辭。',48,'全唐诗/poet.song.142000.json','["納祿惟愁晚，蒙恩未聽辭。", "猖狂思再瀆，感戀獨多時。", "但有花開日，無非飲醉時。", "白頭何所用，滿與插花枝。"]'),
('8dffe928-4f10-4e97-90df-8a562049a08e','寄題萬元享舍人園亭七景 意山','楊萬里','宋','宋诗','song-poetry','','[]','不識弁山面，相逢笠澤詩。',24,'全唐诗/poet.song.142000.json','["不識弁山面，相逢笠澤詩。", "祇應晚雲散，玉立對門時。"]'),
('809553ab-1e17-4a32-96f0-54a666249eed','寄題萬元享舍人園亭七景 蒲魚港','楊萬里','宋','宋诗','song-poetry','','[]','蒲牙長幾何，已足庇玉尺。',24,'全唐诗/poet.song.142000.json','["蒲牙長幾何，已足庇玉尺。", "只恐如主人，潜逃逃不得。"]'),
('329c110b-2b75-487d-aa10-8e378048473f','寄題萬元享舍人園亭七景 溪雲','楊萬里','宋','宋诗','song-poetry','','[]','閣前三面山，閣下一溪水。',24,'全唐诗/poet.song.142000.json','["閣前三面山，閣下一溪水。", "雲出戲作霖，却歸宿簷裏。"]'),
('adae8d84-2f25-44dd-b0f5-e3623b7803ed','寄題萬元享舍人園亭七景 閑世界','楊萬里','宋','宋诗','song-poetry','','[]','要尋閑世界，不在世界外。',24,'全唐诗/poet.song.142000.json','["要尋閑世界，不在世界外。", "明月與清風，何朝不相對。"]'),
('04a20f9e-2da8-4276-8859-e590815f990e','寄題萬元享舍人園亭七景 也賢','楊萬里','宋','宋诗','song-poetry','','[]','架亭元用木，一夕化爲竹。',24,'全唐诗/poet.song.142000.json','["架亭元用木，一夕化爲竹。", "醉眼碧成朱，若箇是蒼玉。"]'),
('472fbfc2-61f4-4811-a471-b3c9dd13d986','寄題萬元享舍人園亭七景 倚苕','楊萬里','宋','宋诗','song-poetry','','[]','何處苕溪好，請君來倚樓。',24,'全唐诗/poet.song.142000.json','["何處苕溪好，請君來倚樓。", "西山也驩喜，奔走入簾鈎。"]'),
('2cfd414a-6ce7-4e98-8a91-5899acd70f8f','寄題萬元享舍人園亭七景 綿隠堂','楊萬里','宋','宋诗','song-poetry','','[]','試問隠綿上，何如隠東山。',24,'全唐诗/poet.song.142000.json','["試問隠綿上，何如隠東山。", "出處兩無閡，世間出世間。"]'),
('250f8c15-6e5d-4688-8b4d-48a50b67beca','送趙寬之排岸之官章貢','楊萬里','宋','宋诗','song-poetry','','[]','監河曾賦鹿鳴篇，又奉潘輿上貢川。',64,'全唐诗/poet.song.142000.json','["監河曾賦鹿鳴篇，又奉潘輿上貢川。", "五子循環迎一母，十分酌玉祝千年。", "鬰孤馬祖饒行樂，柿栗來禽肥過拳。", "蘭膳餘閑繙故紙，曲江早趁燕花邊。"]'),
('d0162e2c-e3d4-4da3-b542-7d7c03817e2c','積雨新晴二月八日東園小步二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','醉來忽墮錦網窩，無奈桃圍李繞何。',32,'全唐诗/poet.song.142000.json','["醉來忽墮錦網窩，無奈桃圍李繞何。", "八角小亭無處坐，見花多處背花多。"]'),
('0ddcaac2-8e0c-4040-a0f8-5143e6dc97dd','積雨新晴二月八日東園小步二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','去歲春時政病身，對花不飲被花嗔。',32,'全唐诗/poet.song.142000.json','["去歲春時政病身，對花不飲被花嗔。", "如今急報千花道，還我前來未足春。"]'),
('7090a82c-094f-4dc0-aaab-1d37d09e52ff','春半雨寒牡丹殊無消息','楊萬里','宋','宋诗','song-poetry','','[]','今歲芳菲儘未忙，去年二月牡丹香。',64,'全唐诗/poet.song.142000.json','["今歲芳菲儘未忙，去年二月牡丹香。", "寒暄不定春光晚，榮落俱遲花命長。", "纔一兩朝晴炫野，又三四陣雨鳴廊。", "鞓紅魏紫拳如蕨，而況姚家進御黄。"]'),
('6710b0b3-60bd-4b51-985c-28d0605eda25','題李子立知縣問月臺','楊萬里','宋','宋诗','song-poetry','','[]','高臺走上青天半，手弄銀盤濯銀漢。',192,'全唐诗/poet.song.142000.json','["高臺走上青天半，手弄銀盤濯銀漢。", "喚起謫仙同醉吟，一面問月一面斟。", "初頭混沌鶻崙樣，阿誰鑿開一爲兩。", "是時燧人猶未胎，那得火鑄銀盤來。", "此盤能團復能缺，團是誰磨缺誰齧。", "中有桂枝起秋風，何處移來秧此中。", "謫仙似癡還似黠，把酒問月月無說。", "老夫代月一轉語，月却問君君領否。", "君能飲酒更能詩，一夕無月君不嬉。", "月能伴君飲百斛，月能照君詩萬玉。", "君但一斗百篇詩，莫問有月來幾時。", "謫仙遠孫證明著，笑脫烏紗看月落。"]'),
('af865f97-0b6c-4766-bb2a-d4c06fe7ccef','初秋戲作山居雜興俳體十二解  其一','楊萬里','宋','宋诗','song-poetry','','[]','暑入秋來午更强，風排雨遣曉差涼。',32,'全唐诗/poet.song.142000.json','["暑入秋來午更强，風排雨遣曉差涼。", "如何遶砌千枝蕙，只是開門一陣香。"]'),
('fe3e2eb6-d7da-4c8a-82f6-f972019801a8','初秋戲作山居雜興俳體十二解  其二','楊萬里','宋','宋诗','song-poetry','','[]','蚤起翻成坐睡昏，鵲聲喚我步前軒。',32,'全唐诗/poet.song.142000.json','["蚤起翻成坐睡昏，鵲聲喚我步前軒。", "竹扉日隙針來大，射壁千千彈子痕。"]'),
('ec1c4a6e-26ec-4095-a87c-fe266e07ab15','初秋戲作山居雜興俳體十二解  其三','楊萬里','宋','宋诗','song-poetry','','[]','暑後花枝輸了春，雜英小巧亦忺人。',32,'全唐诗/poet.song.142000.json','["暑後花枝輸了春，雜英小巧亦忺人。", "素馨解點粉描筆，金鳳愛垂雞下唇。"]'),
('e9650ff2-7885-4e05-9d0d-8a484e1dde42','初秋戲作山居雜興俳體十二解  其四','楊萬里','宋','宋诗','song-poetry','','[]','風騷開國胙寒巖，勞績批書課翠嵐。',32,'全唐诗/poet.song.142000.json','["風騷開國胙寒巖，勞績批書課翠嵐。", "梨子要肥千取百，菊苗每摘一生三。"]'),
('7692e808-c706-4bb8-996b-8eb4ac91b2e1','初秋戲作山居雜興俳體十二解  其五','楊萬里','宋','宋诗','song-poetry','','[]','昨夜天垂破玉盆，今宵辛苦補盆唇。',32,'全唐诗/poet.song.142000.json','["昨夜天垂破玉盆，今宵辛苦補盆唇。", "看它補到十六七，滿得十分虧二分。"]'),
('16aff76f-5ce1-4100-a80c-1464c71be693','初秋戲作山居雜興俳體十二解  其六','楊萬里','宋','宋诗','song-poetry','','[]','甑頭雲子喜嘗新，紅嚼桃花白嚼銀。',32,'全唐诗/poet.song.142000.json','["甑頭雲子喜嘗新，紅嚼桃花白嚼銀。", "笑殺官人浪驩喜，村人殘底到官人。"]'),
('2413b3d8-c85e-486e-bd92-bfec11961acd','初秋戲作山居雜興俳體十二解  其七','楊萬里','宋','宋诗','song-poetry','','[]','七月初頭六月闌，老夫日醉早禾酸。',32,'全唐诗/poet.song.142000.json','["七月初頭六月闌，老夫日醉早禾酸。", "莫將煮喫只生喫，更洩天機向達官。"]'),
('b0f24236-e8ff-4157-aeaf-9a83917028a1','初秋戲作山居雜興俳體十二解  其八','楊萬里','宋','宋诗','song-poetry','','[]','自暴羣書舊間新，浄揩白醭拂黄塵。',32,'全唐诗/poet.song.142000.json','["自暴羣書舊間新，浄揩白醭拂黄塵。", "莫羞空腹無丁字，且免秋陽曬殺人。"]'),
('028b8955-58c7-451a-b2e8-a085a817b146','初秋戲作山居雜興俳體十二解  其九','楊萬里','宋','宋诗','song-poetry','','[]','獨對秋筠倒晚壺，喜無吏舍四歌呼。',32,'全唐诗/poet.song.142000.json','["獨對秋筠倒晚壺，喜無吏舍四歌呼。", "柳梢一殻茲緇滓，屋角雙斑谷古孤。"]'),
('8064b62f-aea4-4092-957f-5e9b0f732d29','初秋戲作山居雜興俳體十二解  其一○','楊萬里','宋','宋诗','song-poetry','','[]','湖蜜青房蛹剝瓊，沼犀紫觝腦藏冰。',32,'全唐诗/poet.song.142000.json','["湖蜜青房蛹剝瓊，沼犀紫觝腦藏冰。", "先生病暑無多酌，堆飣金柈作麽生。"]'),
('797f45f2-d958-4033-8eb6-88156bd3e696','初秋戲作山居雜興俳體十二解  其一一','楊萬里','宋','宋诗','song-poetry','','[]','卓午從它火繖張，先生別有睡爲鄉。',32,'全唐诗/poet.song.142000.json','["卓午從它火繖張，先生別有睡爲鄉。", "竹床移徧兩頭冷，瓦枕翻來四面涼。"]'),
('51809db8-5983-4f00-9b2d-3456202a817f','初秋戲作山居雜興俳體十二解  其一二','楊萬里','宋','宋诗','song-poetry','','[]','月色如霜不粟肌，月光如水不沾衣。',32,'全唐诗/poet.song.142000.json','["月色如霜不粟肌，月光如水不沾衣。", "一年沒賽中元節，政是初凉未冷時。"]'),
('e437051b-3689-4197-bd5b-586b4af868ef','謝潭帥余處恭左相遣騎惠書送酒三首  其一','楊萬里','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','小煩上相領元戎，潭府千年一日雄。',64,'全唐诗/poet.song.142000.json','["小煩上相領元戎，潭府千年一日雄。", "鏡樣洞庭那得浪，身爲天柱不須峰。", "子房富貴雲相似，中立安危國與同。", "帝恐我公招不出，那時虛左到今冬。"]'),
('3ac931e9-76be-43d5-ab82-16b973a80a77','謝潭帥余處恭左相遣騎惠書送酒三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','鵲語燈花兩太謾，三朝五夜强相驩。',64,'全唐诗/poet.song.142000.json','["鵲語燈花兩太謾，三朝五夜强相驩。", "打門軍將還驚枕，破屋山人起著冠。", "知己書從天上落，焚香手把月中看。", "少陵泛愛虛名句，羨殺寒儒眼不寒。"]'),
('5c45e1c1-3dca-469d-8473-dd534e43c072','謝潭帥余處恭左相遣騎惠書送酒三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','相思命駕竟成休，投老寒盟豈自由。',64,'全唐诗/poet.song.142000.json','["相思命駕竟成休，投老寒盟豈自由。", "雪後風濤難訪戴，山間生死總依劉。", "煩公赤手回青昊，容我清溪弄白鷗。", "穉子尚堪驅使在，門闌桃李未應秋。"]'),
('09e33c3b-45a5-4ed9-959a-57587de841d5','陳安行舍人閣學挽詞三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','媯水祀百世，莆田生此公。',48,'全唐诗/poet.song.142000.json','["媯水祀百世，莆田生此公。", "賢如太丘長，忠似了齋翁。", "玉色猶山立，皇居折棟隆。", "孝宗最知己，交臂火城紅。"]'),
('eb9d0cdc-0d5a-41ee-bd67-f5016eccd310','陳安行舍人閣學挽詞三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','循吏今爲冠，高文妙草麻。',48,'全唐诗/poet.song.142000.json','["循吏今爲冠，高文妙草麻。", "龔黄低一著，班左共三家。", "風度春無價，身名玉絕瑕。", "可憐人士淚，滴損紫薇花。"]'),
('06ca2cb3-9a52-4a5d-ac0d-a170fb7aa55c','陳安行舍人閣學挽詞三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','我昔游璧水，公時宿石渠。',48,'全唐诗/poet.song.142000.json','["我昔游璧水，公時宿石渠。", "重來十鑽火，兩省共周廬。", "小語趨丹陛，嘉招煮雪蔬。", "破心搜誄些，淚落不能書。"]'),
('b3a9acb6-bb61-48d3-922a-aa153c802bc2','同王見可劉子年循南溪度西橋登天柱岡望東山二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','親交久別忽相從，飯罷相將拄瘦筇。',64,'全唐诗/poet.song.142000.json','["親交久別忽相從，飯罷相將拄瘦筇。", "深澗小橋聊駐步，胡床羽扇對西風。", "水聲流入肝脾裏，日影輕遮雲氣中。", "玉潤即看朝玉闕，山居獨自卧山翁。"]'),
('ce9172dd-1db5-4aa0-9a6c-0615dc2452f5','同王見可劉子年循南溪度西橋登天柱岡望東山二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','偶因閑步散頑麻，倦喚胡床小歇些。',64,'全唐诗/poet.song.142000.json','["偶因閑步散頑麻，倦喚胡床小歇些。", "飛上山頭人似鶴，回看溪畔路如蛇。", "雲煙極目知何處，松竹爲門是我家。", "下得山來饑更渴，也無麥飯也無茶。"]'),
('1db04454-c7c1-4200-a0a0-8dc75d697445','和曾無疑贈詩語及歐陽公事','楊萬里','宋','宋诗','song-poetry','','[]','烏帽紅塵媿子陵，綠蓑青笠晚尋盟。',64,'全唐诗/poet.song.142000.json','["烏帽紅塵媿子陵，綠蓑青笠晚尋盟。", "三千里外還家後，七十二回看月生。", "與子兩人長對酌，笑渠萬古浪垂名。", "醉翁若是真箇醉，皂白何須鏡樣明。"]'),
('b3ab7258-7367-49b7-8911-e9cff3da1623','演雅六言二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','觳觫受田百畝，蠻觸有宅一區。',28,'全唐诗/poet.song.142000.json','["觳觫受田百畝，蠻觸有宅一區。", "蚍蜉戒之在鬭，蠅蚋寔繁有徒。"]'),
('ebf2e69c-d916-4a4a-a2cb-038456a5dc71','演雅六言二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','果蠃周公作誥，鷾鴯由也升堂。',28,'全唐诗/poet.song.142000.json','["果蠃周公作誥，鷾鴯由也升堂。", "白鷗比德於玉，黄鸝巧言如簧。"]'),
('4c94202d-ffd0-4240-83c5-32cb0eb77e4c','登天柱岡','楊萬里','宋','宋诗','song-poetry','','[]','雲外千峰鬭速行，山尖一樹獨分明。',32,'全唐诗/poet.song.142000.json','["雲外千峰鬭速行，山尖一樹獨分明。", "不知林下人家密，倚杖忽聞鷄犬聲。"]'),
('84cf7db1-4ee5-4f9e-934e-3bfb1c5f21f2','晚歸再度西橋四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','歸近溪橋東復東，蓼花迎路舞西風。',32,'全唐诗/poet.song.142000.json','["歸近溪橋東復東，蓼花迎路舞西風。", "草深一鳥忽飛起，儂不覺它它覺儂。"]'),
('9b28fac9-3e94-4104-95c4-cf445a99f771','晚歸再度西橋四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','水落沙灘倍有情，漩來漩去不成行。',32,'全唐诗/poet.song.142000.json','["水落沙灘倍有情，漩來漩去不成行。", "暗叢飛下小瀑布，攔住溪聲獨作聲。"]'),
('110759db-2d0e-41d5-ac2a-d06f16093fb5','晚歸再度西橋四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','盡日山行意未銷，歸來再與坐溪橋。',32,'全唐诗/poet.song.142000.json','["盡日山行意未銷，歸來再與坐溪橋。", "山童拋石落溪水，喚作魚兒波面跳。"]'),
('4bb3848f-739b-4e02-b60b-11ee5064a779','晚歸再度西橋四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','朝過溪頭聽水鳴，似哀如怨百般聲。',32,'全唐诗/poet.song.142000.json','["朝過溪頭聽水鳴，似哀如怨百般聲。", "歸來依舊鳴未了，知向何人訴不平。"]'),
('30807bba-4a55-403a-b80d-278fcbc54c33','題族弟道卿貧樂齋','楊萬里','宋','宋诗','song-poetry','','[]','雪茹冰餐入骨香，帽欹馿瘦儘詩狂。',64,'全唐诗/poet.song.142000.json','["雪茹冰餐入骨香，帽欹馿瘦儘詩狂。", "人傳幼婦皆稱絕，鬼笑家兄不姓方。", "細雨寒燈初夢短，斷絲枯木一聲長。", "上天已辦河東賦，豈有長貧執戟郎。"]'),
('9b1bffa0-b6f2-4b04-8d91-d56016c381e0','睡起即事','楊萬里','宋','宋诗','song-poetry','','[]','午時睡起忽心驚，一事關心太懶生。',32,'全唐诗/poet.song.142000.json','["午時睡起忽心驚，一事關心太懶生。", "速摘荼糜薰白酒，不愁香重只愁輕。"]'),
('6c619464-cbc8-4bd9-9deb-139c2dff9d7f','送永州唐德明','楊萬里','宋','宋诗','song-poetry','','[]','忽報故人至，知從何許來。',48,'全唐诗/poet.song.142000.json','["忽報故人至，知從何許來。", "滿懷俱玉雪，半語不塵埃。", "聚散千江月，悲驩一酒杯。", "檣烏有底急，一夕百相催。"]'),
('24e80358-a195-4f0c-86bb-863510750091','送趙文友知府謁告省親','楊萬里','宋','宋诗','song-poetry','','[]','邦人寧食三斗葱，莫逢向來蠆尾公。',224,'全唐诗/poet.song.142000.json','["邦人寧食三斗葱，莫逢向來蠆尾公。", "邦人寧卧文江路，莫放今侯霅川去。", "今侯箇是隆準孫，蚤排月脇斸桂根。", "所至與民作陽春，帝遣來活廬陵人。", "是時蠆尾正摇毒，邦人生愁總魚肉。", "今侯下車蔭未移，春臺載民爺與兒。", "鳩鳴雀乳一千里，鴟梟半聲不到耳。", "今侯冰檗清到底，一粒不嚼廬陵米。", "一芽只瀹青原水，玉皇知渠是廉吏。", "如何尊公小愆和，何恙靡已應無它。", "侯望白雪淚雙落，棄印謁告歸侍藥。", "尊公喜歸即日安，一見綵服還加餐。", "玉皇詔侯結絲屨，徑上金門簉鵷鷺。", "借令小緩作尚書，也合追趨趙工部。"]'),
('a9295318-ff25-4fc0-b525-934c8a95fde9','和虞軍使易簡字知能所寄唐律二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','四海九州虞雍公，擎天一柱雪山峰。',64,'全唐诗/poet.song.142000.json','["四海九州虞雍公，擎天一柱雪山峰。", "厥孫俊逸詩無敵，下筆縱橫劍有鋒。", "舊日門生今白髮，故人書札照蒼松。", "掉頭讀得紗巾落，如對青雲阮仲容。"]'),
('25f5f096-c34b-4a9b-ad96-1e20f71011e2','和虞軍使易簡字知能所寄唐律二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','柴桑卧病一茅廬，或棹孤舟或命車。',64,'全唐诗/poet.song.142000.json','["柴桑卧病一茅廬，或棹孤舟或命車。", "道喪今朝逢祖謝，詩工獨步過應徐。", "萬山不隔相思字，數月之間兩得書。", "廊廟方將訪喬木，碧梧翠竹看新除。"]'),
('9d60512f-55b6-4213-8fc6-9f10cd7313c5','酬閣皂山碧崖道士甘叔懷贈美名人不及佳句法如何十古風二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','桂林戶掾舊能文，有弟拋家作道人。',32,'全唐诗/poet.song.142000.json','["桂林戶掾舊能文，有弟拋家作道人。", "詩似道人人似鶴，看來若箇覓纖塵。"]'),
('a3f6b04b-f091-4ef0-8819-525d87c7bf65','酬閣皂山碧崖道士甘叔懷贈美名人不及佳句法如何十古風二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','贈我新詩字字奇，一奩八百顆珠璣。',32,'全唐诗/poet.song.142000.json','["贈我新詩字字奇，一奩八百顆珠璣。", "問儂佳句如何法，無法無盂也沒衣。"]'),
('811b4eb1-2ce6-43f9-86c8-b310c8c4b843','送羅宣卿主簿之官巴陵','楊萬里','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','印孫三子十一孫，六人擢桂兩特恩。',88,'全唐诗/poet.song.142000.json','["印孫三子十一孫，六人擢桂兩特恩。", "惟君有子又擢桂，父子仇香仍一門。", "君今初泛洞庭柂，湖水黏天天更大。", "請君先上岳陽樓，送眼君山最上頭。", "將詩寫取一湖秋，將秋寄來銷我愁，爲君酒船卷拍浮。"]'),
('d3cf1904-1cff-4ac9-a4e8-a5e69644c3aa','送羅必高赴省','楊萬里','宋','宋诗','song-poetry','','[]','印山先生羅天文，一卷周雅遺子孫。',131,'全唐诗/poet.song.142000.json','["印山先生羅天文，一卷周雅遺子孫。", "一門三世六七人，月中桂枝斫到根。", "近來書種將絕却，兩度秋天虛一鶚。", "今年有孫康鼎來，問天還我北斗魁。", "印山草木也驩喜，印山風雲有生氣。", "君不見普州衣鉢付仇香，仇香衣鉢付此郎。", "年未三十筆力强，百斛龍鼎一筆扛。", "殿前春風更努力，莫放別人居第一。"]'),
('afff313c-56d2-4c89-a5ce-a4daa6add6ab','除夕留子上伯玉子西小酌','楊萬里','宋','宋诗','song-poetry','','[]','諸弟山行歸意忙，老夫雪卧病身僵。',64,'全唐诗/poet.song.142000.json','["諸弟山行歸意忙，老夫雪卧病身僵。", "維風及雨歲云暮，不醉無歸夜未央。", "五盞更攙三盞麽，四更偏覺五更長。", "也知柏酒明朝近，且爲梅花盡此觴。"]'),
('bc96dcce-3b0a-4e35-b648-1c13a1d4347b','己未春日山居雜興十二解  其一','楊萬里','宋','宋诗','song-poetry','','[]','今歲春遲雨亦然，生愁無水打秧田。',32,'全唐诗/poet.song.142000.json','["今歲春遲雨亦然，生愁無水打秧田。", "不消三日如麻脚，線樣溪流浪拍天。"]'),
('27074e07-7581-4983-ac8f-c9308484a352','己未春日山居雜興十二解  其二','楊萬里','宋','宋诗','song-poetry','','[]','半月春晴探物華，山園走得脚酸麻。',32,'全唐诗/poet.song.142000.json','["半月春晴探物華，山園走得脚酸麻。", "從教三日風和雨，閉戶燒香不看花。"]'),
('04638f84-e293-460d-819e-9e95668c7323','己未春日山居雜興十二解  其三','楊萬里','宋','宋诗','song-poetry','','[]','海棠雨後不勝佳，子細看來不是花。',32,'全唐诗/poet.song.142000.json','["海棠雨後不勝佳，子細看來不是花。", "西子織成新樣錦，清晨濯出錦江霞。"]'),
('cf81fbed-9471-4152-a1ac-36a3687659b7','己未春日山居雜興十二解  其四','楊萬里','宋','宋诗','song-poetry','','[]','百舌殷勤報曉晴，花梢做出百般聲。',32,'全唐诗/poet.song.142000.json','["百舌殷勤報曉晴，花梢做出百般聲。", "饒渠學徧山禽語，至竟何曾學得鶑。"]'),
('d06d77c8-0139-4d1c-8dc5-9e6c3453e08b','己未春日山居雜興十二解  其五','楊萬里','宋','宋诗','song-poetry','','[]','海棠重葉更妖斜，青帝翻騰別一家。',32,'全唐诗/poet.song.142000.json','["海棠重葉更妖斜，青帝翻騰別一家。", "格外出奇人不識，大紅抹利小蓮花。"]'),
('913a9569-67be-4b72-bc0d-678c5e829c42','己未春日山居雜興十二解  其六','楊萬里','宋','宋诗','song-poetry','','[]','春寒偏勒牡丹遲，晚似常年半月期。',32,'全唐诗/poet.song.142000.json','["春寒偏勒牡丹遲，晚似常年半月期。", "上巳清明同一日，那時恰好放花枝。"]'),
('a1878345-82ac-42e2-bc1f-92ae5105eaad','己未春日山居雜興十二解  其七','楊萬里','宋','宋诗','song-poetry','','[]','手種花王五百窠，半來枯瘁半萌芽。',32,'全唐诗/poet.song.142000.json','["手種花王五百窠，半來枯瘁半萌芽。", "東風未要都開了，每日教開三兩花。"]'),
('e44456e7-2b8e-4b23-9017-217f9d44b999','己未春日山居雜興十二解  其八','楊萬里','宋','宋诗','song-poetry','','[]','金作林檎花絕穠，十年花少怨東風。',32,'全唐诗/poet.song.142000.json','["金作林檎花絕穠，十年花少怨東風。", "即今徧地欒枝錦，不則梢頭幾點紅。"]'),
('b4dd029a-3a74-4437-8bed-b975521515be','己未春日山居雜興十二解  其九','楊萬里','宋','宋诗','song-poetry','','[]','寒久花遲也大奇，雨膏飽足土膏肥。',32,'全唐诗/poet.song.142000.json','["寒久花遲也大奇，雨膏飽足土膏肥。", "牡丹芍藥君須記，管取花房二尺圍。"]'),
('10cf5578-cae9-4b8e-a29d-c36b69fdb1e4','己未春日山居雜興十二解  其一○','楊萬里','宋','宋诗','song-poetry','','[]','日影雲光學鍍金，好風不肯碎花陰。',32,'全唐诗/poet.song.142000.json','["日影雲光學鍍金，好風不肯碎花陰。", "人言春色醲於酒，不醉衰容只醉心。"]'),
('f4cec41b-94b0-4860-95d9-eb7040fdb24d','己未春日山居雜興十二解  其一一','楊萬里','宋','宋诗','song-poetry','','[]','半晴半雨半暄涼，拖带春光未要忙。',32,'全唐诗/poet.song.142000.json','["半晴半雨半暄涼，拖带春光未要忙。", "爲報州家兼縣裏，吾鄉改作萬花鄉。"]'),
('53c2c9ca-70cd-47bc-ab97-b925d7e95b2e','己未春日山居雜興十二解  其一二','楊萬里','宋','宋诗','song-poetry','','[]','一春兩脚滯東園，柳絆花牽不暫閑。',32,'全唐诗/poet.song.142000.json','["一春兩脚滯東園，柳絆花牽不暫閑。", "今日釅晴天氣好，杖藜看水更看山。"]'),
('b6208b6f-e846-48c9-a4d8-8205e98522a7','送談命周從龍','楊萬里','宋','宋诗','song-poetry','','[]','周子囊螢初學儒，學儒不就學星書。',32,'全唐诗/poet.song.142000.json','["周子囊螢初學儒，學儒不就學星書。", "五丸玉李無逃處，折得今年錐也無。"]'),
('a95df510-6f01-4363-bb95-5c50c0a2c542','暮春即事','楊萬里','宋','宋诗','song-poetry','','[]','花時追賞夜將朝，花過癡眠日儘高。',32,'全唐诗/poet.song.142000.json','["花時追賞夜將朝，花過癡眠日儘高。", "又與山禽爭口腹，執竿挾彈守櫻桃。"]'),
('959cf4a4-1fb7-4678-a66a-91f41be0f640','送蕭瑞卿','楊萬里','宋','宋诗','song-poetry','','[]','異縣二百里，分襟五十年。',48,'全唐诗/poet.song.142000.json','["異縣二百里，分襟五十年。", "肯來尋病者，相對各蒼然。", "舉似兒時話，茫如夢裏煙。", "殘花猶可醉，細酌未須眠。"]'),
('96c525bb-db34-4319-9937-9098c1a3efd4','聖恩增秩進職致仕感恩述懷','楊萬里','宋','宋诗','song-poetry','','[]','雨露絲綸下玉宸，問天乞得箇閑身。',64,'全唐诗/poet.song.142000.json','["雨露絲綸下玉宸，問天乞得箇閑身。", "一生無恨長多感，三請歸休恰四春。", "手板抽還大丞相，安車懸示後來人。", "從今萬八百場醉，忽自稱冤五柳巾。"]'),
('02512646-85b9-46f9-8fff-c2e272c0f466','春盡有感','楊萬里','宋','宋诗','song-poetry','','[]','等春不到怨春遲，又是紅稀綠滿枝。',64,'全唐诗/poet.song.142000.json','["等春不到怨春遲，又是紅稀綠滿枝。", "雨後晚花猶好在，檻前殘醉欲醒時。", "百年人事皆如許，千載詩聲亦浪垂。", "金印不爭爭釣石，更饒爭得鬢邊絲。"]'),
('06778972-818d-4ca8-bf01-6854a161e546','送分寧主簿羅宏材秩滿入京','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','要知詩客參江西，政似禪客參曹溪。',96,'全唐诗/poet.song.142000.json','["要知詩客參江西，政似禪客參曹溪。", "不到南華與脩水，於何傳法更傳衣。", "吾家親黨子羅子，只今四海習鑿齒。", "花紅玉白幾百篇，塞破錦囊脫無底。", "三年簿領脩水涯，夜半親傳雙井芽。", "定知誦向百僚上，不道長江與落霞。"]'),
('feb72985-2be5-41cc-b9ea-eb750d1d3daa','書黄廬陵伯庸詩卷','楊萬里','宋','宋诗','song-poetry','','[]','句法何曾問外人，單傳山谷當家春。',64,'全唐诗/poet.song.142000.json','["句法何曾問外人，單傳山谷當家春。", "截來雲錦花無樣，倒寫珠胎海亦貧。", "汗竹香中翻墨汁，扶桑梢上挂頭巾。", "詩名官職看雙美，向道儒冠不誤身。"]'),
('45ba6e59-2cba-4271-ad43-96b67abcc577','賦益公平園牡丹白花青緣','楊萬里','宋','宋诗','song-poetry','','[]','東皇封作萬花王，更賜珍華出尚方。',64,'全唐诗/poet.song.142000.json','["東皇封作萬花王，更賜珍華出尚方。", "白玉杯將青玉緣，碧羅領襯素羅裳。", "古來洛口元無種，今去天心別得香。", "塗改歐家記文著，此花未出說姚黄。"]'),
('58fd464a-24c5-4cf0-be12-55dfedd39ba4','和益公見謝紅都勝芍藥之句','楊萬里','宋','宋诗','song-poetry','','[]','江西春好不關渠，只說平園絕世無。',64,'全唐诗/poet.song.142000.json','["江西春好不關渠，只說平園絕世無。", "牡丹百種移洛苑，海棠千樹賽成都。", "坐令浮花并浪蕊，誰敢塗鉛更抹朱。", "不應一朶翻階豔，博得龍宮八十珠。"]'),
('7802fd6b-c562-4287-a64e-1966735bb596','益公和白花青緣牡丹王字韻詩再和以往','楊萬里','宋','宋诗','song-poetry','','[]','渠是花中異姓王，平園小試染花方。',64,'全唐诗/poet.song.142000.json','["渠是花中異姓王，平園小試染花方。", "冰霜洗出春風面，翡翠輕稜疊雪裳。", "夜領素娥酌青女，曉看國色带天香。", "更將秋菊潭心水，滴作䒠茸月蕊黄。"]'),
('767815a6-3dc3-4db0-b1c9-e5b139a9207b','題黄唐伯一經堂','楊萬里','宋','宋诗','song-poetry','','[]','人言天地生仲尼，不知仲尼生兩儀。',96,'全唐诗/poet.song.142000.json','["人言天地生仲尼，不知仲尼生兩儀。", "易中先自有太極，生天生地誰得知。", "一經以後派爲六，六經以前一經足。", "學子要探天地心，詩書執禮皆可尋。", "吾鄉後身黄叔度，教子一經有佳處。", "寄言韋家父子間，浪比籯金良汗顔。"]'),
('3b4d5cc4-3d61-4dca-99bc-25a28bbf5277','送廬陵丞劉約之','楊萬里','宋','宋诗','song-poetry','','[]','忠顯聞孫定不虛，西樞猶子故應殊。',64,'全唐诗/poet.song.142000.json','["忠顯聞孫定不虛，西樞猶子故應殊。", "鸞停梧上遺風在，雁進松間得句無。", "剩有老農歌贊府，未多薦墨送清都。", "晦翁若問誠齋叟，上下千峰不要扶。"]'),
('be7e8f53-6759-47cf-b1c7-21d42b1b42f3','謝張子儀尚書寄天雄附子北果十包','楊萬里','宋','宋诗','song-poetry','','[]','今古交情市道同，轉頭立地馬牛風。',64,'全唐诗/poet.song.142000.json','["今古交情市道同，轉頭立地馬牛風。", "如何聽履星辰客，猶念孤舟蓑笠翁。", "饋藥雙奩芬玉雪，解包百果粲青紅。", "看渠即上三能去，大小毗陵說兩公。"]'),
('3d0e2697-7ea5-4c23-97bc-d10486c97684','初秋小雨殘暑未退','楊萬里','宋','宋诗','song-poetry','','[]','雨好夫何小，涼新竟未多。',48,'全唐诗/poet.song.142000.json','["雨好夫何小，涼新竟未多。", "飄蕭才響瓦，點滴不霑荷。", "龍亦如儂否，渠還畏熱麽。", "敢勞頻上水，只倩挽天河。"]'),
('3f6ea742-0e31-4e97-a9f8-b40d99d77593','送王子林節推歸融州','楊萬里','宋','宋诗','song-poetry','','[]','吾州佳士子王子，深入黄茅作從事。',98,'全唐诗/poet.song.142000.json','["吾州佳士子王子，深入黄茅作從事。", "捧檄還家侍老親，端能過我誦近文。", "問渠鶚表幾張紙，笑道孤寒那得此。", "老夫已把釣月竿，安能爲子插羽翰。", "似聞融水新二天，外臺使星俱好賢。", "願子西去早著鞭，歸來薦墨滿袖猶未乾。"]');
